import React, { useState, useEffect, useCallback } from 'react';
import { Globe, Menu, ArrowLeft, LayoutGrid } from 'lucide-react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Orders from './components/Orders';
import Customers from './components/Customers';
import StaffView from './components/Staff';
import Production from './components/Production';
import Finance from './components/Finance';
import Login from './components/Login';
import Hub from './components/Hub';
import MakhGold from './components/MakhGold';
import GeneralAdmin from './components/GeneralAdmin';
import AIAssistant from './components/AIAssistant';
import Toast from './components/Toast';
import { Language, Customer, Product, RawMaterial, Order, Staff, Expense, Notification, EntityType, GoldTransaction, Appointment } from './types';
import { TRANSLATIONS, MOCK_CUSTOMERS, MOCK_PRODUCTS, MOCK_RAW_MATERIALS, MOCK_ORDERS, MOCK_STAFF, MOCK_EXPENSES, MOCK_GOLD_TRANSACTIONS, MOCK_APPOINTMENTS } from './constants';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [currentEntity, setCurrentEntity] = useState<EntityType>('MASTER');
  const [currentView, setCurrentView] = useState('dashboard');
  const [lang, setLang] = useState<Language>(Language.AR);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('np_customers') || JSON.stringify(MOCK_CUSTOMERS)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('np_products') || JSON.stringify(MOCK_PRODUCTS)));
  const [materials, setMaterials] = useState<RawMaterial[]>(() => JSON.parse(localStorage.getItem('np_materials') || JSON.stringify(MOCK_RAW_MATERIALS)));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('np_orders') || JSON.stringify(MOCK_ORDERS)));
  const [staff, setStaff] = useState<Staff[]>(() => JSON.parse(localStorage.getItem('np_staff') || JSON.stringify(MOCK_STAFF)));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('np_expenses') || JSON.stringify(MOCK_EXPENSES)));
  const [goldTransactions, setGoldTransactions] = useState<GoldTransaction[]>(() => JSON.parse(localStorage.getItem('np_gold_tx') || JSON.stringify(MOCK_GOLD_TRANSACTIONS)));
  const [appointments, setAppointments] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('np_appointments') || JSON.stringify(MOCK_APPOINTMENTS)));
  const [notification, setNotification] = useState<Notification | null>(null);

  const isRTL = lang === Language.AR;
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;

  useEffect(() => {
    localStorage.setItem('np_customers', JSON.stringify(customers));
    localStorage.setItem('np_products', JSON.stringify(products));
    localStorage.setItem('np_materials', JSON.stringify(materials));
    localStorage.setItem('np_orders', JSON.stringify(orders));
    localStorage.setItem('np_staff', JSON.stringify(staff));
    localStorage.setItem('np_expenses', JSON.stringify(expenses));
    localStorage.setItem('np_gold_tx', JSON.stringify(goldTransactions));
    localStorage.setItem('np_appointments', JSON.stringify(appointments));
  }, [customers, products, materials, orders, staff, expenses, goldTransactions, appointments]);

  const showNotification = useCallback((message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
  }, []);

  const toggleLanguage = () => setLang(prev => prev === Language.AR ? Language.FR : Language.AR);

  const handleLogin = (user: Staff) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    if (user.allowedEntity && user.allowedEntity !== 'MASTER' && user.allowedEntity !== 'GENERAL_ADMIN') {
        setCurrentEntity(user.allowedEntity);
    } else {
        setCurrentEntity('MASTER');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentEntity('MASTER');
  };

  if (!isLoggedIn) return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Login lang={lang} onLogin={handleLogin} toggleLanguage={toggleLanguage} staff={staff} showNotification={showNotification} />
    </>
  );

  if (currentEntity === 'MASTER') return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Hub lang={lang} onSelectEntity={(e) => { setCurrentEntity(e); setCurrentView('dashboard'); }} onLogout={handleLogout} />
    </>
  );

  // Special full-screen views for Gold and Admin
  if (currentEntity === 'MAKH_GOLD') return (
    <MakhGold 
      lang={lang} 
      onLogout={() => setCurrentEntity('MASTER')} 
      goldTransactions={goldTransactions} 
      setGoldTransactions={setGoldTransactions} 
      shareholders={[]} 
      setShareholders={() => {}} 
      showNotification={showNotification} 
    />
  );

  if (currentEntity === 'GENERAL_ADMIN') return (
    <GeneralAdmin 
      lang={lang} 
      onLogout={() => setCurrentEntity('MASTER')} 
      expenses={expenses} 
      goldTransactions={goldTransactions} 
      orders={orders} 
      staff={staff} 
      setStaff={setStaff} 
      appointments={appointments} 
      setAppointments={setAppointments} 
      showNotification={showNotification} 
      currentUser={currentUser} 
    />
  );

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard lang={lang} setCurrentView={setCurrentView} orders={orders} staff={staff} expenses={expenses} materials={materials} products={products} />;
      case 'inventory': return <Inventory lang={lang} materials={materials} setMaterials={setMaterials} products={products} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} showNotification={showNotification} onRestockMaterial={() => {}} />;
      case 'orders': return <Orders lang={lang} customers={customers} orders={orders} setOrders={setOrders} products={products} setProducts={setProducts} setExpenses={setExpenses} showNotification={showNotification} />;
      case 'customers': return <Customers lang={lang} customers={customers} setCustomers={setCustomers} showNotification={showNotification} />;
      case 'staff': return <StaffView lang={lang} staff={staff} setStaff={setStaff} onPaySalary={() => {}} onRequestAdvance={() => {}} showNotification={showNotification} />;
      case 'production': return <Production lang={lang} products={products} setProducts={setProducts} materials={materials} setMaterials={setMaterials} showNotification={showNotification} />;
      case 'finance': return <Finance lang={lang} expenses={expenses} setExpenses={setExpenses} orders={orders} showNotification={showNotification} />;
      default: return <Dashboard lang={lang} setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div dir={isRTL ? 'rtl' : 'ltr'} className={`flex h-screen bg-slate-50 overflow-hidden ${isRTL ? 'font-cairo' : 'font-sans'}`}>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}

      <Sidebar currentView={currentView} setCurrentView={setCurrentView} lang={lang} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 bg-white border-b border-slate-100 flex items-center justify-between px-8 z-10 print:hidden">
          <div className="flex items-center gap-6">
             <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-slate-500"><Menu size={24} /></button>
             <button onClick={() => setCurrentEntity('MASTER')} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all">
               <ArrowLeft size={16} className={isRTL ? 'rotate-180' : ''} />
               {t('backToHub')}
             </button>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden sm:block text-sm text-slate-400 font-bold">
                {lang === Language.AR ? `أهلاً، ${currentUser?.name || 'سليمان'}` : `Welcome, ${currentUser?.name || 'Suleiman'}`}
             </div>
             <button onClick={toggleLanguage} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-50 text-slate-600 hover:bg-slate-100 transition-all text-xs font-bold border border-slate-200">
               <Globe size={14} />
               {lang === Language.AR ? 'Français' : 'العربية'}
             </button>
             <h2 className="hidden md:flex items-center gap-2 text-sm font-black text-slate-800">
               {t(currentView)}
             </h2>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 lg:p-10 bg-slate-50/50">
          <div className="max-w-7xl mx-auto h-full">{renderContent()}</div>
        </main>

        <AIAssistant lang={lang} materials={materials} products={products} orders={orders} />
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Package, Plus, Factory, MinusCircle, Box, Droplets, Palette, TrendingUp, AlertCircle } from 'lucide-react';
import { Language, Product, RawMaterial } from '../types';
import { TRANSLATIONS } from '../constants';

interface ProductionProps {
  lang: Language;
  products: Product[];
  setProducts: (p: Product[]) => void;
  materials: RawMaterial[];
  setMaterials: (m: RawMaterial[]) => void;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Production: React.FC<ProductionProps> = ({ lang, products, setProducts, materials, setMaterials, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  const [prodProductId, setProdProductId] = useState('');
  const [prodQuantity, setProdQuantity] = useState('');

  // Quick consumption states
  const [consMaterialId, setConsMaterialId] = useState('');
  const [consQuantity, setConsQuantity] = useState('');

  const handleSaveProduction = () => {
    if (!prodProductId || !prodQuantity || Number(prodQuantity) <= 0) {
      showNotification(isRTL ? 'يرجى إدخال كمية صحيحة' : 'Please enter valid quantity', 'error');
      return;
    }

    // Logic for auto-consumption (Optional: can be expanded based on a fixed recipe)
    // For now, we update the product quantity
    setProducts(products.map(p => p.id === prodProductId ? { ...p, quantity: p.quantity + Number(prodQuantity) } : p));
    setProdProductId(''); 
    setProdQuantity('');
    showNotification(t('success'), 'success');
  };

  const handleSaveConsumption = () => {
    if (!consMaterialId || !consQuantity || Number(consQuantity) <= 0) {
      showNotification(isRTL ? 'يرجى اختيار مادة وكمية' : 'Please select material and quantity', 'error');
      return;
    }
    const mat = materials.find(m => m.id === consMaterialId);
    if (mat && mat.quantity < Number(consQuantity)) {
        showNotification(t('insufficientRaw'), 'error');
        return;
    }
    setMaterials(materials.map(m => m.id === consMaterialId ? { ...m, quantity: m.quantity - Number(consQuantity) } : m));
    setConsMaterialId(''); 
    setConsQuantity('');
    showNotification(t('success'), 'success');
  };

  const inputClass = "w-full border-2 border-slate-100 bg-slate-50 text-slate-900 rounded-2xl p-4 focus:border-blue-500 focus:bg-white outline-none transition-all font-black text-center font-mono text-lg";
  const labelClass = "block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 text-center";

  const ItemCard = ({ title, qty, unit, max, icon: Icon, colorClass, baseColor }: any) => (
    <div className={`bg-white p-6 rounded-[2rem] border border-slate-100 flex flex-col items-center justify-center text-center shadow-sm min-w-[140px] flex-1 border-b-8 ${baseColor || 'border-b-blue-500'} hover:-translate-y-1 transition-transform`}>
        <div className={`p-4 rounded-2xl mb-4 ${colorClass || 'bg-blue-50 text-blue-500'}`}>
            <Icon size={28} />
        </div>
        <p className="font-black text-slate-800 text-sm mb-2 uppercase tracking-tight">{title}</p>
        <div className="flex flex-col">
            <p className={`text-2xl font-black font-mono ${baseColor ? 'text-slate-800' : 'text-blue-600'}`}>
                {qty.toLocaleString('en-US')}
            </p>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">
                {unit} / {max.toLocaleString('en-US')}
            </p>
        </div>
    </div>
  );

  return (
    <div className="space-y-12 animate-fade-in-up pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">{isRTL ? 'خط الإنتاج والتشغيل' : 'Production Line'}</h2>
            <p className="text-slate-400 font-bold text-sm mt-1">{isRTL ? 'إدارة الماكينات واستهلاك الورق والماء.' : 'Manage machinery and resource consumption.'}</p>
        </div>
        <div className="flex items-center gap-2 bg-emerald-50 text-emerald-600 px-4 py-2 rounded-xl font-black text-xs uppercase tracking-widest">
            <TrendingUp size={16} />
            <span>Active Session</span>
        </div>
      </div>

      {/* الإنتاج: المنتجات الجاهزة */}
      <div className="space-y-6">
        <div className="flex items-center gap-3">
            <div className="h-8 w-1.5 bg-blue-600 rounded-full"></div>
            <h3 className="text-xl font-black text-slate-800">{isRTL ? 'تسجيل إنتاج الأطباق الجاهزة' : 'Register Finished Goods'}</h3>
        </div>
        <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 gap-6">
                {products.map(p => (
                    <ItemCard key={p.id} title={lang === Language.AR ? p.nameAr : p.nameFr} qty={p.quantity} unit={p.unit} max={p.maxQuantity} icon={Box} />
                ))}
            </div>
            <div className="w-full lg:w-[400px] bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl flex flex-col gap-8">
                <div>
                    <label className={labelClass}>{isRTL ? 'المنتج المستهدف' : 'Target Product'}</label>
                    <select value={prodProductId} onChange={(e) => setProdProductId(e.target.value)} className={inputClass}>
                        <option value="">-- {isRTL ? 'اختر المنتج' : 'Select'} --</option>
                        {products.map(p => <option key={p.id} value={p.id}>{lang === Language.AR ? p.nameAr : p.nameFr}</option>)}
                    </select>
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'الكمية المنتجة (طبق)' : 'Produced Qty (Plates)'}</label>
                    <input type="number" value={prodQuantity} onChange={(e) => setProdQuantity(e.target.value)} className={inputClass} placeholder="0" />
                </div>
                <button onClick={handleSaveProduction} className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-[1.5rem] font-black shadow-2xl shadow-blue-500/30 transition-all flex items-center justify-center gap-3 active:scale-95">
                    <Plus size={24} /> <span>{isRTL ? 'تأكيد الإنتاج' : 'Confirm Production'}</span>
                </button>
            </div>
        </div>
      </div>

      {/* الاستهلاك: المواد الخام */}
      <div className="space-y-6 pt-12 border-t border-slate-100">
        <div className="flex items-center gap-3">
            <div className="h-8 w-1.5 bg-niger-orange rounded-full"></div>
            <h3 className="text-xl font-black text-niger-orange">{isRTL ? 'تسجيل استهلاك المواد الخام' : 'Register Raw Material Consumption'}</h3>
        </div>
        <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 gap-6">
                {materials.slice(0, 4).map(m => {
                    let color = 'bg-orange-50 text-orange-600';
                    let bColor = 'border-b-orange-500';
                    let icon = Factory;
                    if (m.nameAr.includes('ماء')) { color = 'bg-emerald-50 text-emerald-600'; bColor = 'border-b-emerald-500'; icon = Droplets; }
                    if (m.nameAr.includes('لون')) { color = 'bg-rose-50 text-rose-600'; bColor = 'border-b-rose-500'; icon = Palette; }
                    return <ItemCard key={m.id} title={lang === Language.AR ? m.nameAr : m.nameFr} qty={m.quantity} unit={m.unit} max={m.maxQuantity} icon={icon} colorClass={color} baseColor={bColor} />;
                })}
            </div>
            <div className="w-full lg:w-[400px] bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl flex flex-col gap-8">
                <div className="bg-amber-50 p-4 rounded-2xl flex items-center gap-3 text-amber-700 text-xs font-bold border border-amber-100">
                    <AlertCircle size={18} />
                    <span>{isRTL ? 'الاستهلاك يقلل المخزون المتاح فوراً.' : 'Consumption reduces stock immediately.'}</span>
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'المادة المستهلكة' : 'Raw Material'}</label>
                    <select value={consMaterialId} onChange={(e) => setConsMaterialId(e.target.value)} className={inputClass}>
                        <option value="">-- {isRTL ? 'اختر المادة' : 'Select'} --</option>
                        {materials.map(m => <option key={m.id} value={m.id}>{lang === Language.AR ? m.nameAr : m.nameFr}</option>)}
                    </select>
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'الكمية المستهلكة' : 'Consumed Qty'}</label>
                    <input type="number" value={consQuantity} onChange={(e) => setConsQuantity(e.target.value)} className={inputClass} placeholder="0" />
                </div>
                <button onClick={handleSaveConsumption} className="w-full py-5 bg-niger-orange hover:bg-orange-700 text-white rounded-[1.5rem] font-black shadow-2xl shadow-orange-500/30 transition-all flex items-center justify-center gap-3 active:scale-95">
                    <MinusCircle size={24} /> <span>{isRTL ? 'تسجيل الاستهلاك' : 'Save Consumption'}</span>
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Production;

import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Package, AlertTriangle, TrendingUp, Wallet, Calendar as CalendarIcon, ArrowUpCircle, ArrowDownCircle, Boxes } from 'lucide-react';
import { Language, Order, Staff, Expense, RawMaterial, Product } from '../types';
import { TRANSLATIONS } from '../constants';

interface DashboardProps {
  lang: Language;
  setCurrentView: (view: string) => void;
  orders?: Order[];
  staff?: Staff[];
  expenses?: Expense[];
  materials?: RawMaterial[];
  products?: Product[];
}

const Dashboard: React.FC<DashboardProps> = ({ lang, orders = [], expenses = [], materials = [], products = [] }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // Real data calculations
  const totalIncome = expenses.filter(e => e.type === 'income').reduce((sum, e) => sum + e.amount, 0);
  const totalExpenses = expenses.filter(e => e.type === 'expense').reduce((sum, e) => sum + e.amount, 0);
  const netProfit = totalIncome - totalExpenses;
  const lowStockCount = materials.filter(m => m.quantity < (m.maxQuantity || 100) * 0.25).length;
  const totalProduced = products.reduce((sum, p) => sum + p.quantity, 0);

  const dailyData = useMemo(() => {
    const data = [];
    const today = new Date();
    const days = isRTL 
      ? ['الأحد', 'الاثنين', 'الثلاثاء', 'الأربعاء', 'الخميس', 'الجمعة', 'السبت']
      : ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    for (let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(today.getDate() - i);
        data.push({ 
          name: days[d.getDay()], 
          value: Math.floor(Math.random() * 5000) + 1000 // Mock performance logic
        });
    }
    return data;
  }, [lang, isRTL]);

  const barData = [
    { name: isRTL ? 'الأسبوع الماضي' : 'Last Week', income: totalIncome * 0.8, expense: totalExpenses * 0.9 },
    { name: isRTL ? 'هذا الأسبوع' : 'This Week', income: totalIncome, expense: totalExpenses },
  ];

  const CurrencyValue = ({ val }: { val: number }) => (
      <span className="font-mono font-black">
          <small className="text-[10px] text-slate-400 font-bold uppercase mr-1">SAR</small>
          {val.toLocaleString('en-US')}
      </span>
  );

  return (
    <div className="space-y-8 pb-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">{t('dashboard')}</h2>
            <p className="text-slate-400 font-bold text-sm mt-1">{isRTL ? 'نظرة شاملة على أداء المصنع اليومي.' : 'General overview of factory performance.'}</p>
        </div>
        <div className="flex items-center gap-3 text-slate-400 bg-white px-5 py-3 rounded-2xl shadow-sm border border-slate-100 text-xs font-black">
          <CalendarIcon size={14} className="text-blue-600" />
          <span className="uppercase tracking-widest">{new Date().toLocaleDateString(isRTL ? 'ar-SA' : 'en-US', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-start justify-between group hover:shadow-xl transition-all">
          <div className="flex-1">
            <p className="text-[10px] text-slate-400 font-black uppercase mb-1 tracking-[0.2em]">{t('netProfit')}</p>
            <h3 className="text-2xl text-slate-800"><CurrencyValue val={netProfit} /></h3>
            <div className="flex gap-2 mt-4 font-mono">
                <div className="flex items-center gap-1 text-[9px] text-emerald-600 font-black bg-emerald-50 px-2 py-1 rounded-full border border-emerald-100">
                    <ArrowUpCircle size={10} /> <span>+{totalIncome.toLocaleString()}</span>
                </div>
                <div className="flex items-center gap-1 text-[9px] text-rose-600 font-black bg-rose-50 px-2 py-1 rounded-full border border-rose-100">
                    <ArrowDownCircle size={10} /> <span>-{totalExpenses.toLocaleString()}</span>
                </div>
            </div>
          </div>
          <div className="p-4 bg-purple-50 text-purple-500 rounded-2xl"><Wallet size={24} /></div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-start justify-between group hover:shadow-xl transition-all">
          <div className="flex-1">
            <p className="text-[10px] text-slate-400 font-black uppercase mb-1 tracking-[0.2em]">{t('lowStock')}</p>
            <h3 className="text-3xl font-black text-slate-800 font-mono tracking-tighter">{lowStockCount} <small className="text-xs font-bold text-slate-400 uppercase">Items</small></h3>
            <p className={`text-[9px] font-black mt-3 uppercase tracking-tight ${lowStockCount > 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                {lowStockCount > 0 ? (isRTL ? 'إجراء عاجل مطلوب' : 'Action Required') : (isRTL ? 'المخزون ممتاز' : 'Stock Optimal')}
            </p>
          </div>
          <div className={`p-4 rounded-2xl ${lowStockCount > 0 ? 'bg-amber-50 text-amber-500 animate-pulse' : 'bg-emerald-50 text-emerald-500'}`}>
            <AlertTriangle size={24} />
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-start justify-between group hover:shadow-xl transition-all">
          <div className="flex-1">
