interface MosqueManagementProps {
  lang: Language;
  onLogout: () => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
}

const MosqueManagement: React.FC<MosqueManagementProps> = ({ lang, onLogout, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;
  const [activeTab, setActiveTab] = useState<'mosques' | 'rewards'>('mosques');
  const [selectedMosqueIndex, setSelectedMosqueIndex] = useState(0);

  // Modals state
  const [isDonorModalOpen, setIsDonorModalOpen] = useState(false);
  const [isPayoutModalOpen, setIsPayoutModalOpen] = useState(false);
  const [selectedStaff, setSelectedStaff] = useState<MosqueStaffReward | null>(null);

  // Salary Config
