                </div>
                <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 block">{isRTL ? 'المبلغ (XOF)' : 'Amount XOF'}</label>
                    <input type="number" value={txForm.xof} onChange={(e) => setTxForm({...txForm, xof: e.target.value})} className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-mono" />
