                <input type="date" value={txForm.date} onChange={(e) => setTxForm({...txForm, date: e.target.value})} className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-mono" />
            </div>
            <button onClick={handleAddTransaction} className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black mt-4 shadow-xl shadow-emerald-600/20 active:scale-95 transition-all">
                {isRTL ? 'حفظ البيانات' : 'Save Transaction'}
            </button>
        </div>
      </Modal>

      {/* Pay Salary Modal */}
      <Modal isOpen={isPayoutModalOpen} onClose={() => setIsPayoutModalOpen(false)} title={isRTL ? 'صرف الرواتب' : 'Disburse Pay'} isRTL={isRTL} contentClassName="bg-slate-900 text-white">
        <div className="space-y-6">
            <div className="p-6 bg-slate-800 rounded-2xl border border-white/5">
                <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-1">{isRTL ? 'المستحق' : 'Beneficiary'}</p>
                <h4 className="text-xl font-black text-white">{selectedStaff?.staffName}</h4>
            </div>
            <div className="flex justify-between items-center p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20">
                <span className="text-sm font-bold text-slate-300">Amount to Disburse:</span>
                <span className="text-xl font-black text-emerald-400 font-mono">{selectedStaff?.amountXOF.toLocaleString('en-US')} XOF</span>
            </div>
            <button onClick={() => { showNotification('Payment Disbursed', 'success'); setIsPayoutModalOpen(false); }} className="w-full py-4 bg-amber-600 hover:bg-amber-700 text-white rounded-2xl font-black flex items-center justify-center gap-3 active:scale-95 transition-all">
                <Send size={24} /> {isRTL ? 'تأكيد الصرف' : 'Confirm Payout'}
            </button>
        </div>
      </Modal>

      <footer className="max-w-7xl mx-auto mt-12 mb-10 text-center opacity-30 text-[10px] font-black uppercase tracking-[0.3em]">
        Niger Projects Group • Mosque Management v5.0
      </footer>
    </div>
  );
};

export default MosqueManagement;

import React, { useState, useMemo } from 'react';
import { 
  Church, 
  Plus, 
  ArrowUpRight, 
  ArrowDownRight, 
  Calculator, 
  HandCoins,
  FileText,
  Calendar,
  UserPlus,
  Send,
  CreditCard,
  History,
  TrendingUp,
  Briefcase,
  Building,
  Users,
  Wallet,
  Trash2,
  ChevronRight,
  Info,
  DollarSign
} from 'lucide-react';
import { Language, MosqueData, MosqueTransaction, MosqueDonation, MosqueStaffReward } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface MosqueManagementProps {
  lang: Language;
  onLogout: () => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
}

const MosqueManagement: React.FC<MosqueManagementProps> = ({ lang, onLogout, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
