  const [txType, setTxType] = useState<'receipt' | 'payment' | 'expense'>('receipt');
  const [isPayoutModalOpen, setIsPayoutModalOpen] = useState(false);
  const [selectedStaff, setSelectedStaff] = useState<MosqueStaffReward | null>(null);

  // Form States
  const [newMosqueName, setNewMosqueName] = useState('');
  const [txForm, setTxForm] = useState({ 
    desc: '', sar: '', xof: '', date: new Date().toISOString().split('T')[0], donor: '' 
  });

  // Main Data State
  const [mosques, setMosques] = useState<any[]>([
    {
      id: 'm1',
      name: isRTL ? 'مسجد الغامدي' : 'Mosquée Al-Ghamdi',
