        { id: 'r1', date: '2025-01-11', desc: 'الدفعة الأولى', sar: 30000, xof: 4900000, donor: 'الغامدي' },
        { id: 'r2', date: '2025-01-27', desc: 'الدفعة الثانية', sar: 25000, xof: 4100000, donor: 'الغامدي' },
        { id: 'r8', date: '2025-05-14', desc: 'الدفعة الأخيرة', sar: 25000, xof: 3790000, donor: 'الغامدي' },
      ],
      payments: [
        { id: 'p1', date: '2025-01-20', desc: 'الدفعة الأولى مقاول', amount: 2000000 },
        { id: 'p11', date: '2025-05-14', desc: 'الدفعة الأخيرة', amount: 3564500 },
      ],
      otherExpenses: [
        { id: 'e1', desc: 'شراء الأرضية', amount: 3000000 },
        { id: 'e2', desc: 'البئر', amount: 2000000 },
      ],
      suleimanShare: 1660000,
      suleimanReceived: [660000, 1000000]
    },
    {
        id: 'm2',
        name: isRTL ? 'مسجد الحربي' : 'Mosquée Al-Harbi',
        receipts: [
            { id: 'r21', date: '2025-04-22', desc: 'الدفعة الأولى', sar: 100000, xof: 15880000, donor: 'الحربي' },
            { id: 'r22', date: '2025-06-23', desc: 'الدفعة الثانية', sar: 120000, xof: 17911000, donor: 'الحربي' },
        ],
        payments: [
            { id: 'p21', date: '2025-04-20', desc: 'الدفعة الأولى مقاول', amount: 3000000 },
        ],
        otherExpenses: [],
        suleimanShare: 2332500,
        suleimanReceived: [1500000, 810000]
    }
  ]);

  const [staffRewards, setStaffRewards] = useState<MosqueStaffReward[]>([
    { id: 'sr1', staffName: 'عيسى صلاح', role: 'إمام وخطيب ومدرس', amountXOF: 4300000 },
    { id: 'sr2', staffName: 'محمد مجيد', role: 'إمام وخطيب ومدرس', amountXOF: 2000000 },
    { id: 'sr3', staffName: 'أمينة', role: 'معلمة قرآن', amountXOF: 1900000 }
  ]);

  // Derived Data: Global Donors List
  const globalDonors = useMemo(() => {
    const map = new Map<string, { sar: number, xof: number, count: number }>();
    mosques.forEach(m => {
      m.receipts.forEach((r: any) => {
        const name = r.donor || 'متبرع فاعل خير';
        const current = map.get(name) || { sar: 0, xof: 0, count: 0 };
        map.set(name, {
          sar: current.sar + r.sar,
          xof: current.xof + r.xof,
          count: current.count + 1
        });
      });
    });
    return Array.from(map.entries()).map(([name, stats]) => ({ name, ...stats }));
  }, [mosques]);

  const activeMosque = useMemo(() => mosques.find(m => m.id === selectedMosqueId), [mosques, selectedMosqueId]);

  const activeStats = useMemo(() => {
    if (!activeMosque) return null;
    const totalSAR = activeMosque.receipts.reduce((s: any, r: any) => s + r.sar, 0);
    const totalXOF = activeMosque.receipts.reduce((s: any, r: any) => s + r.xof, 0);
    const totalPaid = activeMosque.payments.reduce((s: any, p: any) => s + p.amount, 0);
    const totalOther = activeMosque.otherExpenses.reduce((s: any, e: any) => s + e.amount, 0);
    const totalSuleimanRec = activeMosque.suleimanReceived.reduce((s: any, r: any) => s + r, 0);

    return {
        totalSAR,
        totalXOF,
        totalPaid,
        totalOther,
        totalSuleimanRec,
        balance: totalXOF - (totalPaid + totalOther),
        suleimanRemaining: activeMosque.suleimanShare - totalSuleimanRec
    };
  }, [activeMosque]);

  // Handlers
  const handleAddMosque = () => {
    if (!newMosqueName) return;
    const newM = {
      id: 'm-' + Math.random().toString(36).substr(2, 5),
      name: newMosqueName,
      receipts: [],
      payments: [],
      otherExpenses: [],
      suleimanShare: 0,
      suleimanReceived: []
    };
    setMosques([...mosques, newM]);
    setNewMosqueName('');
    setIsMosqueModalOpen(false);
    showNotification(isRTL ? 'تم إضافة المسجد بنجاح' : 'Mosque added', 'success');
  };

  const handleAddTransaction = () => {
    if (!activeMosque) return;
    const updatedMosques = mosques.map(m => {
      if (m.id === selectedMosqueId) {
        const newEntry = { 
            id: Math.random().toString(36).substr(2, 9), 
            date: txForm.date, 
            desc: txForm.desc, 
            sar: Number(txForm.sar) || 0, 
            xof: Number(txForm.xof) || 0,
            amount: Number(txForm.xof) || 0,
            donor: txForm.donor
        };
        if (txType === 'receipt') return { ...m, receipts: [...m.receipts, newEntry] };
        if (txType === 'payment') return { ...m, payments: [...m.payments, newEntry] };
        return { ...m, otherExpenses: [...m.otherExpenses, newEntry] };
      }
      return m;
    });
    setMosques(updatedMosques);
    setIsTransactionModalOpen(false);
    setTxForm({ desc: '', sar: '', xof: '', date: new Date().toISOString().split('T')[0], donor: '' });
    showNotification(t('success'), 'success');
  };

