                    <button onClick={() => { setTxType('payment'); setIsTransactionModalOpen(true); }} className="px-4 py-2 bg-rose-600 hover:bg-rose-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-rose-500/20 transition-all">
