                    <button onClick={() => { setTxType('expense'); setIsTransactionModalOpen(true); }} className="px-4 py-2 bg-amber-600 hover:bg-amber-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-amber-500/20 transition-all">
                        {isRTL ? 'مصروف آخر' : '+ Expense'}
                    </button>
                </div>
            </div>

