            </div>
            <div className="bg-orange-500/10 border border-orange-500/20 p-5 rounded-2xl text-center">
                <p className="text-[10px] text-orange-400 font-black uppercase mb-1">{isRTL ? 'المبلغ المراد صرفه' : 'Amount to Disburse'}</p>
