            </div>
            <button onClick={() => { showNotification('Payment Disbursed', 'success'); setIsPayoutModalOpen(false); }} className="w-full py-5 bg-orange-600 hover:bg-orange-700 text-white rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-orange-500/20 active:scale-95 transition-all">
                <Send size={24} /> {isRTL ? 'تأكيد عملية الصرف' : 'Confirm Payout'}
            </button>
        </div>
      </Modal>

      <footer className="max-w-7xl mx-auto mt-12 mb-10 text-center opacity-30 text-[10px] font-black uppercase tracking-[0.3em]">
        Niger Projects Group • Mosque Management v6.0
      </footer>
    </div>
  );
};

