      {/* Header with Search */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
            <h2 className="text-3xl font-black text-slate-800 tracking-tight">{isRTL ? 'نظام معلومات المخزون' : 'Inventory Info System'}</h2>
            <p className="text-slate-500 font-bold text-sm mt-1">{isRTL ? 'تتبع المواد الخام والمنتجات النهائية بدقة.' : 'Track raw materials and finished products.'}</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
            <div className="relative flex-1 md:w-64">
                <Search size={18} className={`absolute ${isRTL ? 'right-4' : 'left-4'} top-1/2 -translate-y-1/2 text-slate-400`} />
                <input 
                  type="text" 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder={t('search')}
                  className={`w-full ${isRTL ? 'pr-12' : 'pl-12'} py-3.5 bg-white border border-slate-200 rounded-2xl shadow-sm text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500/20 transition-all`}
                />
            </div>
            <button onClick={() => handleOpenModal()} className="bg-blue-600 hover:bg-blue-700 text-white p-3.5 rounded-2xl shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2">
                <Plus size={20} />
                <span className="hidden sm:inline font-black text-xs uppercase tracking-widest">{isRTL ? 'إضافة صنف' : 'Add Item'}</span>
            </button>
        </div>
      </div>

      {/* Mini Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
         <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center"><Package size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{isRTL ? 'إجمالي الأصناف' : 'Total Items'}</p>
                <p className="text-2xl font-black text-slate-800 font-mono">{stats.count}</p>
            </div>
         </div>
         <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center"><AlertTriangle size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{isRTL ? 'أصناف تحت الحد الحرج' : 'Low Stock Alert'}</p>
                <p className="text-2xl font-black text-amber-600 font-mono">{stats.lowStock}</p>
            </div>
         </div>
         <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center"><ShoppingCart size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{isRTL ? 'قيمة المخزون التقريبية' : 'Estimated Value'}</p>
                <p className="text-2xl font-black text-emerald-600 font-mono">{stats.totalValue.toLocaleString('en-US')} <small className="text-xs">SAR</small></p>
            </div>
         </div>
      </div>

      {/* Main Inventory Board */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        {/* Tabs Selector */}
        <div className="px-8 pt-8 border-b border-slate-50 flex items-center justify-between">
            <div className={`flex gap-10 ${isRTL ? 'justify-end' : 'justify-start'}`}>
                <button onClick={() => setActiveTab('raw')} className={`pb-6 text-xs font-black transition-all relative uppercase tracking-widest ${activeTab === 'raw' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                    {t('rawMaterials')}
                    {activeTab === 'raw' && <div className="absolute bottom-0 left-0 w-full h-1 bg-blue-600 rounded-full" />}
                </button>
                <button onClick={() => setActiveTab('finished')} className={`pb-6 text-xs font-black transition-all relative uppercase tracking-widest ${activeTab === 'finished' ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                    {isRTL ? 'المنتجات الجاهزة' : 'Finished Goods'}
                    {activeTab === 'finished' && <div className="absolute bottom-0 left-0 w-full h-1 bg-blue-600 rounded-full" />}
                </button>
            </div>
            <div className="pb-6">
                <Filter size={16} className="text-slate-300" />
            </div>
        </div>

        {/* Inventory List */}
        <div className="overflow-x-auto p-4 md:p-8">
            <table className="w-full text-right border-collapse">
                <thead className="bg-slate-50/50 rounded-2xl">
                    <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        <th className="px-6 py-5">{isRTL ? 'اسم الصنف' : 'Item Name'}</th>
                        <th className="px-6 py-5">{isRTL ? 'المستوى الحالي' : 'Stock Level'}</th>
                        <th className="px-6 py-5">{isRTL ? 'الحالة' : 'Status'}</th>
                        <th className="px-6 py-5">{isRTL ? 'المورد / السعر' : 'Info'}</th>
                        <th className="px-6 py-5 text-center">{isRTL ? 'إجراءات' : 'Actions'}</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                    {filteredItems.map(item => {
                        const status = getStockStatus(item);
                        const progress = (item.quantity / (item.maxQuantity || 100)) * 100;
                        return (
                            <tr key={item.id} className="group hover:bg-slate-50/80 transition-all">
                                <td className="px-6 py-6">
                                    <p className="font-black text-slate-800 text-sm">{isRTL ? item.nameAr : item.nameFr}</p>
                                    <p className="text-[10px] text-slate-400 font-bold uppercase mt-0.5 tracking-tighter">ID: {item.id}</p>
                                </td>
                                <td className="px-6 py-6 min-w-[180px]">
                                    <div className="space-y-2">
                                        <div className="flex justify-between items-baseline font-mono text-[11px] font-black">
                                            <span className="text-slate-700">{item.quantity.toLocaleString('en-US')} <small className="opacity-50">{item.unit}</small></span>
                                            <span className="text-slate-400">Target: {item.maxQuantity}</span>
                                        </div>
                                        <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                                            <div className={`h-full transition-all duration-700 ${progress < 20 ? 'bg-rose-500' : progress < 50 ? 'bg-amber-500' : 'bg-emerald-500'}`} style={{width: `${Math.min(100, progress)}%`}} />
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-6">
                                    <span className={`px-3 py-1.5 rounded-xl border text-[10px] font-black uppercase tracking-wider ${status.color}`}>
                                        {status.label}
                                    </span>
                                </td>
                                <td className="px-6 py-6">
                                    <p className="text-xs font-bold text-slate-700">{activeTab === 'raw' ? (item as RawMaterial).supplier : `${item.price} SAR`}</p>
                                    <p className="text-[10px] text-slate-400 font-medium">Updated: {item.lastUpdated}</p>
                                </td>
                                <td className="px-6 py-6">
                                    <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        {activeTab === 'raw' && (
                                            <button onClick={() => handleOpenRestock(item as RawMaterial)} className="p-2.5 bg-emerald-50 text-emerald-600 rounded-xl hover:bg-emerald-600 hover:text-white transition-all">
                                                <ShoppingCart size={16} />
                                            </button>
                                        )}
                                        <button onClick={() => handleOpenModal(item)} className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all">
                                            <Edit2 size={16} />
                                        </button>
                                        <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all">
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editItem ? (isRTL ? 'تعديل الصنف' : 'Edit Item') : (isRTL ? 'إضافة صنف جديد' : 'New Item')} isRTL={isRTL}>
         <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className={labelClass}>الاسم (AR)</label>
                    <input type="text" value={formData.nameAr} onChange={(e) => setFormData({...formData, nameAr: e.target.value})} className={inputClass} placeholder="مثال: ورق كرتون" />
                </div>
                <div>
                    <label className={labelClass}>Nom (FR)</label>
                    <input type="text" value={formData.nameFr} onChange={(e) => setFormData({...formData, nameFr: e.target.value})} className={inputClass} placeholder="Ex: Papier" />
                </div>
            </div>

            <div className="grid grid-cols-3 gap-4">
                <div>
                    <label className={labelClass}>{isRTL ? 'الكمية الحالية' : 'Current Qty'}</label>
                    <input type="number" value={formData.quantity} onChange={(e) => setFormData({...formData, quantity: Number(e.target.value)})} className={inputClass} />
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'الحد الحرج (تنبيه)' : 'Min Alert Level'}</label>
                    <input type="number" value={formData.minLevel} onChange={(e) => setFormData({...formData, minLevel: Number(e.target.value)})} className={inputClass + " border-amber-100 text-amber-600 focus:border-amber-500"} />
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'السعة القصوى' : 'Max Cap'}</label>
                    <input type="number" value={formData.maxQuantity} onChange={(e) => setFormData({...formData, maxQuantity: Number(e.target.value)})} className={inputClass} />
                </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className={labelClass}>{isRTL ? 'الوحدة' : 'Unit'}</label>
                    <select value={formData.unit} onChange={(e) => setFormData({...formData, unit: e.target.value})} className={inputClass}>
                        <option value="kg">KG</option>
                        <option value="plate">Plate</option>
                        <option value="l">Litre</option>
                        <option value="ton">Ton</option>
                    </select>
                </div>
                <div>
                    <label className={labelClass}>{isRTL ? 'سعر الوحدة' : 'Unit Price'}</label>
                    <input type="number" step="0.01" value={formData.unitPrice} onChange={(e) => setFormData({...formData, unitPrice: Number(e.target.value)})} className={inputClass} />
                </div>
            </div>

            {activeTab === 'raw' && (
                <div>
                    <label className={labelClass}>{isRTL ? 'المورد الافتراضي' : 'Default Supplier'}</label>
                    <input type="text" value={formData.supplier} onChange={(e) => setFormData({...formData, supplier: e.target.value})} className={inputClass} placeholder="Supplier Name" />
                </div>
            )}

            <button onClick={handleSave} className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black shadow-xl shadow-blue-500/20 active:scale-95 transition-all">
                {isRTL ? 'حفظ الصنف' : 'Save Item'}
            </button>
         </div>
      </Modal>

      {/* Restock Purchase Modal */}
      <Modal isOpen={isRestockModalOpen} onClose={() => setIsRestockModalOpen(false)} title={isRTL ? 'شراء توريد جديد' : 'Restock Material'} isRTL={isRTL}>
          <div className="space-y-6">
              <div className="p-6 bg-slate-900 rounded-2xl text-white">
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">Target Material</p>
                  <h4 className="text-xl font-black">{isRTL ? restockItem?.nameAr : restockItem?.nameFr}</h4>
                  <p className="text-xs text-emerald-400 font-bold mt-1">Default Price: {restockItem?.price} SAR / {restockItem?.unit}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className={labelClass}>{isRTL ? 'الكمية المضافة' : 'Quantity Added'}</label>
                    <input type="number" value={restockData.quantity} onChange={(e) => setRestockData({...restockData, quantity: Number(e.target.value), totalCost: Number(e.target.value) * (restockItem?.price || 0)})} className={inputClass} />
                  </div>
                  <div>
                    <label className={labelClass}>{isRTL ? 'إجمالي التكلفة (SAR)' : 'Total Cost'}</label>
                    <input type="number" value={restockData.totalCost} onChange={(e) => setRestockData({...restockData, totalCost: Number(e.target.value)})} className={inputClass} />
                  </div>
              </div>
              <button onClick={handleRestockSubmit} className="w-full py-5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black active:scale-95 transition-all">
                  {isRTL ? 'تأكيد عملية الشراء' : 'Confirm Purchase'}
              </button>
          </div>
      </Modal>
    </div>
  );
};

