import React, { useState, useMemo } from 'react';
import { 
  Church, 
  Plus, 
  ArrowUpRight, 
  ArrowDownRight, 
  Calculator, 
  HandCoins,
  FileText,
  Calendar,
  UserPlus,
  Send,
  CreditCard,
  History,
  TrendingUp,
  Briefcase,
  Building,
  Users,
  Wallet,
