                    <label className="text-[10px] font-black text-slate-500 uppercase block mb-1">XOF</label>
                    <input type="number" value={txForm.xof} onChange={e => setTxForm({...txForm, xof: e.target.value})} className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none text-orange-400" />
                </div>
            </div>
            <button onClick={handleAddTransaction} className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black mt-4 transition-all">
                {isRTL ? 'تأكيد وحفظ' : 'Confirm & Save'}
            </button>
        </div>
      </Modal>

      <footer className="max-w-7xl mx-auto mt-12 mb-10 text-center opacity-30 text-[10px] font-black uppercase tracking-[0.3em]">
        Niger Projects Group • Unified Accounting v7.0
      </footer>
    </div>
  );
};

export default MosqueManagement;

import React, { useState, useEffect, useCallback } from 'react';
import { Globe, Menu, ArrowLeft } from 'lucide-react';
// استيراد المكونات الفرعية
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Orders from './components/Orders';
import Customers from './components/Customers';
import StaffView from './components/Staff';
import Production from './components/Production';
import Finance from './components/Finance';
import Login from './components/Login';
import Hub from './components/Hub';
import MakhGold from './components/MakhGold';
import GeneralAdmin from './components/GeneralAdmin';
import MosqueManagement from './components/MosqueManagement';
import Toast from './components/Toast';
// استيراد الأنواع والثوابت
import { Language, Customer, Product, RawMaterial, Order, Staff, Expense, Notification, EntityType, GoldTransaction, Appointment } from './types';
import { TRANSLATIONS, MOCK_CUSTOMERS, MOCK_PRODUCTS, MOCK_RAW_MATERIALS, MOCK_ORDERS, MOCK_STAFF, MOCK_EXPENSES, MOCK_GOLD_TRANSACTIONS, MOCK_APPOINTMENTS } from './constants';

const App: React.FC = () => {
  // =========================================
  // إدارة حالة التطبيق (State Management)
  // =========================================
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [currentEntity, setCurrentEntity] = useState<EntityType>('MASTER');
  const [currentView, setCurrentView] = useState('dashboard');
  const [lang, setLang] = useState<Language>(Language.AR);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);

  // =========================================
  // بيانات النظام (مع التخزين المحلي LocalStorage)
  // =========================================
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('np_customers') || JSON.stringify(MOCK_CUSTOMERS)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('np_products') || JSON.stringify(MOCK_PRODUCTS)));
  const [materials, setMaterials] = useState<RawMaterial[]>(() => JSON.parse(localStorage.getItem('np_materials') || JSON.stringify(MOCK_RAW_MATERIALS)));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('np_orders') || JSON.stringify(MOCK_ORDERS)));
  const [staff, setStaff] = useState<Staff[]>(() => JSON.parse(localStorage.getItem('np_staff') || JSON.stringify(MOCK_STAFF)));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('np_expenses') || JSON.stringify(MOCK_EXPENSES)));
  const [goldTransactions, setGoldTransactions] = useState<GoldTransaction[]>(() => JSON.parse(localStorage.getItem('np_gold_tx') || JSON.stringify(MOCK_GOLD_TRANSACTIONS)));
  const [appointments, setAppointments] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('np_appointments') || JSON.stringify(MOCK_APPOINTMENTS)));

  const isRTL = lang === Language.AR;
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;

  // =========================================
  // حفظ البيانات تلقائياً عند التغيير
  // =========================================
  useEffect(() => {
    localStorage.setItem('np_customers', JSON.stringify(customers));
    localStorage.setItem('np_products', JSON.stringify(products));
    localStorage.setItem('np_materials', JSON.stringify(materials));
    localStorage.setItem('np_orders', JSON.stringify(orders));
    localStorage.setItem('np_staff', JSON.stringify(staff));
    localStorage.setItem('np_expenses', JSON.stringify(expenses));
    localStorage.setItem('np_gold_tx', JSON.stringify(goldTransactions));
    localStorage.setItem('np_appointments', JSON.stringify(appointments));
  }, [customers, products, materials, orders, staff, expenses, goldTransactions, appointments]);

  // دالة لعرض الإشعارات
  const showNotification = useCallback((message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
  }, []);

  // دالة تغيير اللغة
  const toggleLanguage = () => setLang(prev => prev === Language.AR ? Language.FR : Language.AR);

  // دالة تسجيل الدخول
  const handleLogin = (user: Staff) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    if (user.allowedEntity && user.allowedEntity !== 'MASTER' && user.allowedEntity !== 'GENERAL_ADMIN') {
        setCurrentEntity(user.allowedEntity);
    } else {
        setCurrentEntity('MASTER');
    }
  };

  // دالة تسجيل الخروج
  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentEntity('MASTER');
  };

  // =========================================
  // التوجيه (Routing) وعرض الصفحات
  // =========================================

  // 1. شاشة تسجيل الدخول
  if (!isLoggedIn) return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Login lang={lang} onLogin={handleLogin} toggleLanguage={toggleLanguage} staff={staff} showNotification={showNotification} />
    </>
  );

  // 2. المركز الرئيسي (HUB)
  if (currentEntity === 'MASTER') return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Hub lang={lang} onSelectEntity={(e) => { setCurrentEntity(e); setCurrentView('dashboard'); }} onLogout={handleLogout} />
    </>
  );

  // 3. إدارة الذهب (عرض خاص)
  if (currentEntity === 'MAKH_GOLD') return (
    <MakhGold 
      lang={lang} 
      onLogout={() => setCurrentEntity('MASTER')} 
      goldTransactions={goldTransactions} 
      setGoldTransactions={setGoldTransactions} 
      shareholders={[]} 
      setShareholders={() => {}} 
      showNotification={showNotification} 
    />
  );

  // 4. إدارة المساجد (عرض خاص)
  if (currentEntity === 'MOSQUE') return (
    <MosqueManagement 
      lang={lang} 
      onLogout={() => setCurrentEntity('MASTER')} 
      showNotification={showNotification} 
    />
  );

  // 5. الإدارة العامة (عرض خاص)
  if (currentEntity === 'GENERAL_ADMIN') return (
    <GeneralAdmin 
      lang={lang} 
      onLogout={() => setCurrentEntity('MASTER')} 
      expenses={expenses} 
      goldTransactions={goldTransactions} 
      orders={orders} 
      staff={staff} 
      setStaff={setStaff} 
      appointments={appointments} 
      setAppointments={setAppointments} 
      showNotification={showNotification} 
      currentUser={currentUser} 
    />
  );

  // 6. لوحة التحكم الافتراضية للمصنع
  const renderContent = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard lang={lang} setCurrentView={setCurrentView} orders={orders} staff={staff} expenses={expenses} materials={materials} products={products} />;
      case 'inventory': return <Inventory lang={lang} materials={materials} setMaterials={setMaterials} products={products} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} showNotification={showNotification} onRestockMaterial={() => {}} />;
      case 'orders': return <Orders lang={lang} customers={customers} orders={orders} setOrders={setOrders} products={products} setProducts={setProducts} setExpenses={setExpenses} showNotification={showNotification} />;
      case 'customers': return <Customers lang={lang} customers={customers} setCustomers={setCustomers} showNotification={showNotification} />;
      case 'staff': return <StaffView lang={lang} staff={staff} setStaff={setStaff} onPaySalary={() => {}} onRequestAdvance={() => {}} showNotification={showNotification} />;
      case 'production': return <Production lang={lang} products={products} setProducts={setProducts} materials={materials} setMaterials={setMaterials} showNotification={showNotification} />;
      case 'finance': return <Finance lang={lang} expenses={expenses} setExpenses={setExpenses} orders={orders} showNotification={showNotification} />;
      default: return <Dashboard lang={lang} setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div dir={isRTL ? 'rtl' : 'ltr'} className={`flex h-screen bg-slate-50 overflow-hidden ${isRTL ? 'font-cairo' : 'font-sans'}`}>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}

      {/* القائمة الجانبية */}
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} lang={lang} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        {/* الشريط العلوي */}
        <header className="h-20 bg-white border-b border-slate-100 flex items-center justify-between px-8 z-10 print:hidden">
          <div className="flex items-center gap-6">
             <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-slate-500"><Menu size={24} /></button>
             <button onClick={() => setCurrentEntity('MASTER')} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all">
               <ArrowLeft size={16} className={isRTL ? 'rotate-180' : ''} />
               {t('backToHub')}
             </button>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden sm:block text-sm text-slate-400 font-bold">
                {lang === Language.AR ? `أهلاً، ${currentUser?.name || 'سليمان'}` : `Welcome, ${currentUser?.name || 'Suleiman'}`}
             </div>
             <button onClick={toggleLanguage} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-50 text-slate-600 hover:bg-slate-100 transition-all text-xs font-bold border border-slate-200">
               <Globe size={14} />
               {lang === Language.AR ? 'Français' : 'العربية'}
             </button>
             <h2 className="hidden md:flex items-center gap-2 text-sm font-black text-slate-800">
               {t(currentView)}
             </h2>
          </div>
        </header>

        {/* المحتوى الرئيسي */}
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 bg-slate-50/50">
          <div className="max-w-7xl mx-auto h-full">{renderContent()}</div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Search, Plus, UserPlus, DollarSign, Wallet, Trash2, Edit } from 'lucide-react';
import { Language, Staff } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface StaffProps {
  lang: Language;
  staff: Staff[];
  setStaff: (s: Staff[]) => void;
  onPaySalary: (id: string) => void;
  onRequestAdvance: (id: string, amount: number) => void;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const StaffView: React.FC<StaffProps> = ({ lang, staff, setStaff, onPaySalary, onRequestAdvance, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة المودالات والتحرير
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAdvanceModalOpen, setIsAdvanceModalOpen] = useState(false);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [advanceAmount, setAdvanceAmount] = useState(0);
  const [editMode, setEditMode] = useState(false);

  // حالة النموذج (إضافة/تعديل)
  const [formData, setFormData] = useState({ id: '', name: '', roleAr: '', roleFr: '', salary: 0 });

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // فتح المودال للإضافة
  const openAddModal = () => {
      setEditMode(false);
      setFormData({ id: '', name: '', roleAr: '', roleFr: '', salary: 0 });
      setIsModalOpen(true);
  };

  // فتح المودال للتعديل
  const openEditModal = (employee: Staff) => {
      setEditMode(true);
      setFormData({ 
          id: employee.id, 
          name: employee.name, 
          roleAr: employee.roleAr, 
          roleFr: employee.roleFr, 
          salary: employee.salary 
      });
      setIsModalOpen(true);
  };

  // حفظ البيانات (إضافة أو تعديل)
  const handleSaveStaff = () => {
    try {
        if (!formData.name || formData.salary <= 0) {
            showNotification(isRTL ? 'بيانات غير مكتملة' : 'Incomplete data', 'error');
            return;
        }

        if (editMode) {
            // منطق التعديل
            const updatedStaff = staff.map(s => s.id === formData.id ? { ...s, ...formData } : s);
            setStaff(updatedStaff);
            showNotification(t('success'), 'success');
        } else {
            // منطق الإضافة
            const newStaff: Staff = {
                id: Math.random().toString(36).substr(2, 9),
                name: formData.name,
                roleAr: formData.roleAr,
                roleFr: formData.roleFr,
                salary: Number(formData.salary),
                lastPaymentDate: '-',
                advanceTaken: 0,
                loginCount: 0,
                loginHistory: []
            };
            setStaff([...staff, newStaff]);
            showNotification(t('success'), 'success');
        }
        setIsModalOpen(false);
    } catch(e) {
        showNotification(t('error'), 'error');
    }
  };

  // حذف موظف
  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'هل أنت متأكد من حذف هذا الموظف؟' : 'Are you sure you want to delete this employee?')) {
          setStaff(staff.filter(s => s.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  // طلب سلفة
  const handleRequestAdvance = () => {
      if(!selectedStaffId || advanceAmount <= 0) return;
      // تحديث قيمة السلفة للموظف
      setStaff(staff.map(s => s.id === selectedStaffId ? { ...s, advanceTaken: s.advanceTaken + Number(advanceAmount) } : s));
      setIsAdvanceModalOpen(false);
      setAdvanceAmount(0);
      setSelectedStaffId(null);
      showNotification(t('success'), 'success');
  }

  const inputClass = "w-full border-2 border-slate-200 bg-slate-50 text-slate-900 rounded-xl p-3 focus:border-blue-500 focus:bg-white outline-none transition-all font-bold placeholder:text-slate-400";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5";

  return (
    <div className="space-y-6">
      {/* الترويسة */}
      <div className="flex justify-between items-center">
        <h2 className={`text-2xl font-black text-slate-800 ${isRTL ? 'font-cairo' : 'font-sans'}`}>
          {t('staff')}
        </h2>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl transition-all text-sm font-black shadow-lg shadow-blue-500/20"
        >
          <UserPlus size={18} />
          <span>{lang === Language.AR ? 'موظف جديد' : 'Nouvel employé'}</span>
        </button>
      </div>

      {/* جدول الموظفين */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('name')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('role')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('salary')}</th>
                 <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('advance')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{lang === Language.AR ? 'آخر راتب' : 'Dernier paiement'}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('actions')}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {staff.map((emp: Staff) => (
                <tr key={emp.id} className="hover:bg-slate-50 transition-colors">
                  <td className={`px-6 py-4 text-sm font-bold text-slate-900 ${isRTL ? 'text-right' : 'text-left'}`}>{emp.name}</td>
                  <td className={`px-6 py-4 text-sm text-slate-600 ${isRTL ? 'text-right' : 'text-left'}`}>
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-black uppercase bg-blue-50 text-blue-700">
                      {lang === Language.AR ? emp.roleAr : emp.roleFr}
                    </span>
                  </td>
                  <td className={`px-6 py-4 text-sm text-slate-600 font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.salary.toLocaleString()} SAR</td>
                  <td className={`px-6 py-4 text-sm text-red-500 font-black font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.advanceTaken > 0 ? `-${emp.advanceTaken.toLocaleString()}` : '-'}</td>
                  <td className={`px-6 py-4 text-sm text-slate-500 font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.lastPaymentDate}</td>
                  <td className="px-6 py-4 text-sm flex gap-2">
                    <button onClick={() => openEditModal(emp)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-all" title={t('edit')}><Edit size={18} /></button>
                    <button onClick={() => handleDelete(emp.id)} className="p-2 text-rose-600 hover:bg-rose-50 rounded-xl transition-all" title={t('delete')}><Trash2 size={18} /></button>
                    <button onClick={() => onPaySalary(emp.id)} className="p-2 text-green-600 hover:bg-green-50 rounded-xl transition-all" title={t('paySalary')}><DollarSign size={18} /></button>
                    <button onClick={() => { setSelectedStaffId(emp.id); setIsAdvanceModalOpen(true); }} className="p-2 text-orange-600 hover:bg-orange-50 rounded-xl transition-all" title={t('requestAdvance')}><Wallet size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* مودال الإضافة/التعديل */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editMode ? (isRTL ? 'تعديل بيانات' : 'Edit Staff') : (lang === Language.AR ? 'موظف جديد' : 'Nouvel employé')} isRTL={isRTL}>
        <div className="space-y-4">
          <div><label className={labelClass}>{t('name')}</label><input type="text" className={inputClass} value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} /></div>
          <div><label className={labelClass}>Role (Ar)</label><input type="text" className={inputClass} value={formData.roleAr} onChange={(e) => setFormData({...formData, roleAr: e.target.value})} /></div>
          <div><label className={labelClass}>Role (Fr)</label><input type="text" className={inputClass} value={formData.roleFr} onChange={(e) => setFormData({...formData, roleFr: e.target.value})} /></div>
           <div><label className={labelClass}>{t('salary')}</label><input type="number" className={inputClass} value={formData.salary} onChange={(e) => setFormData({...formData, salary: Number(e.target.value)})} /></div>
          <div className="pt-4 flex justify-end gap-2"><button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-xs font-black text-slate-500">{t('cancel')}</button><button onClick={handleSaveStaff} className="px-8 py-3 text-xs bg-blue-600 text-white rounded-xl font-black shadow-lg shadow-blue-500/20">{t('save')}</button></div>
        </div>
      </Modal>

      {/* مودال السلفة */}
      <Modal isOpen={isAdvanceModalOpen} onClose={() => setIsAdvanceModalOpen(false)} title={t('requestAdvance')} isRTL={isRTL}>
           <div className="space-y-4">
               <div><label className={labelClass}>{t('amount')}</label><input type="number" className={inputClass} value={advanceAmount} onChange={(e) => setAdvanceAmount(Number(e.target.value))} /></div>
              <div className="pt-4 flex justify-end gap-2"><button onClick={() => setIsAdvanceModalOpen(false)} className="px-6 py-3 text-xs font-black text-slate-500">{t('cancel')}</button><button onClick={handleRequestAdvance} className="px-8 py-3 text-xs bg-blue-600 text-white rounded-xl font-black shadow-lg shadow-blue-500/20">{t('save')}</button></div>
           </div>
      </Modal>
    </div>
  );
};

export default StaffView;

import React, { useState } from 'react';
import { DollarSign, TrendingDown, TrendingUp, Plus, Trash2 } from 'lucide-react';
import { Language, Expense, Order, OrderStatus } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface FinanceProps {
  lang: Language;
  expenses: Expense[];
  setExpenses: (e: Expense[]) => void;
  orders: Order[];
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Finance: React.FC<FinanceProps> = ({ lang, expenses, setExpenses, orders, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حسابات الإجماليات (Totals Calculation)
  // =========================================
  const totalIncome = expenses.filter(e => e.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
  const totalExpenses = expenses.filter(e => e.type === 'expense').reduce((acc, curr) => acc + curr.amount, 0);
  const netProfit = totalIncome - totalExpenses;

  // =========================================
  // حالة البيانات (State)
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newExpense, setNewExpense] = useState({ description: '', amount: 0, category: 'Utility', customType: '' });

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // إضافة مصروف جديد
  const handleAddExpense = () => {
      try {
        if (newExpense.amount <= 0 || !newExpense.description) {
            showNotification(isRTL ? 'بيانات ناقصة' : 'Missing data', 'error');
            return;
        }

        const finalDescription = newExpense.category === 'Other' && newExpense.customType 
            ? `${newExpense.customType} - ${newExpense.description}` 
            : newExpense.description;

        const exp: Expense = {
            id: Math.random().toString(),
            type: 'expense',
            date: new Date().toISOString().split('T')[0],
            description: finalDescription,
            amount: Number(newExpense.amount),
            category: newExpense.category as any
        };
        setExpenses([exp, ...expenses]);
        setIsModalOpen(false);
        setNewExpense({ description: '', amount: 0, category: 'Utility', customType: '' });
        showNotification(t('success'), 'success');
      } catch(e) {
          showNotification(t('error'), 'error');
      }
  }

  // حذف مصروف
  const handleDelete = (id: string) => {
