  const [karahValue, setKarahValue] = useState<number>(0);
  const [exchangeRateXOF, setExchangeRateXOF] = useState<number>(160);

  // حساب المبلغ تلقائياً بناءً على الوزن والكارة
  useEffect(() => {
    if(txForm.goldWeight && karahValue) {
        const total = txForm.goldWeight * karahValue;
        setTxForm(prev => ({...prev, amountRiyal: total}));
    } else {
        setTxForm(prev => ({...prev, amountRiyal: 0}));
    }
