  Eye,
  EyeOff,
  History,
  ShieldCheck,
  ClipboardList,
  Edit,
  ChevronRight
} from 'lucide-react';
import { Language, Expense, GoldTransaction, Order, Staff, Appointment, EntityType } from '../types';
import { TRANSLATIONS, ENTITIES } from '../constants';
import Modal from './Modal';

interface GeneralAdminProps {
  lang: Language;
  onLogout: () => void;
  expenses: Expense[];
  goldTransactions: GoldTransaction[];
  orders: Order[];
  staff: Staff[];
  setStaff: (s: Staff[]) => void;
  appointments: Appointment[];
  setAppointments: (a: Appointment[]) => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  currentUser: Staff | null;
}

const GeneralAdmin: React.FC<GeneralAdminProps> = ({ 
    lang, onLogout, expenses, goldTransactions, orders, 
    staff, setStaff, appointments, setAppointments, showNotification, currentUser 
}) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة التحكم في التبويبات والمودال
  // =========================================
  const [activeTab, setActiveTab] = useState<'overview' | 'users' | 'appointments'>('overview');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'user' | 'appointment' | 'userDetails' | 'changePassword'>('user');

  // المستخدم/الموعد النشط للعمليات
  const [selectedItem, setSelectedItem] = useState<any | null>(null);
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [newPassword, setNewPassword] = useState('');

  // =========================================
  // نماذج الإدخال (Form States)
  // =========================================
  const [userForm, setUserForm] = useState<Partial<Staff>>({ name: '', roleAr: '', salary: 0, allowedEntity: 'FACTORY', password: '' });
  const [aptForm, setAptForm] = useState<Partial<Appointment>>({ 
    title: '', date: '', time: '', location: '', notes: '', tasks: [] 
  });
  const [currentTask, setCurrentTask] = useState('');

  // تنسيق الأرقام بالإنجليزية
  const formatNum = (val: number) => val.toLocaleString('en-US');

  // =========================================
  // منطق الإدارة المالية
  // =========================================
  const factoryIncome = expenses.filter(e => e.type === 'income').reduce((sum, e) => sum + e.amount, 0);
  const factoryExpenses = expenses.filter(e => e.type === 'expense').reduce((sum, e) => sum + e.amount, 0);
  const goldPurchases = goldTransactions.filter(t => t.type === 'purchase').reduce((sum, t) => sum + t.amountRiyal, 0);
  const totalNetWorth = (factoryIncome - factoryExpenses) + (goldPurchases * 0.05);

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // إدارة الموظفين
  const handleAddUser = () => {
    if(!userForm.name || !userForm.password) return;
    const newUser: Staff = {
        id: Math.random().toString(36).substr(2, 9),
        name: userForm.name!,
        roleAr: userForm.roleAr || 'موظف',
        roleFr: 'Employee',
        salary: Number(userForm.salary),
        lastPaymentDate: '-',
        advanceTaken: 0,
        allowedEntity: userForm.allowedEntity,
        password: userForm.password,
        loginCount: 0,
        loginHistory: []
    };
    setStaff([...staff, newUser]);
    setIsModalOpen(false);
    showNotification(t('success'), 'success');
  };

  // إدارة الاجتماعات (CRUD)
  const handleSaveAppointment = () => {
    if(!aptForm.title || !aptForm.date) return;

    if (selectedItem) {
        // تعديل
        setAppointments(appointments.map(a => a.id === selectedItem.id ? { ...a, ...aptForm } as Appointment : a));
    } else {
        // إضافة جديد
        const newApt: Appointment = {
            id: Math.random().toString(36).substr(2, 9),
            title: aptForm.title!,
            date: aptForm.date!,
            time: aptForm.time || '09:00 AM',
            location: aptForm.location || 'Conference Room',
            notes: aptForm.notes || '',
            tasks: aptForm.tasks || []
        };
        setAppointments([...appointments, newApt]);
    }
    setIsModalOpen(false);
    setSelectedItem(null);
    setAptForm({ title: '', date: '', time: '', location: '', notes: '', tasks: [] });
    showNotification(t('success'), 'success');
  };

  const openEditAppointment = (apt: Appointment) => {
      setSelectedItem(apt);
      setAptForm({ ...apt });
      setModalType('appointment');
      setIsModalOpen(true);
  };

  const handleDeleteAppointment = (id: string) => {
      if(confirm(isRTL ? 'حذف هذا الاجتماع نهائياً؟' : 'Delete this meeting permanently?')) {
          setAppointments(appointments.filter(a => a.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  const addTask = () => {
      if(!currentTask.trim()) return;
      setAptForm({ ...aptForm, tasks: [...(aptForm.tasks || []), currentTask] });
      setCurrentTask('');
  };

  const removeTask = (index: number) => {
      setAptForm({ ...aptForm, tasks: aptForm.tasks?.filter((_, i) => i !== index) });
  };

  return (
    <div className={`min-h-screen bg-slate-950 text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'} onClick={() => setActiveMenuId(null)}>
        {/* الشريط العلوي */}
        <header className="bg-slate-900 border-b border-white/5 p-6 sticky top-0 z-50">
            <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white text-slate-950 rounded-xl flex items-center justify-center shadow-lg">
                        <Building2 size={28} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black tracking-tight text-white">{isRTL ? 'الإدارة العامة للمجموعة' : 'General Administration'}</h1>
                        <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{isRTL ? 'لوحة تحكم المالك والعمليات' : 'Owner & Operations Control'}</p>
                    </div>
                </div>

                <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg">
                    <button onClick={() => setActiveTab('overview')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('dashboard')}
                    </button>
                    <button onClick={() => setActiveTab('users')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('usersManagement')}
                    </button>
                    <button onClick={() => setActiveTab('appointments')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'appointments' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('appointments')}
                    </button>
                </nav>

                <button onClick={onLogout} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold transition-colors">
                    {t('logout')}
                </button>
            </div>
        </header>

        <main className="max-w-7xl mx-auto p-8 space-y-10 animate-fade-in-up">

            {/* تبويب نظرة عامة */}
            {activeTab === 'overview' && (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-2 bg-gradient-to-br from-slate-900 to-slate-800 p-10 rounded-[3rem] border border-white/5 relative overflow-hidden shadow-2xl">
                        <div className="absolute top-0 right-0 w-80 h-80 bg-blue-600/10 rounded-full blur-[100px] -mr-20 -mt-20"></div>
                        <h2 className="text-slate-500 font-black uppercase tracking-widest text-xs mb-3">{isRTL ? 'صافي الثروة المجمعة للمجموعة' : 'Group Consolidated Net Worth'}</h2>
                        <div className="flex items-baseline gap-4">
                            <span className="text-6xl font-black text-white tracking-tighter">{formatNum(totalNetWorth)}</span>
                            <span className="text-xl font-bold text-slate-500 font-mono">SAR</span>
                        </div>
                    </div>
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-white/5 flex flex-col justify-center gap-4">
                        <div className="flex justify-between items-center p-5 bg-white/5 rounded-2xl">
                            <span className="text-xs font-black text-slate-400">{isRTL ? 'المصنع' : 'Factory'}</span>
                            <span className="font-mono font-black text-blue-400">+{formatNum(factoryIncome-factoryExpenses)}</span>
                        </div>
                        <div className="flex justify-between items-center p-5 bg-white/5 rounded-2xl">
                            <span className="text-xs font-black text-slate-400">{isRTL ? 'الذهب' : 'Gold'}</span>
                            <span className="font-mono font-black text-amber-400">+{formatNum(goldPurchases * 0.05)}</span>
                        </div>
                    </div>
                </div>
            )}

            {/* تبويب المستخدمين */}
            {activeTab === 'users' && (
                <div className="space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-2xl font-black uppercase tracking-tight">{t('usersManagement')}</h2>
                        <button onClick={() => { setModalType('user'); setIsModalOpen(true); }} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all">
                            <Plus size={16} /> {isRTL ? 'إضافة موظف' : 'New User'}
                        </button>
                    </div>
                    {/* جدول المستخدمين المختصر */}
                    <div className="bg-slate-900 rounded-[2.5rem] border border-white/5 overflow-hidden">
                        <table className="w-full text-right text-sm">
                            <thead className="bg-slate-950 text-xs font-black uppercase text-slate-500 tracking-widest">
                                <tr>
                                    <th className="px-8 py-5">الموظف</th>
                                    <th className="px-8 py-5">الصلاحية</th>
                                    <th className="px-8 py-5">الدور</th>
                                    <th className="px-8 py-5 text-center">الإجراءات</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {staff.map(s => (
                                    <tr key={s.id} className="hover:bg-white/5 transition-colors">
                                        <td className="px-8 py-5 font-black text-white">{s.name}</td>
                                        <td className="px-8 py-5 font-mono text-xs text-blue-400">{s.allowedEntity || 'FACTORY'}</td>
                                        <td className="px-8 py-5 text-slate-400">{isRTL ? s.roleAr : s.roleFr}</td>
                                        <td className="px-8 py-5 text-center">
                                            <button className="p-2 text-slate-500 hover:text-white transition-colors"><MoreVertical size={18}/></button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* تبويب المواعيد والاجتماعات (الجديد والمعدل) */}
            {activeTab === 'appointments' && (
                <div className="space-y-10">
                    <div className="flex justify-between items-center">
                        <div>
                            <h2 className="text-3xl font-black text-white tracking-tight">{isRTL ? 'البشرية الموارد أعمال اجتماعات جدول خطة' : 'HR Business Meeting Schedule'}</h2>
                            <p className="text-slate-500 text-xs font-bold mt-2 uppercase tracking-widest opacity-70">Strategic Planning & Operations Calendar</p>
                        </div>
                        <button 
                            onClick={() => { setSelectedItem(null); setAptForm({title:'', date:'', time:'', location:'', notes:'', tasks:[]}); setModalType('appointment'); setIsModalOpen(true); }}
                            className="bg-white text-slate-950 px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:bg-slate-200 transition-all active:scale-95 flex items-center gap-3"
                        >
                            <Plus size={18} /> {isRTL ? 'إضافة اجتماع جديد' : 'Schedule Meeting'}
                        </button>
                    </div>

                    {/* جدول الاجتماعات المصمم على غرار الصورة */}
                    <div className="bg-slate-900 rounded-[3rem] border border-white/10 overflow-hidden shadow-2xl animate-in slide-in-from-bottom-8 duration-700">
                        <div className="overflow-x-auto">
                            <table className="w-full text-center border-collapse">
                                <thead>
                                    <tr className="bg-[#1a1c23]">
                                        {/* رؤوس الأعمدة بتصميم الصورة */}
                                        <th className="px-6 py-8 border-r border-white/5 min-w-[150px]">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#9c4d51] px-8 py-2 rounded-t-xl text-white text-xs font-black uppercase tracking-[0.2em] relative">
                                                    Date <Calendar size={14} className="absolute -top-1 -right-1 opacity-50" />
                                                </div>
                                                <div className="w-full h-1 bg-[#9c4d51] opacity-50"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 border-r border-white/5 min-w-[250px]">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#606b53] px-8 py-2 rounded-t-xl text-white text-xs font-black uppercase tracking-[0.2em] relative">
                                                    Meeting <Users size={14} className="absolute -top-1 -right-1 opacity-50" />
                                                </div>
                                                <div className="w-full h-1 bg-[#606b53] opacity-50"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 border-r border-white/5 min-w-[180px]">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#5c6978] px-8 py-2 rounded-t-xl text-white text-xs font-black uppercase tracking-[0.2em] relative">
                                                    Location <MapPin size={14} className="absolute -top-1 -right-1 opacity-50" />
                                                </div>
                                                <div className="w-full h-1 bg-[#5c6978] opacity-50"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 border-r border-white/5 min-w-[130px]">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#6b7762] px-8 py-2 rounded-t-xl text-white text-xs font-black uppercase tracking-[0.2em] relative">
                                                    Time <Clock size={14} className="absolute -top-1 -right-1 opacity-50" />
                                                </div>
                                                <div className="w-full h-1 bg-[#6b7762] opacity-50"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 min-w-[300px]">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#7a856a] px-8 py-2 rounded-t-xl text-white text-xs font-black uppercase tracking-[0.2em] relative">
                                                    Tasks <ClipboardList size={14} className="absolute -top-1 -right-1 opacity-50" />
                                                </div>
                                                <div className="w-full h-1 bg-[#7a856a] opacity-50"></div>
                                            </div>
                                        </th>
                                    </tr>
                                </thead>
                                <tbody className="bg-slate-900/40">
                                    {appointments.map((apt) => (
                                        <tr key={apt.id} className="group border-b border-white/5 hover:bg-white/[0.02] transition-colors relative">
