                                            <td className="px-6 py-10 border-r border-white/5 text-sm font-bold text-white max-w-xs">
                                                <h4 className="text-white mb-2">{apt.title}</h4>
                                                <p className="text-[10px] text-slate-500 font-medium uppercase italic">{apt.notes || 'No notes provided'}</p>
                                            </td>
                                            {/* الموقع */}
                                            <td className="px-6 py-10 border-r border-white/5 text-sm font-bold text-slate-400">
                                                {apt.location}
                                            </td>
                                            {/* الوقت */}
                                            <td className="px-6 py-10 border-r border-white/5 font-mono text-sm font-black text-slate-300 uppercase">
                                                {apt.time}
                                            </td>
                                            {/* المهام بأسلوب الصورة */}
                                            <td className="px-10 py-10 text-left">
                                                <ul className="space-y-2">
                                                    {(apt.tasks || []).map((task, i) => (
                                                        <li key={i} className="flex items-start gap-3 text-xs text-slate-400">
                                                            <ChevronRight size={14} className="mt-0.5 text-[#7a856a]" />
                                                            <span className="font-bold">{task}</span>
                                                        </li>
                                                    ))}
                                                    {(!apt.tasks || apt.tasks.length === 0) && (
                                                        <li className="text-slate-600 text-[10px] italic">No specific tasks listed</li>
                                                    )}
                                                </ul>

                                                {/* أزرار الإجراءات العائمة عند التحويم */}
                                                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => openEditAppointment(apt)} className="p-2 bg-blue-600/20 text-blue-400 rounded-lg hover:bg-blue-600 hover:text-white transition-all"><Edit size={14}/></button>
                                                    <button onClick={() => handleDeleteAppointment(apt.id)} className="p-2 bg-rose-600/20 text-rose-400 rounded-lg hover:bg-rose-600 hover:text-white transition-all"><Trash2 size={14}/></button>
                                                </div>
