                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            )}

        </main>

        {/* المودالات (Modals) */}
        <Modal 
            isOpen={isModalOpen} 
            onClose={() => { setIsModalOpen(false); setSelectedItem(null); }} 
            title={
                modalType === 'appointment' ? (selectedItem ? (isRTL ? 'تعديل اجتماع' : 'Edit Meeting') : (isRTL ? 'جدولة اجتماع جديد' : 'New Meeting')) :
                (isRTL ? 'إدارة المستخدمين' : 'User Management')
            }
            isRTL={isRTL}
            contentClassName="bg-[#12141a] text-white border border-white/10"
        >
            <div className="space-y-6">
                {modalType === 'appointment' && (
                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Meeting Title</label>
                            <input type="text" value={aptForm.title} onChange={e => setAptForm({...aptForm, title: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-bold" placeholder="e.g. Decision making meeting" />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Date</label>
                                <input type="date" value={aptForm.date} onChange={e => setAptForm({...aptForm, date: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-mono" />
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Time</label>
                                <input type="text" value={aptForm.time} onChange={e => setAptForm({...aptForm, time: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-mono" placeholder="09:30 AM" />
                            </div>
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Location</label>
                            <input type="text" value={aptForm.location} onChange={e => setAptForm({...aptForm, location: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none focus:border-blue-500 font-bold" placeholder="Conference Room" />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Tasks / Action Items</label>
                            <div className="flex gap-2 mb-2">
                                <input type="text" value={currentTask} onChange={e => setCurrentTask(e.target.value)} onKeyPress={e => e.key === 'Enter' && addTask()} className="flex-1 bg-slate-900 border border-white/5 p-3 rounded-xl outline-none focus:border-emerald-500 text-xs font-bold" placeholder="Add task here..." />
                                <button onClick={addTask} className="bg-emerald-600 p-3 rounded-xl hover:bg-emerald-700 transition-all"><Plus size={18}/></button>
                            </div>
                            <div className="space-y-2 max-h-32 overflow-y-auto pr-2 scrollbar-thin">
                                {aptForm.tasks?.map((task, i) => (
                                    <div key={i} className="flex justify-between items-center bg-white/5 p-2 rounded-lg text-[10px] font-bold">
                                        <span className="text-slate-300">{task}</span>
                                        <button onClick={() => removeTask(i)} className="text-rose-500 hover:text-rose-400"><Trash2 size={12}/></button>
                                    </div>
                                ))}
                            </div>
                        </div>
                        <button onClick={handleSaveAppointment} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                            {selectedItem ? 'Update Meeting' : 'Save Meeting'}
                        </button>
                    </div>
                )}

                {modalType === 'user' && (
                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">User Full Name</label>
                            <input type="text" value={userForm.name} onChange={e => setUserForm({...userForm, name: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none font-bold" />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Role (AR)</label>
                                <input type="text" value={userForm.roleAr} onChange={e => setUserForm({...userForm, roleAr: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none font-bold" />
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Entity Access</label>
                                <select value={userForm.allowedEntity} onChange={e => setUserForm({...userForm, allowedEntity: e.target.value as EntityType})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none font-bold">
                                    <option value="FACTORY">FACTORY</option>
                                    <option value="MAKH_GOLD">GOLD</option>
                                    <option value="MOSQUE">MOSQUE</option>
                                    <option value="GENERAL_ADMIN">ADMIN</option>
                                </select>
                            </div>
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">Initial Password</label>
                            <input type="text" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} className="w-full bg-slate-900 border border-white/5 p-3 rounded-xl outline-none font-mono" placeholder="123" />
                        </div>
                        <button onClick={handleAddUser} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black transition-all">
                            Save User Access
                        </button>
                    </div>
                )}
            </div>
        </Modal>

        <footer className="max-w-7xl mx-auto mt-20 mb-10 text-center opacity-20 text-[9px] font-black uppercase tracking-[0.5em]">
            Niger Projects Executive Dashboard v9.2
        </footer>
    </div>
  );
};

export default GeneralAdmin;

export enum Language {
  AR = 'ar',
  FR = 'fr'
}

export type EntityType = 'FACTORY' | 'MOSQUE' | 'ALTAQADDUM' | 'FARM' | 'BANK' | 'MAKH_GOLD' | 'ALNUKHBA' | 'GENERAL_ADMIN' | 'MASTER';

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface Notification {
  message: string;
  type: 'success' | 'error';
}

export interface RawMaterial {
  id: string;
  nameAr: string;
  nameFr: string;
  quantity: number;
  maxQuantity: number;
  unit: string;
  minLevel: number;
  supplier: string;
  price: number;
  lastUpdated: string;
}

export interface Product {
  id: string;
  nameAr: string;
  nameFr: string;
  quantity: number;
  maxQuantity: number;
  unit: string;
  price: number;
  minLevel: number;
  lastUpdated: string;
}

export interface Order {
  id: string;
  customerName: string;
  customerId: string;
  date: string;
  status: OrderStatus;
  totalAmount: number;
  items: any[];
  expectedDeliveryDate?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  email: string;
  address: string;
}

export interface Staff {
  id: string;
  name: string;
  roleAr: string;
  roleFr: string;
