}

export interface CapitalTransaction {
  id: string;
  date: string;
  description: string;
  notes: string;
  type: 'income' | 'expense';
  amount: number;
  balanceAfter: number;
}

export interface TranslationDictionary {
  [key: string]: {
    ar: string;
    fr: string;
  };
}

export interface EntityInfo {
  id: EntityType;
  nameAr: string;
  nameEn: string;
  icon: string;
  color: string;
  descriptionAr: string;
}

import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Building2,
  Users,
  Calendar,
  Plus,
  MapPin,
  Clock,
  Trash2,
  MoreVertical,
  ClipboardList,
  Edit,
  ChevronRight,
  CheckCircle2,
  History,
  FileText
} from 'lucide-react';
import { Language, Expense, GoldTransaction, Order, Staff, Appointment, EntityType } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface GeneralAdminProps {
  lang: Language;
  onLogout: () => void;
  expenses: Expense[];
  goldTransactions: GoldTransaction[];
  orders: Order[];
  staff: Staff[];
  setStaff: (s: Staff[]) => void;
  appointments: Appointment[];
  setAppointments: (a: Appointment[]) => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  currentUser: Staff | null;
}

const GeneralAdmin: React.FC<GeneralAdminProps> = ({ 
    lang, onLogout, expenses, goldTransactions, orders, 
    staff, setStaff, appointments, setAppointments, showNotification, currentUser 
}) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // إدارة حالة التبويبات والمودالات
  // =========================================
  const [activeTab, setActiveTab] = useState<'overview' | 'users' | 'appointments'>('appointments');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'user' | 'appointment' | 'finishAppointment'>('appointment');

  // العنصر المختار للعمليات
  const [selectedItem, setSelectedItem] = useState<any | null>(null);

  // نماذج الإدخال
  const [userForm, setUserForm] = useState<Partial<Staff>>({ name: '', roleAr: '', salary: 0, allowedEntity: 'FACTORY', password: '' });
  const [aptForm, setAptForm] = useState<Partial<Appointment>>({ 
    title: '', date: '', time: '', location: '', notes: '', tasks: [], isFinished: false, summary: '' 
  });
  const [currentTask, setCurrentTask] = useState('');
  const [meetingSummary, setMeetingSummary] = useState('');

  // تنسيق الأرقام بالإنجليزية دائماً
  const formatNum = (val: number) => val.toLocaleString('en-US');

  // دالة لجلب اسم اليوم باللغة العربية
  const getDayName = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return date.toLocaleDateString(isRTL ? 'ar-SA' : 'en-US', { weekday: 'long' });
  };

  // =========================================
  // فرز المواعيد: المواعيد القادمة (الأقرب أولاً)
  // =========================================
  const upcomingAppointments = useMemo(() => {
    return appointments
      .filter(a => !a.isFinished)
      .sort((a, b) => new Date(`${a.date} ${a.time}`).getTime() - new Date(`${b.date} ${b.time}`).getTime());
  }, [appointments]);

  // الاجتماعات المنتهية
  const finishedAppointments = useMemo(() => {
    return appointments
      .filter(a => a.isFinished)
      .sort((a, b) => new Date(`${b.date} ${b.time}`).getTime() - new Date(`${a.date} ${a.time}`).getTime());
  }, [appointments]);

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // حفظ الموعد (إضافة أو تعديل)
  const handleSaveAppointment = () => {
    if(!aptForm.title || !aptForm.date) return;

    if (selectedItem) {
        // تحديث موعد موجود
        setAppointments(appointments.map(a => a.id === selectedItem.id ? { ...a, ...aptForm } as Appointment : a));
        showNotification(isRTL ? 'تم تحديث الموعد' : 'Meeting updated', 'success');
    } else {
        // إضافة موعد جديد
        const newApt: Appointment = {
            id: Math.random().toString(36).substr(2, 9),
            title: aptForm.title!,
            date: aptForm.date!,
            time: aptForm.time || '09:00 AM',
            location: aptForm.location || 'Conference Room',
            notes: aptForm.notes || '',
            tasks: aptForm.tasks || [],
            isFinished: false
        };
        setAppointments([...appointments, newApt]);
        showNotification(isRTL ? 'تمت إضافة الموعد بنجاح' : 'Meeting added successfully', 'success');
    }
    setIsModalOpen(false);
    setSelectedItem(null);
    setAptForm({ title: '', date: '', time: '', location: '', notes: '', tasks: [] });
  };

  // حذف موعد
  const handleDeleteAppointment = (id: string) => {
      if(confirm(isRTL ? 'حذف هذا الموعد نهائياً؟' : 'Delete this meeting permanently?')) {
          setAppointments(appointments.filter(a => a.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  // إنهاء موعد وإضافة ملخص
  const handleFinishMeeting = () => {
      if (!selectedItem) return;
      setAppointments(appointments.map(a => 
        a.id === selectedItem.id ? { ...a, isFinished: true, summary: meetingSummary } : a
      ));
      setIsModalOpen(false);
      setMeetingSummary('');
      setSelectedItem(null);
      showNotification(isRTL ? 'تم نقل الاجتماع للسجلات' : 'Meeting moved to history', 'success');
  };

  // إدارة المهام داخل المودال
  const addTask = () => {
      if(!currentTask.trim()) return;
      setAptForm({ ...aptForm, tasks: [...(aptForm.tasks || []), currentTask] });
      setCurrentTask('');
  };

  return (
    <div className={`min-h-screen bg-[#050811] text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'}>
        {/* الشريط العلوي */}
        <header className="bg-slate-900 border-b border-white/5 p-6 sticky top-0 z-50">
            <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white text-slate-950 rounded-xl flex items-center justify-center shadow-lg">
                        <Building2 size={28} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black tracking-tight text-white">{isRTL ? 'الإدارة العامة للمجموعة' : 'General Administration'}</h1>
                        <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{isRTL ? 'لوحة تحكم المالك والعمليات' : 'Owner & Operations Control'}</p>
                    </div>
                </div>

                <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg">
                    <button onClick={() => setActiveTab('overview')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('dashboard')}
                    </button>
                    <button onClick={() => setActiveTab('users')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('usersManagement')}
                    </button>
                    <button onClick={() => setActiveTab('appointments')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'appointments' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        {t('appointments')}
                    </button>
                </nav>

                <button onClick={onLogout} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold transition-colors">
                    {t('logout')}
                </button>
            </div>
        </header>

        <main className="max-w-7xl mx-auto p-8 space-y-16 animate-fade-in-up">

            {/* قسم المواعيد القادمة */}
            {activeTab === 'appointments' && (
                <div className="space-y-10">
                    <div className="flex justify-between items-center">
                        <div>
                            <h2 className="text-3xl font-black text-white tracking-tight">{isRTL ? 'جدول اجتماعات أعمال الموارد البشرية' : 'HR Business Meeting Schedule'}</h2>
                            <p className="text-slate-500 text-xs font-bold mt-2 uppercase tracking-widest opacity-70">Strategic Planning & Operations Calendar</p>
                        </div>
                        <button 
                            onClick={() => { setSelectedItem(null); setAptForm({title:'', date:'', time:'', location:'', notes:'', tasks:[]}); setModalType('appointment'); setIsModalOpen(true); }}
                            className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:bg-blue-500 transition-all active:scale-95 flex items-center gap-3"
                        >
                            <Plus size={18} /> {isRTL ? 'جدولة اجتماع جديد' : 'Schedule Meeting'}
                        </button>
                    </div>

                    {/* جدول المواعيد القادمة (نفس تصميم الصورة) */}
                    <div className="bg-[#0a0f1d] rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl">
                        <div className="overflow-x-auto">
                            <table className="w-full text-center border-collapse">
                                <thead>
                                    <tr className="bg-[#1a1e2b]">
                                        {/* رؤوس الأعمدة بالألوان المطلوبة في الصورة */}
                                        <th className="px-6 py-8 border-r border-white/5">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#8b4146] px-8 py-2 rounded-lg text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                                                    DATE <Calendar size={12} />
                                                </div>
                                                <div className="w-full h-0.5 bg-[#8b4146]/30"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 border-r border-white/5">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#56634c] px-8 py-2 rounded-lg text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                                                    MEETING <Users size={12} />
                                                </div>
                                                <div className="w-full h-0.5 bg-[#56634c]/30"></div>
                                            </div>
                                        </th>
                                        <th className="px-6 py-8 border-r border-white/5">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="bg-[#4a5463] px-8 py-2 rounded-lg text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                                                    LOCATION <MapPin size={12} />
                                                </div>
                                                <div className="w-full h-0.5 bg-[#4a5463]/30"></div>
