                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            )}
        </main>

        {/* =========================================
            المودالات (Modals)
        ========================================= */}
        <Modal 
            isOpen={isModalOpen} 
            onClose={() => { setIsModalOpen(false); setSelectedItem(null); }} 
            title={
                modalType === 'appointment' ? (selectedItem ? (isRTL ? 'تعديل اجتماع' : 'Edit Meeting') : (isRTL ? 'جدولة اجتماع جديد' : 'New Meeting')) :
                modalType === 'finishAppointment' ? (isRTL ? 'إنهاء الاجتماع وإضافة ملخص' : 'Finish & Summarize Meeting') :
                (isRTL ? 'إدارة المستخدمين' : 'User Management')
            }
            isRTL={isRTL}
            contentClassName="bg-[#12141a] text-white border border-white/10"
        >
            <div className="space-y-6">
                {/* مودال جدولة الموعد (نفس التصميم في الصورة) */}
                {modalType === 'appointment' && (
                    <div className="space-y-5">
                        <div className="space-y-1">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">{isRTL ? 'عنوان الاجتماع' : 'MEETING TITLE'}</label>
                            <input type="text" value={aptForm.title} onChange={e => setAptForm({...aptForm, title: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none focus:border-blue-500 font-bold text-center" placeholder="e.g. Decision making meeting" />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-1">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">{isRTL ? 'التاريخ' : 'DATE'}</label>
                                <input type="date" value={aptForm.date} onChange={e => setAptForm({...aptForm, date: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none focus:border-blue-500 font-mono text-center" />
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">{isRTL ? 'الوقت' : 'TIME'}</label>
                                <input type="text" value={aptForm.time} onChange={e => setAptForm({...aptForm, time: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none focus:border-blue-500 font-mono text-center" placeholder="09:30 AM" />
                            </div>
                        </div>

                        <div className="space-y-1">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">{isRTL ? 'الموقع' : 'LOCATION'}</label>
                            <input type="text" value={aptForm.location} onChange={e => setAptForm({...aptForm, location: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none focus:border-blue-500 font-bold text-center" placeholder="Conference Room" />
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">{isRTL ? 'المهام / عناصر العمل' : 'TASKS / ACTION ITEMS'}</label>
                            <div className="flex gap-2 mb-2">
                                <button onClick={addTask} className="bg-emerald-600 p-4 rounded-xl hover:bg-emerald-700 transition-all flex items-center justify-center text-white"><Plus size={20}/></button>
                                <input type="text" value={currentTask} onChange={e => setCurrentTask(e.target.value)} onKeyPress={e => e.key === 'Enter' && addTask()} className="flex-1 bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none focus:border-emerald-500 text-xs font-bold text-center" placeholder="...Add task here" />
                            </div>

                            {/* قائمة المهام المضافة */}
                            <div className="space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                                {aptForm.tasks?.map((task, i) => (
                                    <div key={i} className="flex justify-between items-center bg-white/5 p-3 rounded-xl border border-white/5 group">
                                        <div className="flex items-center gap-3">
                                            <ChevronRight size={14} className="text-emerald-500" />
                                            <span className="text-xs font-bold text-slate-300">{task}</span>
                                        </div>
                                        <button onClick={() => setAptForm({...aptForm, tasks: aptForm.tasks?.filter((_, idx) => idx !== i)})} className="text-rose-500 hover:scale-110 transition-transform"><Trash2 size={14}/></button>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <button onClick={handleSaveAppointment} className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-2xl transition-all active:scale-95 text-xs">
                            {selectedItem ? 'UPDATE MEETING' : 'SAVE MEETING'}
                        </button>
                    </div>
                )}

                {/* مودال إنهاء الاجتماع وإضافة ملخص */}
                {modalType === 'finishAppointment' && (
                    <div className="space-y-5 text-center">
                        <div className="p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 mb-4">
                            <h4 className="text-emerald-400 font-black mb-1">{selectedItem?.title}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase">{selectedItem?.date}</p>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block text-right">{isRTL ? 'ملخص مخرجات الاجتماع' : 'MEETING SUMMARY'}</label>
                            <textarea 
                                value={meetingSummary} 
                                onChange={e => setMeetingSummary(e.target.value)} 
                                className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-2xl outline-none focus:border-emerald-500 font-bold text-sm h-40 resize-none text-right"
                                placeholder={isRTL ? "اكتب هنا أهم ما تم الاتفاق عليه في الاجتماع..." : "Summarize key decisions and results..."}
                            />
                        </div>
                        <button onClick={handleFinishMeeting} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                            {isRTL ? 'أرشفة الاجتماع كمنتهٍ' : 'MARK AS COMPLETED'}
                        </button>
                    </div>
                )}
            </div>
        </Modal>

        <footer className="max-w-7xl mx-auto mt-20 mb-10 text-center opacity-10 text-[8px] font-black uppercase tracking-[0.5em]">
            Niger Projects Executive Dashboard v10.0 • AI Operating System
        </footer>
    </div>
  );
};

