                        </div>

                        <button onClick={handleSaveAppointment} className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-2xl transition-all active:scale-95 text-xs">
                            {selectedItem ? 'تحديث بيانات الاجتماع' : 'تأكيد وحفظ الموعد'}
                        </button>
                    </div>
                )}

                {modalType === 'finishAppointment' && (
                    <div className="space-y-5 text-center">
                        <div className="p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 mb-4">
                            <h4 className="text-emerald-400 font-black mb-1">{selectedItem?.title}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase">{selectedItem?.date}</p>
