                        <button onClick={handleFinishMeeting} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                            أرشفة الاجتماع كمنتهٍ
