                        </div>

                        <button onClick={handleSaveAppointment} className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-2xl transition-all active:scale-95 text-xs">
                            {selectedItem ? 'تحديث بيانات الاجتماع' : 'تأكيد وحفظ الموعد'}
                        </button>
                    </div>
                )}

                {modalType === 'finishAppointment' && (
                    <div className="space-y-5 text-center">
                        <div className="p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 mb-4">
                            <h4 className="text-emerald-400 font-black mb-1">{selectedItem?.title}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase">{selectedItem?.date}</p>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block text-right">ملخص مخرجات الاجتماع والقرارات</label>
                            <textarea 
                                value={meetingSummary} 
                                onChange={e => setMeetingSummary(e.target.value)} 
                                className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-2xl outline-none focus:border-emerald-500 font-bold text-sm h-40 resize-none text-right"
                            />
                        </div>
                        <button onClick={handleFinishMeeting} className="w-full py-5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                            أرشفة الاجتماع كمنتهٍ
                        </button>
                    </div>
                )}

                {modalType === 'user' && (
                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">اسم الموظف</label>
                            <input type="text" value={userForm.name} onChange={e => setUserForm({...userForm, name: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none font-bold text-right" />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">الدور الوظيفي</label>
                                <input type="text" value={userForm.roleAr} onChange={e => setUserForm({...userForm, roleAr: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none font-bold text-right" />
                            </div>
                            <div>
                                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">الصلاحية</label>
                                <select value={userForm.allowedEntity} onChange={e => setUserForm({...userForm, allowedEntity: e.target.value as EntityType})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none font-bold text-right cursor-pointer">
                                    <option value="FACTORY">FACTORY</option>
                                    <option value="MAKH_GOLD">GOLD</option>
                                    <option value="MOSQUE">MOSQUE</option>
                                    <option value="GENERAL_ADMIN">ADMIN</option>
                                </select>
                            </div>
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">كلمة المرور</label>
                            <input type="text" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} className="w-full bg-[#1a1e2b] border border-white/5 p-4 rounded-xl outline-none font-mono text-center" placeholder="123" />
                        </div>
                        <button onClick={handleAddUser} className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black transition-all">
                            حفظ المستخدم
                        </button>
                    </div>
                )}
            </div>
        </Modal>

        <footer className="max-w-7xl mx-auto mt-20 mb-10 text-center opacity-10 text-[8px] font-black uppercase tracking-[0.5em]">
            Niger Projects Executive Dashboard v12.0
        </footer>
    </div>
  );
};

export default GeneralAdmin;

import React, { useState, useMemo } from 'react';
import { 
  Building2,
  Users,
  Calendar,
  Plus,
  MapPin,
  Clock,
  Trash2,
  ClipboardList,
  Edit,
  ChevronRight,
  CheckCircle2,
  History,
  LayoutDashboard,
  Wallet,
  TrendingUp,
  MoreVertical,
  Factory,
  Eye,
  EyeOff,
  Lock,
  MoreHorizontal
} from 'lucide-react';
import { Language, Expense, GoldTransaction, Order, Staff, Appointment, EntityType } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface GeneralAdminProps {
  lang: Language;
  onLogout: () => void;
  expenses: Expense[];
  goldTransactions: GoldTransaction[];
  orders: Order[];
  staff: Staff[];
  setStaff: (s: Staff[]) => void;
  appointments: Appointment[];
  setAppointments: (a: Appointment[]) => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  currentUser: Staff | null;
}

const GeneralAdmin: React.FC<GeneralAdminProps> = ({ 
    lang, onLogout, expenses, goldTransactions, orders, 
    staff, setStaff, appointments, setAppointments, showNotification, currentUser 
}) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة التحكم في التبويبات والمودالات
  // =========================================
  const [activeTab, setActiveTab] = useState<'overview' | 'users' | 'appointments'>('appointments');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'user' | 'appointment' | 'finishAppointment'>('appointment');

  // الموعد أو العنصر المختار للعمليات
  const [selectedItem, setSelectedItem] = useState<any | null>(null);

  // حالات خاصة بإدارة المستخدمين
  const [activeUserMenu, setActiveUserMenu] = useState<string | null>(null);
  const [showPasswordId, setShowPasswordId] = useState<string | null>(null);

  // نماذج الإدخال
  const [userForm, setUserForm] = useState<Partial<Staff>>({ id: '', name: '', roleAr: '', salary: 0, allowedEntity: 'FACTORY', password: '' });
  const [aptForm, setAptForm] = useState<Partial<Appointment>>({ 
    title: '', date: '', time: '09:00 AM', location: '', notes: '', tasks: [], isFinished: false, summary: '' 
  });
  const [currentTask, setCurrentTask] = useState('');
  const [meetingSummary, setMeetingSummary] = useState('');

  // =========================================
  // العمليات الحسابية للوحة القيادة
  // =========================================
  const factoryIncome = expenses.filter(e => e.type === 'income').reduce((sum, e) => sum + e.amount, 0);
  const factoryExpenses = expenses.filter(e => e.type === 'expense').reduce((sum, e) => sum + e.amount, 0);
  const goldPurchases = goldTransactions.filter(t => t.type === 'purchase').reduce((sum, t) => sum + t.amountRiyal, 0);
  const totalNetWorth = (factoryIncome - factoryExpenses) + (goldPurchases * 1.15); // قيمة تقديرية

  const formatNum = (val: number) => val.toLocaleString('en-US');

  // =========================================
  // منطق المواعيد
  // =========================================
  const timeOptions = useMemo(() => {
    const times = [];
    for (let h = 0; h < 24; h++) {
      for (let m = 0; m < 60; m += 30) {
        const hour = h % 12 || 12;
        const ampm = h < 12 ? 'AM' : 'PM';
        const minute = m === 0 ? '00' : '30';
        const timeStr = `${hour < 10 ? '0' + hour : hour}:${minute} ${ampm}`;
        times.push(timeStr);
      }
    }
    return times;
  }, []);

  const getDayName = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return date.toLocaleDateString('ar-SA', { weekday: 'long' });
  };

  const upcomingAppointments = useMemo(() => {
    return appointments
      .filter(a => !a.isFinished)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [appointments]);

  const finishedAppointments = useMemo(() => {
    return appointments
      .filter(a => a.isFinished)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [appointments]);

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // حفظ المستخدم (إضافة أو تعديل)
  const handleSaveUser = () => {
    if(!userForm.name || !userForm.password) {
        showNotification('يرجى ملء كافة البيانات المطلوبة', 'error');
        return;
    }

    if (userForm.id) {
        // تعديل مستخدم موجود
        const updatedStaff = staff.map(s => s.id === userForm.id ? { ...s, ...userForm } as Staff : s);
        setStaff(updatedStaff);
        showNotification('تم تحديث بيانات المستخدم وصلاحياته بنجاح', 'success');
    } else {
        // إضافة مستخدم جديد
        const newUser: Staff = {
            id: Math.random().toString(36).substr(2, 9),
            name: userForm.name!,
            roleAr: userForm.roleAr || 'موظف',
            roleFr: 'Employee',
            salary: Number(userForm.salary) || 0,
            lastPaymentDate: '-',
            advanceTaken: 0,
            allowedEntity: userForm.allowedEntity,
            password: userForm.password,
            loginCount: 0,
            loginHistory: []
        };
        setStaff([...staff, newUser]);
        showNotification('تم إضافة المستخدم الجديد بنجاح', 'success');
    }
    setIsModalOpen(false);
    setUserForm({});
  };

  const handleEditUserClick = (user: Staff) => {
      setUserForm({ ...user });
      setModalType('user');
      setIsModalOpen(true);
      setActiveUserMenu(null);
  };

  const handleSaveAppointment = () => {
    if(!aptForm.title || !aptForm.date) return;

    if (selectedItem) {
        setAppointments(appointments.map(a => a.id === selectedItem.id ? { ...a, ...aptForm } as Appointment : a));
        showNotification('تم تحديث الاجتماع بنجاح', 'success');
    } else {
        const newApt: Appointment = {
            id: Math.random().toString(36).substr(2, 9),
            title: aptForm.title!,
            date: aptForm.date!,
            time: aptForm.time || '09:00 AM',
            location: aptForm.location || '',
            notes: aptForm.notes || '',
            tasks: aptForm.tasks || [],
            isFinished: false
        };
        setAppointments([...appointments, newApt]);
        showNotification('تمت جدولة الاجتماع بنجاح', 'success');
    }
    setIsModalOpen(false);
    setSelectedItem(null);
  };

  const handleDeleteAppointment = (id: string) => {
      if(confirm('هل أنت متأكد من حذف هذا الاجتماع نهائياً؟')) {
          setAppointments(appointments.filter(a => a.id !== id));
          showNotification('تم الحذف بنجاح', 'success');
      }
  };

  const handleFinishMeeting = () => {
      if (!selectedItem) return;
      setAppointments(appointments.map(a => 
        a.id === selectedItem.id ? { ...a, isFinished: true, summary: meetingSummary } : a
      ));
      setIsModalOpen(false);
      setMeetingSummary('');
      setSelectedItem(null);
      showNotification('تم إنهاء الاجتماع وأرشفته', 'success');
  };

  const addTask = () => {
      if(!currentTask.trim()) return;
      setAptForm({ ...aptForm, tasks: [...(aptForm.tasks || []), currentTask] });
      setCurrentTask('');
  };

  return (
    <div className={`min-h-screen bg-[#050811] text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'} onClick={() => setActiveUserMenu(null)}>
        {/* الشريط العلوي */}
        <header className="bg-slate-900 border-b border-white/5 p-6 sticky top-0 z-50">
            <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white text-slate-950 rounded-xl flex items-center justify-center shadow-lg">
                        <Building2 size={28} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black tracking-tight text-white">الإدارة العامة</h1>
                        <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">المجموعة البرمجية الموحدة</p>
                    </div>
                </div>

                <nav className="flex items-center gap-2 bg-slate-800 p-1 rounded-lg">
                    <button onClick={() => setActiveTab('overview')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        لوحة القيادة
                    </button>
                    <button onClick={() => setActiveTab('users')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'users' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        إدارة المستخدمين
                    </button>
                    <button onClick={() => setActiveTab('appointments')} className={`px-4 py-2 rounded-md text-xs font-bold transition-all ${activeTab === 'appointments' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                        المواعيد
                    </button>
                </nav>

                <button onClick={onLogout} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold transition-colors">
                    تسجيل الخروج
                </button>
            </div>
        </header>

        <main className="max-w-7xl mx-auto p-8 space-y-16 animate-fade-in-up">

            {/* ==========================
               1. لوحة القيادة (Overview)
               ========================== */}
            {activeTab === 'overview' && (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-2 bg-gradient-to-br from-slate-900 to-slate-800 p-10 rounded-[3rem] border border-white/5 relative overflow-hidden shadow-2xl">
                        <div className="absolute top-0 right-0 w-80 h-80 bg-blue-600/10 rounded-full blur-[100px] -mr-20 -mt-20"></div>
                        <h2 className="text-slate-500 font-black uppercase tracking-widest text-xs mb-3">صافي الثروة المجمعة للمجموعة</h2>
                        <div className="flex items-baseline gap-4">
                            <span className="text-6xl font-black text-white tracking-tighter">{formatNum(totalNetWorth)}</span>
                            <span className="text-xl font-bold text-slate-500 font-mono">SAR</span>
                        </div>
                    </div>
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-white/5 flex flex-col justify-center gap-4">
                        <div className="flex justify-between items-center p-5 bg-white/5 rounded-2xl">
                            <div className="flex items-center gap-3">
                                <Factory size={18} className="text-slate-500"/>
                                <span className="text-xs font-black text-slate-400">المصنع</span>
                            </div>
                            <span className="font-mono font-black text-blue-400">+{formatNum(factoryIncome-factoryExpenses)}</span>
                        </div>
                        <div className="flex justify-between items-center p-5 bg-white/5 rounded-2xl">
                            <div className="flex items-center gap-3">
                                <Wallet size={18} className="text-slate-500"/>
                                <span className="text-xs font-black text-slate-400">الذهب</span>
                            </div>
                            <span className="font-mono font-black text-amber-400">+{formatNum(goldPurchases * 0.05)}</span>
                        </div>
                    </div>
                </div>
            )}

            {/* ==========================
               2. إدارة المستخدمين (Users)
               ========================== */}
            {activeTab === 'users' && (
                <div className="space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-2xl font-black uppercase tracking-tight text-white">إدارة المستخدمين والصلاحيات</h2>
                        <button onClick={() => { setModalType('user'); setUserForm({}); setIsModalOpen(true); }} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2.5 rounded-xl font-black text-xs uppercase tracking-widest flex items-center gap-2 transition-all">
                            <Plus size={16} /> إضافة موظف
                        </button>
                    </div>
                    <div className="bg-[#0a0f1d] rounded-[2.5rem] border border-white/5 overflow-hidden min-h-[400px]">
                        <table className="w-full text-right text-sm">
                            <thead className="bg-[#1a1e2b] text-xs font-black uppercase text-slate-500 tracking-widest">
                                <tr>
                                    <th className="px-8 py-5">الموظف</th>
                                    <th className="px-8 py-5">الصلاحية (الشركة)</th>
                                    <th className="px-8 py-5">الدور الوظيفي</th>
                                    <th className="px-8 py-5 text-center">الإجراءات</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {staff.map(s => (
                                    <tr key={s.id} className="hover:bg-white/5 transition-colors relative">
                                        <td className="px-8 py-6 font-black text-white">{s.name}</td>
                                        <td className="px-8 py-6">
                                            <span className={`px-3 py-1 rounded-lg text-[10px] font-mono font-bold border border-white/10 ${
                                                s.allowedEntity === 'MASTER' ? 'bg-rose-500/10 text-rose-400' :
                                                s.allowedEntity === 'GENERAL_ADMIN' ? 'bg-purple-500/10 text-purple-400' :
                                                'bg-blue-500/10 text-blue-400'
                                            }`}>
                                                {s.allowedEntity || 'FACTORY'}
                                            </span>
                                        </td>
                                        <td className="px-8 py-6 text-slate-400">{isRTL ? s.roleAr : s.roleFr}</td>
                                        <td className="px-8 py-6 text-center relative">
