    { id: 'h1', date: '2025-05-01', from: 'تبرعات عامة', to: 'عيسى صلاح', desc: 'راتب شهر مايو', sar: 2500, xof: 4300000 }
  ]);

  // Derived: Global Donors
  const globalDonors = useMemo(() => {
    const list: any[] = [];
    mosques.forEach(m => {
