import React, { useState, useMemo } from 'react';
import { 
  Sprout, 
  Tractor, 
  Leaf, 
  Plus, 
  Calendar, 
  DollarSign, 
  Weight, 
  FileText, 
  Trash2, 
  Edit3, 
  ArrowUpRight,
  Filter,
  Download
} from 'lucide-react';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

// تعريف نوع بيانات الإنتاج الزراعي ليكون جاهز لقواعد البيانات
interface FarmProduction {
  id: string;
  date: string;
  cropType: string;      // النوع (برسيم، قمح، إلخ)
  weight: number;        // الوزن
  unit: string;          // الوحدة (طن، كيلو)
  unitPrice: number;     // سعر الوحدة (595 مثلاً)
  totalPrice: number;    // الإجمالي (محسوب تلقائياً)
  notes: string;         // ملاحظات
  season: string;        // الموسم (2025)
}

interface FarmManagementProps {
  lang: Language;
  onLogout: () => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  farmData: FarmProduction[];
  setFarmData: (data: FarmProduction[]) => void;
}

const FarmManagement: React.FC<FarmManagementProps> = ({ lang, onLogout, showNotification, farmData, setFarmData }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة المودال والنموذج (State)
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState<Partial<FarmProduction>>({
    date: new Date().toISOString().split('T')[0],
    cropType: '',
    weight: 0,
    unit: 'Ton',
    unitPrice: 0,
    notes: '',
    season: '2025'
  });

  // حساب الإجماليات للإحصائيات
  const stats = useMemo(() => {
    const totalRevenue = farmData.reduce((sum, item) => sum + item.totalPrice, 0);
    const totalWeight = farmData.reduce((sum, item) => sum + item.weight, 0);
    const productionCount = farmData.length;
    return { totalRevenue, totalWeight, productionCount };
  }, [farmData]);

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  const handleSave = () => {
    // التحقق من البيانات
    if (!formData.cropType || !formData.weight || !formData.unitPrice) {
        showNotification(isRTL ? 'يرجى تعبئة الحقول الأساسية' : 'Please fill required fields', 'error');
        return;
    }

    const total = Number(formData.weight) * Number(formData.unitPrice);

    const newItem: FarmProduction = {
        id: Math.random().toString(36).substr(2, 9),
        date: formData.date || new Date().toISOString().split('T')[0],
        cropType: formData.cropType,
        weight: Number(formData.weight),
        unit: formData.unit || 'Ton',
        unitPrice: Number(formData.unitPrice),
        totalPrice: total,
        notes: formData.notes || '',
        season: '2025'
    };

    setFarmData([newItem, ...farmData]);
    setIsModalOpen(false);
    setFormData({ date: new Date().toISOString().split('T')[0], cropType: '', weight: 0, unit: 'Ton', unitPrice: 0, notes: '', season: '2025' });
    showNotification(t('success'), 'success');
  };

  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'حذف هذا السجل؟' : 'Delete record?')) {
          setFarmData(farmData.filter(d => d.id !== id));
      }
  };

  // بطاقة إحصائيات صغيرة
  const StatCard = ({ title, value, unit, icon: Icon, color }: any) => (
      <div className="bg-slate-900 border border-white/5 p-6 rounded-3xl flex items-center gap-5 shadow-lg relative overflow-hidden group">
          <div className={`absolute top-0 right-0 w-24 h-24 ${color} opacity-5 rounded-full -mr-10 -mt-10 transition-transform group-hover:scale-150`}></div>
          <div className={`p-4 rounded-2xl ${color} bg-opacity-10 text-white`}>
              <Icon size={24} />
          </div>
          <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{title}</p>
              <h3 className="text-2xl font-black text-white font-mono">{value} <span className="text-xs text-slate-500">{unit}</span></h3>
          </div>
      </div>
  );

  return (
    <div className={`min-h-screen bg-[#050811] text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'}>
      {/* الترويسة */}
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-6 sticky top-0 z-50">
         <div className="max-w-7xl mx-auto flex justify-between items-center">
             <div className="flex items-center gap-4">
                 <div className="w-12 h-12 bg-green-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-green-500/20">
                     <Tractor size={28} />
                 </div>
                 <div>
                     <h1 className="text-2xl font-black tracking-tight">{isRTL ? 'إدارة المزرعة والإنتاج' : 'Farm Management System'}</h1>
                     <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">{isRTL ? 'نظام تتبع المحاصيل 2025' : 'Crop Tracking 2025'}</p>
                 </div>
             </div>
             <button onClick={onLogout} className="px-5 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black text-slate-300 transition-all border border-white/5">
                 {t('backToHub')}
             </button>
         </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 lg:p-10 space-y-10 animate-fade-in-up">

          {/* قسم الإحصائيات العلوية */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title={isRTL ? 'إجمالي الإيرادات (2025)' : 'Total Revenue'} value={stats.totalRevenue.toLocaleString()} unit="SAR" icon={DollarSign} color="bg-emerald-500" />
              <StatCard title={isRTL ? 'إجمالي الوزن المنتج' : 'Total Weight'} value={stats.totalWeight.toLocaleString()} unit="Ton" icon={Weight} color="bg-green-500" />
              <StatCard title={isRTL ? 'عدد الحصاد' : 'Harvest Count'} value={stats.productionCount} unit="#" icon={Sprout} color="bg-amber-500" />
          </div>

          {/* قسم الجدول الرئيسي */}
          <div className="bg-slate-900 rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl">
              <div className="p-8 border-b border-white/5 bg-green-900/10 flex flex-wrap justify-between items-center gap-4">
                  <div>
                      <h3 className="text-xl font-black text-green-400 flex items-center gap-2">
                          <Leaf size={20} />
                          {isRTL ? 'سجل الإنتاج الجديد 2025' : 'Production Log 2025'}
                      </h3>
                      <p className="text-slate-500 text-xs mt-1 font-bold">Database Ready Table</p>
                  </div>
                  <div className="flex gap-3">
                      <button className="px-4 py-2 bg-slate-800 text-slate-400 rounded-xl hover:text-white font-bold text-xs flex items-center gap-2 transition-all">
                          <Download size={16} /> {isRTL ? 'تصدير Excel' : 'Export'}
                      </button>
                      <button 
                          onClick={() => setIsModalOpen(true)}
                          className="px-6 py-3 bg-green-600 hover:bg-green-700 text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-lg shadow-green-500/20 flex items-center gap-2 transition-all"
                      >
                          <Plus size={16} /> {isRTL ? 'إضافة إنتاج' : 'Add Production'}
                      </button>
                  </div>
              </div>

              <div className="overflow-x-auto">
                  <table className="w-full text-right text-sm">
                      <thead className="bg-black/20 text-slate-500 font-black uppercase tracking-widest text-[10px]">
                          <tr>
                              <th className="px-6 py-5 text-center">{t('date')}</th>
                              <th className="px-6 py-5">{isRTL ? 'النوع (المحصول)' : 'Crop Type'}</th>
                              <th className="px-6 py-5 text-center">{isRTL ? 'الوزن (طن)' : 'Weight'}</th>
                              <th className="px-6 py-5 text-center">{isRTL ? 'سعر الوحدة' : 'Unit Price'}</th>
                              <th className="px-6 py-5 text-center text-green-400">{isRTL ? 'الإجمالي (SAR)' : 'Total'}</th>
                              <th className="px-6 py-5 w-1/3">{isRTL ? 'ملاحظات' : 'Notes'}</th>
                              <th className="px-6 py-5 text-center"></th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-white/5 font-mono">
                          {farmData.map((item) => (
                              <tr key={item.id} className="hover:bg-white/5 transition-colors group">
                                  <td className="px-6 py-5 text-center text-slate-400">{item.date}</td>
                                  <td className="px-6 py-5 font-bold text-white font-sans text-base">{item.cropType}</td>
                                  <td className="px-6 py-5 text-center font-bold text-slate-300 bg-slate-800/50 rounded-lg mx-2">{item.weight.toLocaleString()}</td>
                                  <td className="px-6 py-5 text-center text-slate-400">{item.unitPrice.toLocaleString()}</td>
                                  <td className="px-6 py-5 text-center font-black text-green-400 text-lg">{item.totalPrice.toLocaleString()}</td>
                                  <td className="px-6 py-5 text-slate-500 font-sans text-xs italic">{item.notes}</td>
                                  <td className="px-6 py-5 text-center">
                                      <button onClick={() => handleDelete(item.id)} className="p-2 text-slate-600 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100">
                                          <Trash2 size={16} />
                                      </button>
                                  </td>
                              </tr>
                          ))}
                          {farmData.length === 0 && (
                              <tr>
                                  <td colSpan={7} className="py-20 text-center text-slate-600 font-bold uppercase tracking-widest text-xs">
                                      {isRTL ? 'لا توجد سجلات إنتاج لموسم 2025 حتى الآن' : 'No production records for 2025 yet'}
                                  </td>
                              </tr>
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      </main>

      {/* نافذة الإضافة (Modal) */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={isRTL ? 'إضافة إنتاج جديد 2025' : 'New Production 2025'} 
        isRTL={isRTL} 
        contentClassName="bg-slate-900 text-white border border-white/10"
      >
          <div className="space-y-5">

              <div className="bg-green-500/10 border border-green-500/20 p-4 rounded-xl flex items-start gap-3">
                  <FileText className="text-green-500 mt-1" size={18} />
                  <div>
                      <p className="text-xs font-bold text-green-200">{isRTL ? 'تنبيه النظام' : 'System Note'}</p>
                      <p className="text-[10px] text-green-400/70 mt-1">سيتم ربط هذه البيانات تلقائياً بقاعدة البيانات المركزية.</p>
                  </div>
              </div>

              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'تاريخ الإنتاج' : 'Date'}</label>
                  <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none font-mono text-center text-white focus:border-green-500 transition-colors" />
              </div>

              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'نوع المحصول' : 'Crop Type'}</label>
                  <input 
                    type="text" 
                    value={formData.cropType} 
                    onChange={e => setFormData({...formData, cropType: e.target.value})} 
                    className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none font-bold text-white focus:border-green-500 transition-colors placeholder:text-slate-600" 
                    placeholder={isRTL ? "مثال: برسيم، قمح، شعير..." : "e.g. Alfalfa, Wheat..."}
                  />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div>
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'الوزن (طن)' : 'Weight (Ton)'}</label>
                      <input 
                        type="number" 
                        value={formData.weight || ''} 
                        onChange={e => setFormData({...formData, weight: Number(e.target.value)})} 
                        className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none font-mono font-bold text-white text-center focus:border-green-500 transition-colors" 
                        placeholder="0"
                        dir="ltr"
                      />
                  </div>
                  <div>
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'سعر الوحدة (ريال)' : 'Price (SAR)'}</label>
                      <input 
                        type="number" 
                        value={formData.unitPrice || ''} 
                        onChange={e => setFormData({...formData, unitPrice: Number(e.target.value)})} 
                        className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none font-mono font-bold text-green-400 text-center focus:border-green-500 transition-colors" 
                        placeholder="595"
                        dir="ltr"
                      />
                  </div>
              </div>

              {/* حقل الإجمالي المحسوب */}
              <div className="bg-black/20 p-4 rounded-xl flex justify-between items-center border border-white/5">
                  <span className="text-xs font-bold text-slate-400">{isRTL ? 'الإجمالي المتوقع' : 'Total'}</span>
                  <span className="text-xl font-black text-white font-mono">
                      {((formData.weight || 0) * (formData.unitPrice || 0)).toLocaleString()} <span className="text-xs text-green-500">SAR</span>
                  </span>
              </div>

              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'ملاحظات' : 'Notes'}</label>
                  <textarea 
                    value={formData.notes} 
                    onChange={e => setFormData({...formData, notes: e.target.value})} 
                    className="w-full bg-slate-800 border border-white/5 p-3 rounded-xl outline-none font-bold text-white focus:border-green-500 transition-colors h-24 resize-none" 
                    placeholder={isRTL ? "ملاحظات إضافية..." : "Additional notes..."}
                  />
              </div>

              <button onClick={handleSave} className="w-full py-4 bg-green-600 hover:bg-green-700 text-white rounded-2xl font-black mt-2 transition-all shadow-lg active:scale-95">
                  {isRTL ? 'حفظ السجل' : 'Save Record'}
              </button>
          </div>
      </Modal>
    </div>
  );
};

export default FarmManagement;

import React, { useState, useEffect, useCallback } from 'react';
import { Globe, Menu, ArrowLeft } from 'lucide-react';
// استيراد المكونات الفرعية
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Orders from './components/Orders';
import Customers from './components/Customers';
import StaffView from './components/Staff';
import Production from './components/Production';
import Finance from './components/Finance';
import Login from './components/Login';
import Hub from './components/Hub';
import MakhGold from './components/MakhGold';
import GeneralAdmin from './components/GeneralAdmin';
import MosqueManagement from './components/MosqueManagement';
import FarmManagement from './components/FarmManagement'; // New Import
import Toast from './components/Toast';
// استيراد الأنواع والثوابت
import { Language, Customer, Product, RawMaterial, Order, Staff, Expense, Notification, EntityType, GoldTransaction, Appointment } from './types';
import { TRANSLATIONS, MOCK_CUSTOMERS, MOCK_PRODUCTS, MOCK_RAW_MATERIALS, MOCK_ORDERS, MOCK_STAFF, MOCK_EXPENSES, MOCK_GOLD_TRANSACTIONS, MOCK_APPOINTMENTS } from './constants';

const App: React.FC = () => {
  // =========================================
  // إدارة حالة التطبيق (State Management)
  // =========================================
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [currentEntity, setCurrentEntity] = useState<EntityType>('MASTER');
  const [currentView, setCurrentView] = useState('dashboard');
  const [lang, setLang] = useState<Language>(Language.AR);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);

  // =========================================
  // بيانات النظام (مع التخزين المحلي LocalStorage)
  // =========================================
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('np_customers') || JSON.stringify(MOCK_CUSTOMERS)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('np_products') || JSON.stringify(MOCK_PRODUCTS)));
  const [materials, setMaterials] = useState<RawMaterial[]>(() => JSON.parse(localStorage.getItem('np_materials') || JSON.stringify(MOCK_RAW_MATERIALS)));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('np_orders') || JSON.stringify(MOCK_ORDERS)));
  const [staff, setStaff] = useState<Staff[]>(() => JSON.parse(localStorage.getItem('np_staff') || JSON.stringify(MOCK_STAFF)));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('np_expenses') || JSON.stringify(MOCK_EXPENSES)));
  const [goldTransactions, setGoldTransactions] = useState<GoldTransaction[]>(() => JSON.parse(localStorage.getItem('np_gold_tx') || JSON.stringify(MOCK_GOLD_TRANSACTIONS)));
  const [appointments, setAppointments] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('np_appointments') || JSON.stringify(MOCK_APPOINTMENTS)));
  // Farm Data State
  const [farmData, setFarmData] = useState<any[]>(() => JSON.parse(localStorage.getItem('np_farm_data') || '[]'));

  const isRTL = lang === Language.AR;
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;

  // =========================================
  // حفظ البيانات تلقائياً عند التغيير
  // =========================================
  useEffect(() => {
    localStorage.setItem('np_customers', JSON.stringify(customers));
    localStorage.setItem('np_products', JSON.stringify(products));
    localStorage.setItem('np_materials', JSON.stringify(materials));
    localStorage.setItem('np_orders', JSON.stringify(orders));
    localStorage.setItem('np_staff', JSON.stringify(staff));
    localStorage.setItem('np_expenses', JSON.stringify(expenses));
    localStorage.setItem('np_gold_tx', JSON.stringify(goldTransactions));
    localStorage.setItem('np_appointments', JSON.stringify(appointments));
    localStorage.setItem('np_farm_data', JSON.stringify(farmData));
  }, [customers, products, materials, orders, staff, expenses, goldTransactions, appointments, farmData]);

  // دالة لعرض الإشعارات
  const showNotification = useCallback((message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
  }, []);

  // دالة تغيير اللغة
  const toggleLanguage = () => setLang(prev => prev === Language.AR ? Language.FR : Language.AR);

  // دالة تسجيل الدخول
  const handleLogin = (user: Staff) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    if (user.allowedEntity && user.allowedEntity !== 'MASTER' && user.allowedEntity !== 'GENERAL_ADMIN') {
        setCurrentEntity(user.allowedEntity);
    } else {
        setCurrentEntity('MASTER');
    }
  };

  // دالة تسجيل الخروج
  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentEntity('MASTER');
  };

  // =========================================
  // التوجيه (Routing) وعرض الصفحات
  // =========================================

  // 1. شاشة تسجيل الدخول
  if (!isLoggedIn) return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Login lang={lang} onLogin={handleLogin} toggleLanguage={toggleLanguage} staff={staff} showNotification={showNotification} />
    </>
  );

  // 2. المركز الرئيسي (HUB)
  if (currentEntity === 'MASTER') return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Hub lang={lang} onSelectEntity={(e) => { setCurrentEntity(e); setCurrentView('dashboard'); }} onLogout={handleLogout} />
    </>
  );

  // 3. إدارة الذهب (عرض خاص)
  if (currentEntity === 'MAKH_GOLD') return (
    <MakhGold 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      goldTransactions={goldTransactions} 
      setGoldTransactions={setGoldTransactions} 
      shareholders={[]} 
      setShareholders={() => {}} 
      showNotification={showNotification} 
    />
  );

  // 4. إدارة المساجد (عرض خاص)
  if (currentEntity === 'MOSQUE') return (
    <MosqueManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification} 
    />
  );

  // 5. إدارة المزرعة (عرض خاص - جديد)
  if (currentEntity === 'FARM') return (
    <FarmManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification}
      farmData={farmData}
      setFarmData={setFarmData}
    />
  );

  // 6. الإدارة العامة (عرض خاص)
  if (currentEntity === 'GENERAL_ADMIN') return (
    <GeneralAdmin 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER') setCurrentEntity('MASTER'); else handleLogout(); }} 
      expenses={expenses} 
      goldTransactions={goldTransactions} 
      orders={orders} 
      staff={staff} 
      setStaff={setStaff} 
      appointments={appointments} 
      setAppointments={setAppointments} 
      showNotification={showNotification} 
      currentUser={currentUser} 
    />
  );

  // 7. لوحة التحكم الافتراضية للمصنع
  const renderContent = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard lang={lang} setCurrentView={setCurrentView} orders={orders} staff={staff} expenses={expenses} materials={materials} products={products} />;
      case 'inventory': return <Inventory lang={lang} materials={materials} setMaterials={setMaterials} products={products} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} showNotification={showNotification} onRestockMaterial={() => {}} />;
      case 'orders': return <Orders lang={lang} customers={customers} orders={orders} setOrders={setOrders} products={products} setProducts={setProducts} setExpenses={setExpenses} showNotification={showNotification} />;
      case 'customers': return <Customers lang={lang} customers={customers} setCustomers={setCustomers} showNotification={showNotification} />;
      case 'staff': return <StaffView lang={lang} staff={staff} setStaff={setStaff} onPaySalary={() => {}} onRequestAdvance={() => {}} showNotification={showNotification} />;
      case 'production': return <Production lang={lang} products={products} setProducts={setProducts} materials={materials} setMaterials={setMaterials} showNotification={showNotification} />;
      case 'finance': return <Finance lang={lang} expenses={expenses} setExpenses={setExpenses} orders={orders} showNotification={showNotification} />;
      default: return <Dashboard lang={lang} setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div dir={isRTL ? 'rtl' : 'ltr'} className={`flex h-screen bg-slate-50 overflow-hidden ${isRTL ? 'font-cairo' : 'font-sans'}`}>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}

      {/* القائمة الجانبية */}
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} lang={lang} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        {/* الشريط العلوي */}
        <header className="h-20 bg-white border-b border-slate-100 flex items-center justify-between px-8 z-10 print:hidden">
          <div className="flex items-center gap-6">
             <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-slate-500"><Menu size={24} /></button>

             {/* إظهار زر العودة للمركز الرئيسي فقط للإدارة العليا */}
             {(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') && (
                <button onClick={() => setCurrentEntity('MASTER')} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all">
                  <ArrowLeft size={16} className={isRTL ? 'rotate-180' : ''} />
                  {t('backToHub')}
                </button>
             )}
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden sm:block text-sm text-slate-400 font-bold">
                {lang === Language.AR ? `أهلاً، ${currentUser?.name || 'مستخدم'}` : `Welcome, ${currentUser?.name || 'User'}`}
             </div>
             <button onClick={toggleLanguage} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-50 text-slate-600 hover:bg-slate-100 transition-all text-xs font-bold border border-slate-200">
               <Globe size={14} />
               {lang === Language.AR ? 'Français' : 'العربية'}
             </button>
             <h2 className="hidden md:flex items-center gap-2 text-sm font-black text-slate-800">
               {t(currentView)}
             </h2>
          </div>
        </header>

        {/* المحتوى الرئيسي */}
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 bg-slate-50/50">
          <div className="max-w-7xl mx-auto h-full">{renderContent()}</div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Sprout, 
  Tractor, 
  Leaf, 
  Plus, 
  Calendar, 
  DollarSign, 
  Weight, 
  FileText, 
  Trash2, 
  Edit3, 
  ArrowUpRight,
  Filter,
  Download,
  Wheat,
  Droplets,
  Sun
} from 'lucide-react';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

// تعريف نوع بيانات الإنتاج الزراعي ليكون جاهز لقواعد البيانات
interface FarmProduction {
  id: string;
  date: string;
  cropType: string;      // النوع (برسيم، قمح، إلخ)
  weight: number;        // الوزن
  unit: string;          // الوحدة (طن، كيلو)
  unitPrice: number;     // سعر الوحدة (595 مثلاً)
  totalPrice: number;    // الإجمالي (محسوب تلقائياً)
  notes: string;         // ملاحظات
  season: string;        // الموسم (2025)
}

interface FarmManagementProps {
  lang: Language;
  onLogout: () => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  farmData: FarmProduction[];
  setFarmData: (data: FarmProduction[]) => void;
}

const FarmManagement: React.FC<FarmManagementProps> = ({ lang, onLogout, showNotification, farmData, setFarmData }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة المودال والنموذج (State)
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState<Partial<FarmProduction>>({
    date: new Date().toISOString().split('T')[0],
    cropType: '',
    weight: 0,
    unit: 'Ton',
    unitPrice: 595, // القيمة الافتراضية كما طلب المستخدم
    notes: '',
    season: '2025'
  });

  // حساب الإجماليات للإحصائيات
  const stats = useMemo(() => {
    const totalRevenue = farmData.reduce((sum, item) => sum + item.totalPrice, 0);
    const totalWeight = farmData.reduce((sum, item) => sum + item.weight, 0);
    const productionCount = farmData.length;
    return { totalRevenue, totalWeight, productionCount };
  }, [farmData]);

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  const handleSave = () => {
    // التحقق من البيانات
    if (!formData.cropType || !formData.weight || !formData.unitPrice) {
        showNotification(isRTL ? 'يرجى تعبئة الحقول الأساسية' : 'Please fill required fields', 'error');
        return;
    }

    const total = Number(formData.weight) * Number(formData.unitPrice);

    const newItem: FarmProduction = {
        id: Math.random().toString(36).substr(2, 9),
        date: formData.date || new Date().toISOString().split('T')[0],
        cropType: formData.cropType,
        weight: Number(formData.weight),
        unit: formData.unit || 'Ton',
        unitPrice: Number(formData.unitPrice),
        totalPrice: total,
        notes: formData.notes || '',
        season: formData.season || '2025'
    };

    setFarmData([newItem, ...farmData]);
    setIsModalOpen(false);
    // إعادة تعيين النموذج
    setFormData({ 
        date: new Date().toISOString().split('T')[0], 
        cropType: '', 
        weight: 0, 
        unit: 'Ton', 
        unitPrice: 595, 
        notes: '', 
        season: '2025' 
    });
    showNotification(t('success'), 'success');
  };

  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'حذف هذا السجل؟' : 'Delete record?')) {
          setFarmData(farmData.filter(d => d.id !== id));
      }
  };

  // بطاقة إحصائيات بتصميم الطبيعة
  const StatCard = ({ title, value, unit, icon: Icon, gradient }: any) => (
      <div className={`relative overflow-hidden rounded-[2rem] p-6 border border-white/10 shadow-xl group ${gradient}`}>
          {/* خلفية زخرفية */}
          <div className="absolute top-0 right-0 -mt-4 -mr-4 w-24 h-24 bg-white/10 rounded-full blur-2xl group-hover:scale-150 transition-transform duration-700"></div>

          <div className="relative z-10 flex justify-between items-start">
              <div>
                  <p className="text-[10px] font-black text-green-100/70 uppercase tracking-widest mb-1">{title}</p>
                  <h3 className="text-3xl font-black text-white font-mono tracking-tight">{value} <span className="text-sm font-bold opacity-60">{unit}</span></h3>
              </div>
              <div className="p-3 bg-white/20 rounded-2xl text-white backdrop-blur-sm shadow-sm">
                  <Icon size={24} />
              </div>
          </div>
      </div>
  );

  return (
    <div className={`min-h-screen bg-[#02040a] text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'}>
      {/* خلفية الطبيعة التجريدية */}
      <div className="fixed inset-0 z-0 pointer-events-none">
          <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-green-900/20 rounded-full blur-[120px]"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-emerald-900/20 rounded-full blur-[120px]"></div>
      </div>

      {/* الترويسة */}
      <header className="relative z-10 bg-slate-900/60 backdrop-blur-xl border-b border-white/5 p-6 sticky top-0">
         <div className="max-w-7xl mx-auto flex justify-between items-center">
             <div className="flex items-center gap-4">
                 <div className="w-14 h-14 bg-gradient-to-br from-green-500 to-emerald-700 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-green-500/20 ring-1 ring-white/20">
                     <Tractor size={30} />
                 </div>
                 <div>
                     <h1 className="text-2xl font-black tracking-tight text-white">{isRTL ? 'إدارة المزرعة والإنتاج' : 'Farm Management System'}</h1>
                     <div className="flex items-center gap-2 mt-1">
                        <span className="px-2 py-0.5 rounded bg-green-500/20 text-green-400 text-[10px] font-black uppercase tracking-wider border border-green-500/20">
                            {isRTL ? 'موسم 2025' : 'Season 2025'}
                        </span>
                        <span className="text-slate-500 text-[10px] font-bold">| Integrated DB System</span>
                     </div>
                 </div>
             </div>
             <button onClick={onLogout} className="px-6 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black text-slate-300 transition-all border border-white/5 shadow-sm">
                 {t('backToHub')}
             </button>
         </div>
      </header>

      <main className="relative z-10 max-w-7xl mx-auto p-6 lg:p-10 space-y-10 animate-fade-in-up">

          {/* قسم الإحصائيات العلوية */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard 
                title={isRTL ? 'إجمالي الإيرادات (2025)' : 'Total Revenue'} 
                value={stats.totalRevenue.toLocaleString()} 
                unit="SAR" 
                icon={DollarSign} 
                gradient="bg-gradient-to-br from-emerald-800 to-green-900" 
              />
              <StatCard 
                title={isRTL ? 'إجمالي الوزن المنتج' : 'Total Weight'} 
                value={stats.totalWeight.toLocaleString()} 
                unit="Ton" 
                icon={Weight} 
                gradient="bg-gradient-to-br from-lime-800 to-emerald-900" 
              />
              <StatCard 
                title={isRTL ? 'عدد الحصاد / العمليات' : 'Harvest Operations'} 
                value={stats.productionCount} 
                unit="#" 
                icon={Sprout} 
                gradient="bg-gradient-to-br from-green-800 to-teal-900" 
              />
          </div>

          {/* قسم الجدول الرئيسي */}
          <div className="bg-[#0a0c14] rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl relative">
              {/* شريط الأدوات العلوي للجدول */}
              <div className="p-8 border-b border-white/5 bg-gradient-to-r from-green-900/20 to-transparent flex flex-wrap justify-between items-center gap-4">
                  <div className="flex items-center gap-3">
                      <div className="p-3 bg-green-500/10 text-green-400 rounded-xl border border-green-500/20">
                          <Leaf size={20} />
                      </div>
                      <div>
                          <h3 className="text-lg font-black text-white">{isRTL ? 'سجل الإنتاج الزراعي' : 'Agricultural Production Log'}</h3>
                          <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">{isRTL ? 'قاعدة بيانات المحاصيل الحية' : 'Live Crops Database'}</p>
