  const isRTL = lang === Language.AR;
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;

  // =========================================
  // حفظ البيانات تلقائياً عند التغيير
  // =========================================
  useEffect(() => {
    localStorage.setItem('np_customers', JSON.stringify(customers));
    localStorage.setItem('np_products', JSON.stringify(products));
    localStorage.setItem('np_materials', JSON.stringify(materials));
    localStorage.setItem('np_orders', JSON.stringify(orders));
    localStorage.setItem('np_staff', JSON.stringify(staff));
    localStorage.setItem('np_expenses', JSON.stringify(expenses));
    localStorage.setItem('np_gold_tx', JSON.stringify(goldTransactions));
    localStorage.setItem('np_appointments', JSON.stringify(appointments));
    localStorage.setItem('np_farm_data', JSON.stringify(farmData));
  }, [customers, products, materials, orders, staff, expenses, goldTransactions, appointments, farmData]);

  // دالة لعرض الإشعارات
  const showNotification = useCallback((message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
  }, []);

  // دالة تغيير اللغة
  const toggleLanguage = () => setLang(prev => prev === Language.AR ? Language.FR : Language.AR);

  // دالة تسجيل الدخول
  const handleLogin = (user: Staff) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    if (user.allowedEntity && user.allowedEntity !== 'MASTER' && user.allowedEntity !== 'GENERAL_ADMIN') {
        setCurrentEntity(user.allowedEntity);
    } else {
        setCurrentEntity('MASTER');
    }
  };

  // دالة تسجيل الخروج
  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentEntity('MASTER');
  };

  // =========================================
  // التوجيه (Routing) وعرض الصفحات
  // =========================================

  // 1. شاشة تسجيل الدخول
  if (!isLoggedIn) return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Login lang={lang} onLogin={handleLogin} toggleLanguage={toggleLanguage} staff={staff} showNotification={showNotification} />
    </>
  );

  // 2. المركز الرئيسي (HUB)
  if (currentEntity === 'MASTER') return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Hub lang={lang} onSelectEntity={(e) => { setCurrentEntity(e); setCurrentView('dashboard'); }} onLogout={handleLogout} />
    </>
  );

  // 3. إدارة الذهب (عرض خاص)
  if (currentEntity === 'MAKH_GOLD') return (
    <MakhGold 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      goldTransactions={goldTransactions} 
      setGoldTransactions={setGoldTransactions} 
      shareholders={[]} 
      setShareholders={() => {}} 
      showNotification={showNotification} 
    />
  );

  // 4. إدارة المساجد (عرض خاص)
  if (currentEntity === 'MOSQUE') return (
    <MosqueManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification} 
    />
  );

  // 5. إدارة المزرعة (عرض خاص)
  if (currentEntity === 'FARM') return (
    <FarmManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification}
      farmData={farmData}
      setFarmData={setFarmData}
    />
  );

  // 6. شركة التقدم (عرض خاص - جديد)
  if (currentEntity === 'ALTAQADDUM') return (
    <AlTaqaddum 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification}
    />
  );

  // 7. الإدارة العامة (عرض خاص)
  if (currentEntity === 'GENERAL_ADMIN') return (
    <GeneralAdmin 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER') setCurrentEntity('MASTER'); else handleLogout(); }} 
      expenses={expenses} 
      goldTransactions={goldTransactions} 
      orders={orders} 
      staff={staff} 
      setStaff={setStaff} 
      appointments={appointments} 
      setAppointments={setAppointments} 
      showNotification={showNotification} 
      currentUser={currentUser} 
    />
  );

  // 8. لوحة التحكم الافتراضية للمصنع
  const renderContent = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard lang={lang} setCurrentView={setCurrentView} orders={orders} staff={staff} expenses={expenses} materials={materials} products={products} />;
      case 'inventory': return <Inventory lang={lang} materials={materials} setMaterials={setMaterials} products={products} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} showNotification={showNotification} onRestockMaterial={() => {}} />;
      case 'orders': return <Orders lang={lang} customers={customers} orders={orders} setOrders={setOrders} products={products} setProducts={setProducts} setExpenses={setExpenses} showNotification={showNotification} />;
      case 'customers': return <Customers lang={lang} customers={customers} setCustomers={setCustomers} showNotification={showNotification} />;
      case 'staff': return <StaffView lang={lang} staff={staff} setStaff={setStaff} onPaySalary={() => {}} onRequestAdvance={() => {}} showNotification={showNotification} />;
      case 'production': return <Production lang={lang} products={products} setProducts={setProducts} materials={materials} setMaterials={setMaterials} showNotification={showNotification} />;
      case 'finance': return <Finance lang={lang} expenses={expenses} setExpenses={setExpenses} orders={orders} showNotification={showNotification} />;
      default: return <Dashboard lang={lang} setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div dir={isRTL ? 'rtl' : 'ltr'} className={`flex h-screen bg-slate-50 overflow-hidden ${isRTL ? 'font-cairo' : 'font-sans'}`}>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}

      {/* القائمة الجانبية */}
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} lang={lang} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        {/* الشريط العلوي */}
        <header className="h-20 bg-white border-b border-slate-100 flex items-center justify-between px-8 z-10 print:hidden">
          <div className="flex items-center gap-6">
             <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-slate-500"><Menu size={24} /></button>

             {/* إظهار زر العودة للمركز الرئيسي فقط للإدارة العليا */}
             {(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') && (
                <button onClick={() => setCurrentEntity('MASTER')} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all">
                  <ArrowLeft size={16} className={isRTL ? 'rotate-180' : ''} />
                  {t('backToHub')}
                </button>
             )}
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden sm:block text-sm text-slate-400 font-bold">
                {lang === Language.AR ? `أهلاً، ${currentUser?.name || 'مستخدم'}` : `Welcome, ${currentUser?.name || 'User'}`}
             </div>
             <button onClick={toggleLanguage} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-50 text-slate-600 hover:bg-slate-100 transition-all text-xs font-bold border border-slate-200">
               <Globe size={14} />
               {lang === Language.AR ? 'Français' : 'العربية'}
             </button>
             <h2 className="hidden md:flex items-center gap-2 text-sm font-black text-slate-800">
               {t(currentView)}
             </h2>
          </div>
        </header>

        {/* المحتوى الرئيسي */}
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 bg-slate-50/50">
          <div className="max-w-7xl mx-auto h-full">{renderContent()}</div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Building2, 
  Wallet, 
  Landmark, 
  TrendingUp, 
  TrendingDown, 
  Users, 
  Plus, 
  Trash2, 
  Edit, 
  Save, 
  X, 
  Calculator,
  ArrowRightLeft,
  Banknote,
  PieChart,
  UserPlus
} from 'lucide-react';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

// واجهات البيانات الخاصة بالتقدم
interface TaqaddumTransaction {
  id: string;
  date: string;
  description: string;
  type: 'income' | 'expense' | 'transfer';
  category: 'bank' | 'cash' | 'loan'; // بنك، صندوق، سلف
  amount: number;
  notes?: string;
  beneficiary?: string; // المستفيد (للسلف)
}

interface TaqaddumShareholder {
  id: string;
  name: string;
  capital: number;
  shares: number;
  months: number;
  operatorPercent: number; // نسبة المشغل
  mediatorPercent: number; // نسبة الوسيط
  shareholderPercent: number; // نسبة المساهم
  profitRatio: number; // نسبة الربح من المساهمة (مثلا 200%)
  firstPayment?: number;
  secondPayment?: number;
}

interface LoanRecord {
  id: string;
  name: string;
  amount: number;
  date: string;
  notes: string;
  isPaid: boolean;
}

interface AlTaqaddumProps {
  lang: Language;
  onLogout: () => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
}

const AlTaqaddum: React.FC<AlTaqaddumProps> = ({ lang, onLogout, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // الحالة (State)
  // =========================================
  const [activeTab, setActiveTab] = useState<'accounting' | 'shareholders'>('accounting');

  // بيانات المحاسبة (مبدئية حسب طلبك)
  const [transactions, setTransactions] = useState<TaqaddumTransaction[]>([
    { id: 't1', date: '2022-01-01', description: 'رصيد الافتتاح للعام', type: 'income', category: 'bank', amount: 2133114, notes: 'رصيد مرحل' },
    { id: 't2', date: '2022-01-01', description: 'رصيد الافتتاح نقدي', type: 'income', category: 'cash', amount: 350000, notes: 'رصيد مرحل' },
    { id: 't3', date: '2022-01-01', description: 'سحب من البنك شراء 500 بيض + رواتب', type: 'expense', category: 'bank', amount: 275000, notes: 'مصاريف المزرعة' },
  ]);

  // بيانات السلف (حسب طلبك)
  const [loans, setLoans] = useState<LoanRecord[]>([
    { id: 'l1', name: 'أحمد العماري', amount: 3000, date: '2022-01-05', notes: 'سلفة لشركة التقدم', isPaid: false },
    { id: 'l2', name: 'علي حسين', amount: 8000, date: '2022-01-10', notes: 'سلفة لشركة التقدم', isPaid: false },
    { id: 'l3', name: 'علي حسين', amount: 4000, date: '2022-01-15', notes: 'سلفة إضافية', isPaid: false },
    { id: 'l4', name: 'سليمان', amount: 9515424, date: '2022-01-01', notes: 'سلفة لسليمان على الشركة (فارق حسابات)', isPaid: false },
  ]);

  // بيانات المساهمين (حسب الجدول)
  const [shareholders, setShareholders] = useState<TaqaddumShareholder[]>([
    { id: 'sh1', name: 'إبراهيم يحيى إبراهيم أبو بكر', capital: 3300, shares: 3, months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 },
    { id: 'sh2', name: 'أحمد إبراهيم أبو بكر عبد الله', capital: 15150, shares: 15, months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 },
    { id: 'sh3', name: 'أحمد محمد جبران العماري', capital: 54583, shares: 55, months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 },
    { id: 'sh4', name: 'إدريس إبراهيم أبو بكر عبد الله', capital: 6600, shares: 7, months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 },
  ]);

  // المودالات
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [isShModalOpen, setIsShModalOpen] = useState(false);
  const [isLoanModalOpen, setIsLoanModalOpen] = useState(false);

  // النماذج (Forms)
  const [txForm, setTxForm] = useState<Partial<TaqaddumTransaction>>({ date: new Date().toISOString().split('T')[0], type: 'income', category: 'bank', amount: 0, description: '' });
  const [shForm, setShForm] = useState<Partial<TaqaddumShareholder>>({ months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 });
  const [loanForm, setLoanForm] = useState<Partial<LoanRecord>>({ date: new Date().toISOString().split('T')[0], isPaid: false });

  // =========================================
  // الحسابات (Calculations)
  // =========================================
  const stats = useMemo(() => {
    const bankIncome = transactions.filter(t => t.category === 'bank' && t.type === 'income').reduce((s, t) => s + t.amount, 0);
    const bankExpense = transactions.filter(t => t.category === 'bank' && t.type === 'expense').reduce((s, t) => s + t.amount, 0);
    const cashIncome = transactions.filter(t => t.category === 'cash' && t.type === 'income').reduce((s, t) => s + t.amount, 0);
    const cashExpense = transactions.filter(t => t.category === 'cash' && t.type === 'expense').reduce((s, t) => s + t.amount, 0);

    const totalLoans = loans.filter(l => !l.isPaid).reduce((s, l) => s + l.amount, 0);

    return {
      bankBalance: bankIncome - bankExpense,
      cashBalance: cashIncome - cashExpense,
      totalIncome: bankIncome + cashIncome,
      totalExpense: bankExpense + cashExpense,
      totalLoans
    };
  }, [transactions, loans]);

  // =========================================
  // الدوال (Handlers)
  // =========================================

  const handleSaveTx = () => {
    if (!txForm.amount || !txForm.description) return;
    const newTx: TaqaddumTransaction = {
      id: Math.random().toString(36).substr(2, 9),
      ...txForm as TaqaddumTransaction
    };
    setTransactions([newTx, ...transactions]);
    setIsTxModalOpen(false);
    setTxForm({ date: new Date().toISOString().split('T')[0], type: 'income', category: 'bank', amount: 0, description: '' });
    showNotification(t('success'), 'success');
  };

  const handleSaveShareholder = () => {
    if (!shForm.name || !shForm.capital) return;
    const newSh: TaqaddumShareholder = {
      id: shForm.id || Math.random().toString(36).substr(2, 9),
      ...shForm as TaqaddumShareholder
    };

    if (shForm.id) {
        setShareholders(shareholders.map(s => s.id === shForm.id ? newSh : s));
    } else {
        setShareholders([...shareholders, newSh]);
    }
    setIsShModalOpen(false);
    setShForm({ months: 12, operatorPercent: 0, mediatorPercent: 0, shareholderPercent: 100, profitRatio: 200 });
    showNotification(t('success'), 'success');
  };

  const handleSaveLoan = () => {
      if (!loanForm.name || !loanForm.amount) return;
      const newLoan: LoanRecord = {
          id: Math.random().toString(36).substr(2, 9),
          ...loanForm as LoanRecord
      };
      setLoans([...loans, newLoan]);
      setIsLoanModalOpen(false);
      setLoanForm({ date: new Date().toISOString().split('T')[0], isPaid: false });
      showNotification(t('success'), 'success');
  };

  const deleteItem = (type: 'tx' | 'sh' | 'loan', id: string) => {
      if (!confirm('تأكيد الحذف؟')) return;
      if (type === 'tx') setTransactions(transactions.filter(t => t.id !== id));
      if (type === 'sh') setShareholders(shareholders.filter(s => s.id !== id));
      if (type === 'loan') setLoans(loans.filter(l => l.id !== id));
      showNotification(t('success'), 'success');
  };

  // المكونات الفرعية للتصميم
  const StatBox = ({ title, val, color, icon: Icon }: any) => (
      <div className={`p-6 rounded-3xl border border-white/5 flex flex-col justify-between h-full bg-slate-900 shadow-xl relative overflow-hidden group`}>
          <div className={`absolute top-0 right-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity ${color}`}>
              <Icon size={64} />
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest z-10">{title}</p>
          <p className={`text-2xl font-black mt-2 font-mono z-10 ${color.replace('bg-', 'text-')}`} dir="ltr">
              {val.toLocaleString()} <span className="text-[10px] text-slate-500">SAR</span>
          </p>
      </div>
  );

  return (
    <div className={`min-h-screen bg-[#02040a] text-slate-100 ${isRTL ? 'font-cairo' : 'font-sans'}`} dir={isRTL ? 'rtl' : 'ltr'}>

      {/* الترويسة */}
      <header className="bg-slate-900/80 backdrop-blur-xl border-b border-white/5 p-6 sticky top-0 z-50">
         <div className="max-w-7xl mx-auto flex justify-between items-center">
             <div className="flex items-center gap-4">
                 <div className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                     <Building2 size={30} />
                 </div>
                 <div>
                     <h1 className="text-2xl font-black tracking-tight text-white">{isRTL ? 'شركة التقدم' : 'Al-Taqaddum Co.'}</h1>
                     <p className="text-slate-500 text-[10px] font-bold uppercase tracking-wider">نظام المحاسبة وإدارة المساهمين</p>
                 </div>
             </div>
             <button onClick={onLogout} className="px-6 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black text-slate-300 transition-all border border-white/5">
                 {t('backToHub')}
             </button>
         </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 lg:p-10 space-y-8 animate-fade-in-up">

        {/* التبويبات */}
        <div className="flex bg-slate-900/50 p-1.5 rounded-2xl border border-white/5 w-fit">
            <button 
            onClick={() => setActiveTab('accounting')}
            className={`px-8 py-3 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${activeTab === 'accounting' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
                <Calculator size={16} /> {isRTL ? 'البرنامج المحاسبي' : 'Accounting'}
            </button>
            <button 
            onClick={() => setActiveTab('shareholders')}
            className={`px-8 py-3 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${activeTab === 'shareholders' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
                <Users size={16} /> {isRTL ? 'مساهمو التقدم' : 'Shareholders'}
            </button>
        </div>

        {/* محتوى البرنامج المحاسبي */}
        {activeTab === 'accounting' && (
            <div className="space-y-8">
                {/* الإحصائيات */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    <StatBox title={isRTL ? 'رصيد البنك' : 'Bank Balance'} val={stats.bankBalance} color="text-blue-500" icon={Landmark} />
                    <StatBox title={isRTL ? 'رصيد الصندوق' : 'Cash Balance'} val={stats.cashBalance} color="text-emerald-500" icon={Wallet} />
                    <StatBox title={isRTL ? 'إجمالي المصروفات' : 'Total Expenses'} val={stats.totalExpense} color="text-rose-500" icon={TrendingDown} />
                    <StatBox title={isRTL ? 'إجمالي السلف والديون' : 'Total Loans'} val={stats.totalLoans} color="text-amber-500" icon={ArrowRightLeft} />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* جدول العمليات */}
                    <div className="lg:col-span-2 bg-slate-900 rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl">
                        <div className="p-8 border-b border-white/5 flex justify-between items-center">
                            <h3 className="text-lg font-black text-white">{isRTL ? 'سجل العمليات اليومية' : 'Transactions Log'}</h3>
                            <button onClick={() => setIsTxModalOpen(true)} className="px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all">
                                <Plus size={16} /> {isRTL ? 'عملية جديدة' : 'New Transaction'}
                            </button>
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-right text-xs">
                                <thead className="bg-black/20 text-slate-500 font-black uppercase tracking-widest">
                                    <tr>
                                        <th className="px-6 py-5">{t('date')}</th>
                                        <th className="px-6 py-5">{isRTL ? 'البيان' : 'Description'}</th>
                                        <th className="px-6 py-5 text-center">{isRTL ? 'التصنيف' : 'Type'}</th>
                                        <th className="px-6 py-5">{isRTL ? 'وارد (دخل)' : 'Credit'}</th>
                                        <th className="px-6 py-5">{isRTL ? 'منصرف' : 'Debit'}</th>
                                        <th className="px-6 py-5 text-center"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-white/5 font-mono">
                                    {transactions.map(tx => (
                                        <tr key={tx.id} className="hover:bg-white/5 transition-colors">
                                            <td className="px-6 py-5 text-slate-500">{tx.date}</td>
                                            <td className="px-6 py-5 font-bold text-white font-sans">{tx.description} <span className="text-[10px] text-slate-500 block font-normal">{tx.notes}</span></td>
                                            <td className="px-6 py-5 text-center">
                                                <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${tx.category === 'bank' ? 'bg-blue-500/10 text-blue-400' : 'bg-emerald-500/10 text-emerald-400'}`}>
                                                    {tx.category}
                                                </span>
                                            </td>
                                            <td className="px-6 py-5 text-emerald-400 font-black">{tx.type === 'income' ? tx.amount.toLocaleString() : '-'}</td>
                                            <td className="px-6 py-5 text-rose-400 font-black">{tx.type === 'expense' ? tx.amount.toLocaleString() : '-'}</td>
                                            <td className="px-6 py-5 text-center">
                                                <button onClick={() => deleteItem('tx', tx.id)} className="text-slate-600 hover:text-rose-500"><Trash2 size={16} /></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    {/* قائمة السلف */}
                    <div className="bg-slate-900 rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl h-fit">
