import { Language, GoldTransaction, Shareholder } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

// --- Interfaces for New Features ---
interface FinancialSettings {
  initialCapital: number;
  exchangeRate: number; // Default 157.27786
}

interface GeneralTransaction {
  id: string;
  type: 'income' | 'expense';
  amount: number; // In XOF (CFA)
  description: string;
  date: string;
  category?: string;
}

interface FixedAsset {
  id: string;
  name: string;
  quantity: number;
  value: number; // Estimated value per unit or total? Usually Total Value in simple dashboards
  notes?: string;
  date: string;
}

interface MakhGoldProps {
  lang: Language;
  onLogout: () => void;
  goldTransactions: GoldTransaction[];
  setGoldTransactions: (t: GoldTransaction[]) => void;
  shareholders: Shareholder[];
  setShareholders: (s: Shareholder[]) => void;
  showNotification: (msg: string, type: 'success' | 'error') => void;
}

const MakhGold: React.FC<MakhGoldProps> = ({ 
  lang, onLogout, goldTransactions, setGoldTransactions, shareholders, setShareholders, showNotification 
}) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // State Management
  // =========================================
  const [activeTab, setActiveTab] = useState<'dashboard' | 'assets' | 'gold_program' | 'shares'>('dashboard');

  // Settings (Persisted in LocalStorage for demo)
  const [settings, setSettings] = useState<FinancialSettings>(() => {
    const saved = localStorage.getItem('mg_settings');
    return saved ? JSON.parse(saved) : { initialCapital: 100000000, exchangeRate: 157.27786 };
  });

  // General Accounting Transactions (Persisted)
  const [genTransactions, setGenTransactions] = useState<GeneralTransaction[]>(() => {
    const saved = localStorage.getItem('mg_gen_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  // Fixed Assets (Persisted)
  const [fixedAssets, setFixedAssets] = useState<FixedAsset[]>(() => {
    const saved = localStorage.getItem('mg_assets');
    return saved ? JSON.parse(saved) : [];
  });

  // Modals
  const [isTxModalOpen, setIsTxModalOpen] = useState(false);
  const [isAssetModalOpen, setIsAssetModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [isShareholderModalOpen, setIsShareholderModalOpen] = useState(false);
  const [isGoldTxModalOpen, setIsGoldTxModalOpen] = useState(false); // For old gold program

  // Forms
  const [txForm, setTxForm] = useState<Partial<GeneralTransaction>>({ type: 'expense', date: new Date().toISOString().split('T')[0] });
  const [assetForm, setAssetForm] = useState<Partial<FixedAsset>>({ quantity: 1, value: 0, date: new Date().toISOString().split('T')[0] });
  const [goldTxForm, setGoldTxForm] = useState<Partial<GoldTransaction>>({ type: 'purchase', date: new Date().toISOString().split('T')[0] });
  const [shareholderForm, setShareholderForm] = useState<Partial<Shareholder>>({ numberOfShares: 0, capitalAmount: 0 });

  // Persistence Effects
  useEffect(() => localStorage.setItem('mg_settings', JSON.stringify(settings)), [settings]);
  useEffect(() => localStorage.setItem('mg_gen_transactions', JSON.stringify(genTransactions)), [genTransactions]);
  useEffect(() => localStorage.setItem('mg_assets', JSON.stringify(fixedAssets)), [fixedAssets]);

  // =========================================
  // Financial Dashboard Logic (The Formulas)
  // =========================================
  const financials = useMemo(() => {
    // 1. Total Income (B1366)
    const totalIncome = genTransactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + t.amount, 0);

    // 2. Total Expense (C1366)
    const totalExpense = genTransactions
      .filter(t => t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0);

    // 3. Box Balance / Net Cash (K2-K3)
    const boxBalance = totalIncome - totalExpense;

    // 4. Box Balance in SAR
    const boxBalanceSAR = boxBalance / (settings.exchangeRate || 1);

    // 5. Remaining Capital (G1366: Initial Capital + Box Balance as requested)
    // Interpretation: This represents the Current Cash Position relative to Initial Capital
    const remainingCapital = settings.initialCapital + boxBalance;

    // 6. Assets Value
    const totalAssetsValue = fixedAssets.reduce((sum, a) => sum + (a.value * a.quantity), 0);

    // 7. New Capital (L4+H2: Remaining Capital + Current Profit/Assets)
    // We define this as "Total Equity" = Remaining Cash Capital + Fixed Assets Value
    const newCapital = remainingCapital + totalAssetsValue;

    return {
      totalIncome,
      totalExpense,
      boxBalance,
      boxBalanceSAR,
      remainingCapital,
      totalAssetsValue,
      newCapital
    };
  }, [genTransactions, fixedAssets, settings]);

