        )}

        {/* =======================
            TAB 4: GOLD PROGRAM (Legacy)
           ======================= */}
        {activeTab === 'gold_program' && (
           <div className="space-y-6">
              <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden">
                 <div className="p-6 border-b border-slate-700 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-amber-500">{isRTL ? 'برنامج شراء الذهب' : 'Gold Purchase Program'}</h3>
                    {/* Placeholder for old functionality if needed */}
