                     <TableIcon size={48} className="mx-auto mb-4 opacity-20"/>
                     <p className="text-xs uppercase tracking-widest font-black">Specific Gold Trading Ledger (Legacy)</p>
                     <p className="text-xs mt-2">See "Transactions" in Dashboard for the main ledger.</p>
                 </div>
              </div>
           </div>
        )}

      </main>

      {/* =======================
          MODALS
         ======================= */}

      {/* Settings Modal */}
      <Modal isOpen={isSettingsModalOpen} onClose={() => setIsSettingsModalOpen(false)} title={isRTL ? 'إعدادات النظام المالي' : 'Financial Settings'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-slate-700">
          <div className="space-y-6">
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'رأس المال الأولي (Initial Capital)' : 'Initial Capital'}</label>
                  <input type="number" value={settings.initialCapital} onChange={e => setSettings({...settings, initialCapital: Number(e.target.value)})} className="w-full bg-slate-800 border border-slate-700 p-4 rounded-xl outline-none font-mono text-xl text-white focus:border-blue-500" dir="ltr" />
              </div>
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">{isRTL ? 'سعر الصرف (Exchange Rate)' : 'Exchange Rate'}</label>
                  <input type="number" value={settings.exchangeRate} onChange={e => setSettings({...settings, exchangeRate: Number(e.target.value)})} className="w-full bg-slate-800 border border-slate-700 p-4 rounded-xl outline-none font-mono text-xl text-amber-400 focus:border-amber-500" dir="ltr" />
              </div>
              <button onClick={() => setIsSettingsModalOpen(false)} className="w-full py-4 bg-slate-700 hover:bg-slate-600 text-white rounded-2xl font-black">{t('save')}</button>
          </div>
      </Modal>

      {/* Add Transaction Modal */}
      <Modal isOpen={isTxModalOpen} onClose={() => setIsTxModalOpen(false)} title={isRTL ? 'عملية محاسبية جديدة' : 'New Transaction'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-slate-700">
          <div className="space-y-4">
              <div className="flex gap-2 bg-slate-800 p-1 rounded-xl">
                  <button onClick={() => setTxForm({...txForm, type: 'income'})} className={`flex-1 py-3 rounded-lg font-black text-xs ${txForm.type === 'income' ? 'bg-emerald-600 text-white' : 'text-slate-400'}`}>{isRTL ? 'دخل (Income)' : 'Income'}</button>
                  <button onClick={() => setTxForm({...txForm, type: 'expense'})} className={`flex-1 py-3 rounded-lg font-black text-xs ${txForm.type === 'expense' ? 'bg-rose-600 text-white' : 'text-slate-400'}`}>{isRTL ? 'مصروف (Expense)' : 'Expense'}</button>
              </div>
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">المبلغ (XOF)</label>
                  <input type="number" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: Number(e.target.value)})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-mono text-white text-lg" dir="ltr" />
              </div>
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">البيان / الوصف</label>
                  <input type="text" value={txForm.description} onChange={e => setTxForm({...txForm, description: e.target.value})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-bold text-white" />
              </div>
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">التاريخ</label>
                  <input type="date" value={txForm.date} onChange={e => setTxForm({...txForm, date: e.target.value})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-mono text-center text-white" />
              </div>
              <button onClick={handleSaveGenTx} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black mt-2">{t('save')}</button>
          </div>
      </Modal>

      {/* Add Asset Modal */}
      <Modal isOpen={isAssetModalOpen} onClose={() => setIsAssetModalOpen(false)} title={isRTL ? 'إضافة أصل جديد' : 'New Asset'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-slate-700">
          <div className="space-y-4">
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">اسم الأصل</label>
                  <input type="text" value={assetForm.name} onChange={e => setAssetForm({...assetForm, name: e.target.value})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-bold text-white" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                  <div>
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">الكمية</label>
                      <input type="number" value={assetForm.quantity} onChange={e => setAssetForm({...assetForm, quantity: Number(e.target.value)})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-mono text-center text-white" dir="ltr" />
                  </div>
                  <div>
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">القيمة التقديرية (للوحدة)</label>
                      <input type="number" value={assetForm.value} onChange={e => setAssetForm({...assetForm, value: Number(e.target.value)})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-mono text-center text-white" dir="ltr" />
                  </div>
              </div>
              <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1">ملاحظات</label>
                  <input type="text" value={assetForm.notes} onChange={e => setAssetForm({...assetForm, notes: e.target.value})} className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none font-bold text-white" />
              </div>
              <button onClick={handleSaveAsset} className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black mt-2">{t('save')}</button>
          </div>
      </Modal>

      {/* Shareholder Modal (Reused Logic) */}
      <Modal isOpen={isShareholderModalOpen} onClose={() => setIsShareholderModalOpen(false)} title={isRTL ? 'إضافة مساهم' : 'Add Shareholder'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-slate-700">
         <div className="space-y-4">
            {/* Simple inputs for demo, fully functional in prev version */}
            <input type="text" placeholder="Name" className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none" value={shareholderForm.name} onChange={e => setShareholderForm({...shareholderForm, name: e.target.value})} />
            <input type="number" placeholder="Capital" className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none" value={shareholderForm.capitalAmount} onChange={e => setShareholderForm({...shareholderForm, capitalAmount: Number(e.target.value)})} />
            <button onClick={() => { 
                if(!shareholderForm.name) return;
                setShareholders([...shareholders, { id: Math.random().toString(), name: shareholderForm.name!, capitalAmount: shareholderForm.capitalAmount || 0, phone: '', numberOfShares: 0, operatingMonths: 0, percentage: 0, operatorPercentage: 0, mediatorPercentage: 0, profitShare: 0, operatorProfit: 0, mediatorProfit: 0 }]); 
                setIsShareholderModalOpen(false); 
                setShareholderForm({});
            }} className="w-full py-3 bg-purple-600 text-white rounded-xl font-bold">{t('save')}</button>
         </div>
      </Modal>

    </div>
  );
};

