import React, { useState, useMemo } from 'react';
import { 
  Plus, 
  Edit2, 
  Trash2, 
  ShoppingCart, 
  Search, 
  AlertTriangle, 
  Package, 
  Truck, 
  ArrowUpDown,
  Filter,
  MoreVertical,
  ChevronDown
} from 'lucide-react';
import { Language, RawMaterial, Product, Expense } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface InventoryProps {
  lang: Language;
  materials: RawMaterial[];
  setMaterials: (m: RawMaterial[]) => void;
  products: Product[];
  setProducts: (p: Product[]) => void;
  expenses: Expense[];
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  showNotification: (msg: string, type: 'success' | 'error') => void;
  onRestockMaterial: () => void;
}

const Inventory: React.FC<InventoryProps> = ({ 
  lang, materials, setMaterials, products, setProducts, expenses, setExpenses, showNotification 
}) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;
  const [activeTab, setActiveTab] = useState<'raw' | 'finished'>('raw');
  const [searchQuery, setSearchQuery] = useState('');

  // Modal states
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRestockModalOpen, setIsRestockModalOpen] = useState(false);
  const [editItem, setEditItem] = useState<any | null>(null);
  const [restockItem, setRestockItem] = useState<RawMaterial | null>(null);

  // Form states
  const [formData, setFormData] = useState({ 
    nameAr: '', nameFr: '', quantity: 0, maxQuantity: 100, minLevel: 10, unit: 'pcs', unitPrice: 0, supplier: '' 
  });
  const [restockData, setRestockData] = useState({ quantity: 0, totalCost: 0 });

  // Filtered Items
  const filteredItems = useMemo(() => {
    const list = activeTab === 'raw' ? materials : products;
    return list.filter(item => 
      item.nameAr.toLowerCase().includes(searchQuery.toLowerCase()) || 
      item.nameFr.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [activeTab, materials, products, searchQuery]);

  const stats = useMemo(() => {
    const list = activeTab === 'raw' ? materials : products;
    const lowStock = list.filter(item => item.quantity <= item.minLevel).length;
    const totalValue = list.reduce((sum, item) => sum + (item.quantity * (item.price || 0)), 0);
    return { lowStock, totalValue, count: list.length };
  }, [activeTab, materials, products]);

  const handleOpenModal = (item?: any) => {
    if (item) {
      setEditItem(item);
      setFormData({
        nameAr: item.nameAr,
        nameFr: item.nameFr,
        quantity: item.quantity,
        maxQuantity: item.maxQuantity || 100,
        minLevel: item.minLevel || 10,
        unit: item.unit || 'pcs',
        unitPrice: item.price || 0,
        supplier: item.supplier || ''
      });
    } else {
      setEditItem(null);
      setFormData({ 
          nameAr: '', nameFr: '', quantity: 0, maxQuantity: 100, minLevel: 10, unit: activeTab === 'raw' ? 'kg' : 'plate', unitPrice: 0, supplier: '' 
      });
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    try {
        const newItemBase = {
            nameAr: formData.nameAr, 
            nameFr: formData.nameFr, 
            quantity: Number(formData.quantity), 
            maxQuantity: Number(formData.maxQuantity),
            minLevel: Number(formData.minLevel),
            unit: formData.unit,
            price: Number(formData.unitPrice),
            lastUpdated: new Date().toISOString().split('T')[0]
        };

        if (activeTab === 'raw') {
            if (editItem) {
                setMaterials(materials.map(m => m.id === editItem.id ? { ...m, ...newItemBase, supplier: formData.supplier } : m));
            } else {
                setMaterials([...materials, { ...newItemBase, id: 'm-' + Math.random().toString(36).substr(2, 5), supplier: formData.supplier } as RawMaterial]);
            }
        } else {
            if (editItem) {
                setProducts(products.map(p => p.id === editItem.id ? { ...p, ...newItemBase } : p));
            } else {
                setProducts([...products, { ...newItemBase, id: 'p-' + Math.random().toString(36).substr(2, 5) } as Product]);
            }
        }
        setIsModalOpen(false);
        showNotification(t('success'), 'success');
    } catch (e) {
        showNotification(t('error'), 'error');
    }
  };

  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'هل أنت متأكد من الحذف؟' : 'Are you sure you want to delete?')) {
          if(activeTab === 'raw') setMaterials(materials.filter(m => m.id !== id));
          else setProducts(products.filter(p => p.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  const handleOpenRestock = (item: RawMaterial) => {
      setRestockItem(item);
      setRestockData({ quantity: 0, totalCost: 0 });
      setIsRestockModalOpen(true);
  };

  const handleRestockSubmit = () => {
    if (!restockItem || restockData.quantity <= 0) return;
    setMaterials(materials.map(m => m.id === restockItem.id ? { ...m, quantity: m.quantity + Number(restockData.quantity) } : m));
    setExpenses([{
        id: Math.random().toString(),
        type: 'expense',
        category: 'RawMaterial',
        description: `شراء مواد: ${restockItem.nameAr}`,
        amount: restockData.totalCost,
        date: new Date().toISOString().split('T')[0]
    }, ...expenses]);
    setIsRestockModalOpen(false);
    showNotification(t('success'), 'success');
  };

  const getStockStatus = (item: any) => {
      if (item.quantity <= 0) return { label: isRTL ? 'نفذ' : 'Out', color: 'bg-rose-500/10 text-rose-400 border-rose-500/20' };
      if (item.quantity <= item.minLevel) return { label: isRTL ? 'منخفض' : 'Low', color: 'bg-amber-500/10 text-amber-400 border-amber-500/20' };
