                />
            </div>
            <button onClick={() => handleOpenModal()} className="bg-blue-600 hover:bg-blue-700 text-white p-3.5 rounded-2xl shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2">
                <Plus size={20} />
                <span className="hidden sm:inline font-black text-xs uppercase tracking-widest">{isRTL ? 'إضافة صنف' : 'Add Item'}</span>
            </button>
        </div>
      </div>

      {/* Mini Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
         <div className="bg-slate-900 p-6 rounded-[2rem] border border-white/5 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-blue-500/10 text-blue-500 rounded-2xl flex items-center justify-center"><Package size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{isRTL ? 'إجمالي الأصناف' : 'Total Items'}</p>
                <p className="text-2xl font-black text-white font-mono">{stats.count}</p>
            </div>
         </div>
         <div className="bg-slate-900 p-6 rounded-[2rem] border border-white/5 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-amber-500/10 text-amber-500 rounded-2xl flex items-center justify-center"><AlertTriangle size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{isRTL ? 'أصناف تحت الحد الحرج' : 'Low Stock Alert'}</p>
                <p className="text-2xl font-black text-amber-500 font-mono">{stats.lowStock}</p>
            </div>
         </div>
         <div className="bg-slate-900 p-6 rounded-[2rem] border border-white/5 shadow-sm flex items-center gap-5">
            <div className="w-14 h-14 bg-emerald-500/10 text-emerald-500 rounded-2xl flex items-center justify-center"><ShoppingCart size={28}/></div>
            <div>
                <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">{isRTL ? 'قيمة المخزون التقريبية' : 'Estimated Value'}</p>
                <p className="text-2xl font-black text-emerald-500 font-mono">{stats.totalValue.toLocaleString('en-US')} <small className="text-xs">SAR</small></p>
            </div>
         </div>
      </div>

      {/* Main Inventory Board */}
      <div className="bg-slate-900 rounded-[2.5rem] shadow-sm border border-white/5 overflow-hidden">
        {/* Tabs Selector */}
        <div className="px-8 pt-8 border-b border-white/5 flex items-center justify-between">
            <div className={`flex gap-10 ${isRTL ? 'justify-end' : 'justify-start'}`}>
                <button onClick={() => setActiveTab('raw')} className={`pb-6 text-xs font-black transition-all relative uppercase tracking-widest ${activeTab === 'raw' ? 'text-blue-500' : 'text-slate-500 hover:text-slate-300'}`}>
                    {t('rawMaterials')}
                    {activeTab === 'raw' && <div className="absolute bottom-0 left-0 w-full h-1 bg-blue-500 rounded-full" />}
                </button>
                <button onClick={() => setActiveTab('finished')} className={`pb-6 text-xs font-black transition-all relative uppercase tracking-widest ${activeTab === 'finished' ? 'text-blue-500' : 'text-slate-500 hover:text-slate-300'}`}>
                    {isRTL ? 'المنتجات الجاهزة' : 'Finished Goods'}
                    {activeTab === 'finished' && <div className="absolute bottom-0 left-0 w-full h-1 bg-blue-500 rounded-full" />}
                </button>
            </div>
            <div className="pb-6">
                <Filter size={16} className="text-slate-500" />
