                </div>
                <div>
                    <label className={labelClass}>Nom (FR)</label>
                    <input type="text" value={formData.nameFr} onChange={(e) => setFormData({...formData, nameFr: e.target.value})} className={inputClass} placeholder="Ex: Papier" />
