                </div>
            </div>

            {activeTab === 'raw' && (
                <div>
                    <label className={labelClass}>{isRTL ? 'المورد الافتراضي' : 'Default Supplier'}</label>
                    <input type="text" value={formData.supplier} onChange={(e) => setFormData({...formData, supplier: e.target.value})} className={inputClass} placeholder="Supplier Name" />
                </div>
            )}

            <button onClick={handleSave} className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black shadow-xl shadow-blue-500/20 active:scale-95 transition-all">
                {isRTL ? 'حفظ الصنف' : 'Save Item'}
            </button>
         </div>
      </Modal>

      {/* Restock Purchase Modal */}
      <Modal isOpen={isRestockModalOpen} onClose={() => setIsRestockModalOpen(false)} title={isRTL ? 'شراء توريد جديد' : 'Restock Material'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-white/10">
          <div className="space-y-6">
              <div className="p-6 bg-black/20 rounded-2xl text-white">
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">Target Material</p>
                  <h4 className="text-xl font-black">{isRTL ? restockItem?.nameAr : restockItem?.nameFr}</h4>
                  <p className="text-xs text-emerald-400 font-bold mt-1">Default Price: {restockItem?.price} SAR / {restockItem?.unit}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className={labelClass}>{isRTL ? 'الكمية المضافة' : 'Quantity Added'}</label>
                    <input type="number" value={restockData.quantity} onChange={(e) => setRestockData({...restockData, quantity: Number(e.target.value), totalCost: Number(e.target.value) * (restockItem?.price || 0)})} className={inputClass} />
                  </div>
                  <div>
                    <label className={labelClass}>{isRTL ? 'إجمالي التكلفة (SAR)' : 'Total Cost'}</label>
                    <input type="number" value={restockData.totalCost} onChange={(e) => setRestockData({...restockData, totalCost: Number(e.target.value)})} className={inputClass} />
