import React, { useState } from 'react';
import { Package, Plus, Factory, MinusCircle, Box, Droplets, Palette, TrendingUp, AlertCircle } from 'lucide-react';
import { Language, Product, RawMaterial } from '../types';
import { TRANSLATIONS } from '../constants';

interface ProductionProps {
  lang: Language;
  products: Product[];
  setProducts: (p: Product[]) => void;
  materials: RawMaterial[];
  setMaterials: (m: RawMaterial[]) => void;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Production: React.FC<ProductionProps> = ({ lang, products, setProducts, materials, setMaterials, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  const [prodProductId, setProdProductId] = useState('');
  const [prodQuantity, setProdQuantity] = useState('');

  // Quick consumption states
  const [consMaterialId, setConsMaterialId] = useState('');
  const [consQuantity, setConsQuantity] = useState('');

  const handleSaveProduction = () => {
    if (!prodProductId || !prodQuantity || Number(prodQuantity) <= 0) {
      showNotification(isRTL ? 'يرجى إدخال كمية صحيحة' : 'Please enter valid quantity', 'error');
      return;
    }

    // Logic for auto-consumption (Optional: can be expanded based on a fixed recipe)
    // For now, we update the product quantity
    setProducts(products.map(p => p.id === prodProductId ? { ...p, quantity: p.quantity + Number(prodQuantity) } : p));
    setProdProductId(''); 
    setProdQuantity('');
    showNotification(t('success'), 'success');
  };

  const handleSaveConsumption = () => {
    if (!consMaterialId || !consQuantity || Number(consQuantity) <= 0) {
      showNotification(isRTL ? 'يرجى اختيار مادة وكمية' : 'Please select material and quantity', 'error');
      return;
    }
    const mat = materials.find(m => m.id === consMaterialId);
    if (mat && mat.quantity < Number(consQuantity)) {
        showNotification(t('insufficientRaw'), 'error');
        return;
    }
    setMaterials(materials.map(m => m.id === consMaterialId ? { ...m, quantity: m.quantity - Number(consQuantity) } : m));
    setConsMaterialId(''); 
    setConsQuantity('');
    showNotification(t('success'), 'success');
  };

  const inputClass = "w-full border border-white/5 bg-slate-800 text-white rounded-2xl p-4 focus:border-blue-500 outline-none transition-all font-black text-center font-mono text-lg";
  const labelClass = "block text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-3 text-center";

