        <div className="flex items-center gap-3">
            <div className="h-8 w-1.5 bg-blue-600 rounded-full"></div>
            <h3 className="text-xl font-black text-white">{isRTL ? 'تسجيل إنتاج الأطباق الجاهزة' : 'Register Finished Goods'}</h3>
