import React, { useState } from 'react';
import { Plus, Printer, Trash2, ChevronDown, MoreHorizontal, X } from 'lucide-react';
import { Language, Order, OrderStatus, Customer, Product, Expense } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface OrdersProps {
  lang: Language;
  customers: Customer[];
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Orders: React.FC<OrdersProps> = ({ lang, customers, orders, setOrders, products, setProducts, setExpenses, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showInvoice, setShowInvoice] = useState<Order | null>(null);

  const [formData, setFormData] = useState({ 
    customerId: '', productId: '', quantity: 0, status: OrderStatus.PENDING, expectedDeliveryDate: ''
  });

  const recordIncome = (order: Order) => {
      const displayDesc = lang === Language.AR ? `دخل فاتورة مبيعات رقم #${order.id}` : `Sales Invoice Revenue #${order.id}`;
      const newIncome: Expense = {
          id: Math.random().toString(),
          type: 'income',
          category: 'Sales',
          description: displayDesc,
          amount: order.totalAmount,
          date: order.date
      };
      setExpenses(prev => [newIncome, ...prev]);
  };

  const handleSaveOrder = () => {
    const customer = customers.find(c => c.id === formData.customerId);
    const product = products.find(p => p.id === formData.productId);
    if (!customer || !product || formData.quantity <= 0) return;
    const total = product.price * formData.quantity;
    const newOrder: Order = {
        id: Math.random().toString(36).substr(2, 6).toUpperCase(),
        customerId: customer.id, customerName: customer.name,
        totalAmount: total, date: new Date().toISOString().split('T')[0],
        status: formData.status,
        items: [{ productId: product.id, productName: lang === Language.AR ? product.nameAr : product.nameFr, quantity: formData.quantity, unitPrice: product.price, total: total }]
    };
    setOrders(prev => [newOrder, ...prev]);
    if (formData.status === OrderStatus.COMPLETED) recordIncome(newOrder);
    setIsModalOpen(false);
    showNotification(t('success'), 'success');
  };

  const handleStatusChange = (id: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === id ? { ...o, status: newStatus } : o));
    showNotification(t('success'), 'success');
  };

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.COMPLETED: return 'bg-emerald-500/10 text-emerald-400';
      case OrderStatus.PROCESSING: return 'bg-blue-500/10 text-blue-400';
      case OrderStatus.PENDING: return 'bg-amber-500/10 text-amber-400';
      default: return 'bg-slate-800 text-slate-400';
    }
  };

  const SmallCurrency = ({ val }: { val: number }) => (
      <span className="font-mono font-bold text-white flex items-center gap-1">
          <small className="text-[10px] text-slate-500 font-bold uppercase">SAR</small>
          {val.toLocaleString('en-US')}
      </span>
  );

  const inputClass = "w-full border border-white/5 bg-slate-800 text-white rounded-xl p-3 font-mono font-bold text-center";

  return (
    <div className="space-y-8 animate-fade-in-up" onClick={() => setActiveMenuId(null)}>
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black text-white tracking-tight">{isRTL ? 'المبيعات والطلبات' : 'Sales & Orders'}</h2>
        <button onClick={(e) => { e.stopPropagation(); setIsModalOpen(true); }} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl transition-all text-sm font-black shadow-lg shadow-blue-500/20">
            <Plus size={18} /><span>{isRTL ? 'طلب جديد' : 'New Order'}</span>
        </button>
      </div>

      <div className="bg-slate-900 rounded-[2rem] shadow-sm border border-white/5 overflow-hidden">
        <div className="p-8 pb-0">
            <h3 className="text-xl font-black text-white mb-6">{isRTL ? 'سجل العمليات' : 'Orders Log'}</h3>
        </div>

        <div className="overflow-x-auto p-4 md:p-8">
            <table className="w-full text-right border-collapse">
                <thead className="bg-slate-900 border-b border-white/5">
                  <tr className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    <th className="px-6 py-4">{isRTL ? 'العميل' : 'Customer'}</th>
                    <th className="px-6 py-4">{isRTL ? 'المبلغ' : 'Amount'}</th>
                    <th className="px-6 py-4">{isRTL ? 'الحالة' : 'Status'}</th>
                    <th className="px-6 py-4">{isRTL ? 'إجراءات' : 'Actions'}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {orders.map((order) => (
                    <tr key={order.id} className="hover:bg-white/5 transition-colors group">
                      <td className="px-6 py-6 text-sm font-bold text-slate-300">{order.customerName}</td>
                      <td className="px-6 py-6">
                        <SmallCurrency val={order.totalAmount} />
                      </td>
                      <td className="px-6 py-6">
                          <div className="relative inline-block">
                             <select value={order.status} onChange={(e) => handleStatusChange(order.id, e.target.value as OrderStatus)} className={`appearance-none cursor-pointer pl-3 pr-8 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest border-0 focus:ring-2 focus:ring-blue-500 ${getStatusColor(order.status)}`}>
                                <option value={OrderStatus.COMPLETED}>{isRTL ? 'مكتمل' : 'Completed'}</option>
                                <option value={OrderStatus.PENDING}>{isRTL ? 'انتظار' : 'Pending'}</option>
                                <option value={OrderStatus.PROCESSING}>{isRTL ? 'تنفيذ' : 'Processing'}</option>
                                <option value={OrderStatus.CANCELLED}>{isRTL ? 'ملغي' : 'Cancelled'}</option>
                             </select>
                             <div className={`pointer-events-none absolute inset-y-0 ${isRTL ? 'left-0 pl-2' : 'right-0 pr-2'} flex items-center px-2 text-slate-400`}><ChevronDown size={10} /></div>
                          </div>
                      </td>
                      <td className="px-6 py-6 relative">
                         <button onClick={(e) => { e.stopPropagation(); setActiveMenuId(activeMenuId === order.id ? null : order.id); }} className="p-2 text-slate-500 hover:text-white rounded-full transition-all"><MoreHorizontal size={20} /></button>
                         {activeMenuId === order.id && (
                               <div className={`absolute z-20 ${isRTL ? 'left-8' : 'right-8'} top-8 w-48 bg-black rounded-2xl shadow-2xl border border-white/10 py-2 overflow-hidden animate-in fade-in zoom-in duration-200 text-left`}>
                                   <button onClick={() => setShowInvoice(order)} className="w-full px-5 py-3 text-xs font-bold text-white hover:bg-white/10 flex items-center gap-3"><Printer size={14} /> {t('printInvoice')}</button>
                                   <button onClick={() => setOrders(orders.filter(o => o.id !== order.id))} className="w-full px-5 py-3 text-xs font-bold text-rose-500 hover:bg-rose-500/10 flex items-center gap-3"><Trash2 size={14} /> {t('delete')}</button>
                               </div>
                           )}
                      </td>
                    </tr>
                  ))}
                </tbody>
            </table>
        </div>
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={isRTL ? 'تسجيل طلبية مبيعات' : 'Register Sales Order'} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-white/10">
        <div className="space-y-4">
          <div><label className="block text-xs font-black text-slate-500 uppercase mb-1.5">{t('customer')}</label><select value={formData.customerId} onChange={(e) => setFormData({...formData, customerId: e.target.value})} className="w-full border border-white/5 bg-slate-800 text-white rounded-xl p-3 font-bold"><option value="">{t('selectCustomer')}</option>{customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></div>
          <div><label className="block text-xs font-black text-slate-500 uppercase mb-1.5">{t('finishedGoods')}</label><select value={formData.productId} onChange={(e) => setFormData({...formData, productId: e.target.value})} className="w-full border border-white/5 bg-slate-800 text-white rounded-xl p-3 font-bold"><option value="">{t('selectProduct')}</option>{products.map(p => <option key={p.id} value={p.id}>{lang === Language.AR ? p.nameAr : p.nameFr}</option>)}</select></div>
          <div><label className="block text-xs font-black text-slate-500 uppercase mb-1.5">{t('quantity')}</label><input type="number" value={formData.quantity} onChange={(e) => setFormData({...formData, quantity: Number(e.target.value)})} className={inputClass} placeholder="0" /></div>
          <div className="pt-4 flex justify-end gap-2"><button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-xs font-black text-slate-500 hover:text-white">{t('cancel')}</button><button onClick={handleSaveOrder} className="px-10 py-3 bg-blue-600 text-white rounded-xl font-black shadow-lg shadow-blue-500/20 hover:bg-blue-700 transition-all uppercase tracking-widest">{t('save')}</button></div>
        </div>
      </Modal>
    </div>
  );
};

export default Orders;

import React, { useState } from 'react';
import { DollarSign, TrendingDown, TrendingUp, Plus, Trash2 } from 'lucide-react';
import { Language, Expense, Order, OrderStatus } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface FinanceProps {
  lang: Language;
  expenses: Expense[];
  setExpenses: (e: Expense[]) => void;
  orders: Order[];
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Finance: React.FC<FinanceProps> = ({ lang, expenses, setExpenses, orders, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حسابات الإجماليات (Totals Calculation)
  // =========================================
  const totalIncome = expenses.filter(e => e.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
  const totalExpenses = expenses.filter(e => e.type === 'expense').reduce((acc, curr) => acc + curr.amount, 0);
  const netProfit = totalIncome - totalExpenses;

  // =========================================
  // حالة البيانات (State)
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newExpense, setNewExpense] = useState({ description: '', amount: 0, category: 'Utility', customType: '' });

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // إضافة مصروف جديد
  const handleAddExpense = () => {
      try {
        if (newExpense.amount <= 0 || !newExpense.description) {
            showNotification(isRTL ? 'بيانات ناقصة' : 'Missing data', 'error');
            return;
        }

        const finalDescription = newExpense.category === 'Other' && newExpense.customType 
            ? `${newExpense.customType} - ${newExpense.description}` 
            : newExpense.description;

        const exp: Expense = {
            id: Math.random().toString(),
            type: 'expense',
            date: new Date().toISOString().split('T')[0],
            description: finalDescription,
            amount: Number(newExpense.amount),
            category: newExpense.category as any
        };
        setExpenses([exp, ...expenses]);
        setIsModalOpen(false);
        setNewExpense({ description: '', amount: 0, category: 'Utility', customType: '' });
        showNotification(t('success'), 'success');
      } catch(e) {
          showNotification(t('error'), 'error');
      }
  }

  // حذف مصروف
  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'هل أنت متأكد من حذف هذا السجل المالي؟' : 'Are you sure you want to delete this record?')) {
          setExpenses(expenses.filter(e => e.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  const inputClass = "w-full border border-white/5 bg-slate-800 text-white rounded-xl p-3 focus:border-blue-500 outline-none transition-all font-bold placeholder:text-slate-500";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5";

  return (
    <div className="space-y-6">
      {/* الترويسة */}
      <div className="flex justify-between items-center">
        <h2 className={`text-2xl font-black text-white ${isRTL ? 'font-cairo' : 'font-sans'}`}>
          {t('finance')}
        </h2>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white px-5 py-2.5 rounded-xl transition-all text-sm font-black shadow-lg shadow-red-500/20"
        >
          <Plus size={18} />
          <span>{t('addExpense')}</span>
        </button>
      </div>

      {/* البطاقات الإحصائية */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-slate-900 p-6 rounded-3xl border border-white/5 shadow-sm flex items-center justify-between">
            <div><p className="text-[10px] text-slate-500 font-black uppercase mb-1">{t('income')}</p><h3 className="text-2xl font-black text-emerald-500 font-mono">{totalIncome.toLocaleString()} SAR</h3></div>
            <div className="p-3 bg-emerald-500/10 text-emerald-500 rounded-2xl"><TrendingUp size={24} /></div>
        </div>
        <div className="bg-slate-900 p-6 rounded-3xl border border-white/5 shadow-sm flex items-center justify-between">
            <div><p className="text-[10px] text-slate-500 font-black uppercase mb-1">{t('expenses')}</p><h3 className="text-2xl font-black text-rose-500 font-mono">{totalExpenses.toLocaleString()} SAR</h3></div>
            <div className="p-3 bg-rose-500/10 text-rose-500 rounded-2xl"><TrendingDown size={24} /></div>
        </div>
        <div className="bg-slate-900 p-6 rounded-3xl border border-white/5 shadow-sm flex items-center justify-between">
            <div><p className="text-[10px] text-slate-500 font-black uppercase mb-1">{t('netProfit')}</p><h3 className="text-2xl font-black text-blue-500 font-mono">{netProfit.toLocaleString()} SAR</h3></div>
            <div className="p-3 bg-blue-500/10 text-blue-500 rounded-2xl"><DollarSign size={24} /></div>
        </div>
      </div>

      {/* جدول العمليات المالية */}
      <div className="bg-slate-900 rounded-3xl shadow-sm border border-white/5 overflow-hidden">
        <table className="w-full text-right border-collapse">
            <thead className="bg-black/20 border-b border-white/5">
              <tr>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t('date')}</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t('category')}</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t('description')}</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t('amount')}</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5 font-mono">
                {expenses.map((exp) => (
                    <tr key={exp.id} className="hover:bg-white/5 transition-colors group">
                        <td className="px-6 py-4 text-xs text-slate-400">{exp.date}</td>
                        <td className="px-6 py-4 text-xs font-bold text-slate-200">{exp.category}</td>
                        <td className="px-6 py-4 text-xs text-slate-400">{exp.description}</td>
                        <td className={`px-6 py-4 text-sm font-black ${exp.type === 'income' ? 'text-emerald-400' : 'text-rose-400'}`}>
                            {exp.type === 'income' ? '+' : '-'}{exp.amount.toLocaleString()}
                        </td>
                        <td className="px-6 py-4 text-center">
                            <button onClick={() => handleDelete(exp.id)} className="text-slate-500 hover:text-rose-500 transition-colors">
                                <Trash2 size={16} />
                            </button>
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
      </div>

       {/* مودال إضافة مصروف */}
