          <div><label className={labelClass}>{t('description')}</label><input type="text" className={inputClass} value={newExpense.description} onChange={(e) => setNewExpense({...newExpense, description: e.target.value})} /></div>
          <div><label className={labelClass}>{t('amount')}</label><input type="number" className={inputClass} value={newExpense.amount} onChange={(e) => setNewExpense({...newExpense, amount: Number(e.target.value)})} /></div>
