import React, { useState } from 'react';
import { Search, Plus, UserPlus, DollarSign, Wallet, Trash2, Edit } from 'lucide-react';
import { Language, Staff } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface StaffProps {
  lang: Language;
  staff: Staff[];
  setStaff: (s: Staff[]) => void;
  onPaySalary: (id: string) => void;
  onRequestAdvance: (id: string, amount: number) => void;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const StaffView: React.FC<StaffProps> = ({ lang, staff, setStaff, onPaySalary, onRequestAdvance, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // =========================================
  // حالة المودالات والتحرير
  // =========================================
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAdvanceModalOpen, setIsAdvanceModalOpen] = useState(false);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [advanceAmount, setAdvanceAmount] = useState(0);
  const [editMode, setEditMode] = useState(false);

  // حالة النموذج (إضافة/تعديل)
  const [formData, setFormData] = useState({ id: '', name: '', roleAr: '', roleFr: '', salary: 0 });

  // =========================================
  // دوال المعالجة (Handlers)
  // =========================================

  // فتح المودال للإضافة
  const openAddModal = () => {
      setEditMode(false);
      setFormData({ id: '', name: '', roleAr: '', roleFr: '', salary: 0 });
      setIsModalOpen(true);
  };

  // فتح المودال للتعديل
  const openEditModal = (employee: Staff) => {
      setEditMode(true);
      setFormData({ 
          id: employee.id, 
          name: employee.name, 
          roleAr: employee.roleAr, 
          roleFr: employee.roleFr, 
          salary: employee.salary 
      });
      setIsModalOpen(true);
  };

  // حفظ البيانات (إضافة أو تعديل)
  const handleSaveStaff = () => {
    try {
        if (!formData.name || formData.salary <= 0) {
            showNotification(isRTL ? 'بيانات غير مكتملة' : 'Incomplete data', 'error');
            return;
        }

        if (editMode) {
            // منطق التعديل
            const updatedStaff = staff.map(s => s.id === formData.id ? { ...s, ...formData } : s);
            setStaff(updatedStaff);
            showNotification(t('success'), 'success');
        } else {
            // منطق الإضافة
            const newStaff: Staff = {
                id: Math.random().toString(36).substr(2, 9),
                name: formData.name,
                roleAr: formData.roleAr,
                roleFr: formData.roleFr,
                salary: Number(formData.salary),
                lastPaymentDate: '-',
                advanceTaken: 0,
                loginCount: 0,
                loginHistory: []
            };
            setStaff([...staff, newStaff]);
            showNotification(t('success'), 'success');
        }
        setIsModalOpen(false);
    } catch(e) {
        showNotification(t('error'), 'error');
    }
  };

  // حذف موظف
  const handleDelete = (id: string) => {
      if(confirm(isRTL ? 'هل أنت متأكد من حذف هذا الموظف؟' : 'Are you sure you want to delete this employee?')) {
          setStaff(staff.filter(s => s.id !== id));
          showNotification(t('success'), 'success');
      }
  };

  // طلب سلفة
  const handleRequestAdvance = () => {
      if(!selectedStaffId || advanceAmount <= 0) return;
      // تحديث قيمة السلفة للموظف
      setStaff(staff.map(s => s.id === selectedStaffId ? { ...s, advanceTaken: s.advanceTaken + Number(advanceAmount) } : s));
      setIsAdvanceModalOpen(false);
      setAdvanceAmount(0);
      setSelectedStaffId(null);
      showNotification(t('success'), 'success');
  }

  const inputClass = "w-full border border-white/5 bg-slate-800 text-white rounded-xl p-3 focus:border-blue-500 outline-none transition-all font-bold placeholder:text-slate-500";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5";

  return (
    <div className="space-y-6">
      {/* الترويسة */}
      <div className="flex justify-between items-center">
        <h2 className={`text-2xl font-black text-white ${isRTL ? 'font-cairo' : 'font-sans'}`}>
          {t('staff')}
        </h2>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl transition-all text-sm font-black shadow-lg shadow-blue-500/20"
        >
          <UserPlus size={18} />
          <span>{lang === Language.AR ? 'موظف جديد' : 'Nouvel employé'}</span>
        </button>
      </div>

      {/* جدول الموظفين */}
      <div className="bg-slate-900 rounded-3xl shadow-sm border border-white/5 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-black/20 border-b border-white/5">
              <tr>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('name')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('role')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('salary')}</th>
                 <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('advance')}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{lang === Language.AR ? 'آخر راتب' : 'Dernier paiement'}</th>
                <th className={`px-6 py-4 text-[10px] font-black text-slate-500 uppercase tracking-widest ${isRTL ? 'text-right' : 'text-left'}`}>{t('actions')}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {staff.map((emp: Staff) => (
                <tr key={emp.id} className="hover:bg-white/5 transition-colors">
                  <td className={`px-6 py-4 text-sm font-bold text-white ${isRTL ? 'text-right' : 'text-left'}`}>{emp.name}</td>
                  <td className={`px-6 py-4 text-sm text-slate-400 ${isRTL ? 'text-right' : 'text-left'}`}>
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-black uppercase bg-blue-500/10 text-blue-400">
                      {lang === Language.AR ? emp.roleAr : emp.roleFr}
                    </span>
                  </td>
                  <td className={`px-6 py-4 text-sm text-slate-300 font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.salary.toLocaleString()} SAR</td>
                  <td className={`px-6 py-4 text-sm text-red-400 font-black font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.advanceTaken > 0 ? `-${emp.advanceTaken.toLocaleString()}` : '-'}</td>
                  <td className={`px-6 py-4 text-sm text-slate-500 font-mono ${isRTL ? 'text-right' : 'text-left'}`}>{emp.lastPaymentDate}</td>
                  <td className="px-6 py-4 text-sm flex gap-2">
                    <button onClick={() => openEditModal(emp)} className="p-2 text-blue-500 hover:bg-blue-500/10 rounded-xl transition-all" title={t('edit')}><Edit size={18} /></button>
                    <button onClick={() => handleDelete(emp.id)} className="p-2 text-rose-500 hover:bg-rose-500/10 rounded-xl transition-all" title={t('delete')}><Trash2 size={18} /></button>
                    <button onClick={() => onPaySalary(emp.id)} className="p-2 text-green-500 hover:bg-green-500/10 rounded-xl transition-all" title={t('paySalary')}><DollarSign size={18} /></button>
                    <button onClick={() => { setSelectedStaffId(emp.id); setIsAdvanceModalOpen(true); }} className="p-2 text-orange-500 hover:bg-orange-500/10 rounded-xl transition-all" title={t('requestAdvance')}><Wallet size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* مودال الإضافة/التعديل */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editMode ? (isRTL ? 'تعديل بيانات' : 'Edit Staff') : (lang === Language.AR ? 'موظف جديد' : 'Nouvel employé')} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-white/10">
        <div className="space-y-4">
          <div><label className={labelClass}>{t('name')}</label><input type="text" className={inputClass} value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} /></div>
          <div><label className={labelClass}>Role (Ar)</label><input type="text" className={inputClass} value={formData.roleAr} onChange={(e) => setFormData({...formData, roleAr: e.target.value})} /></div>
          <div><label className={labelClass}>Role (Fr)</label><input type="text" className={inputClass} value={formData.roleFr} onChange={(e) => setFormData({...formData, roleFr: e.target.value})} /></div>
           <div><label className={labelClass}>{t('salary')}</label><input type="number" className={inputClass} value={formData.salary} onChange={(e) => setFormData({...formData, salary: Number(e.target.value)})} /></div>
          <div className="pt-4 flex justify-end gap-2"><button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-xs font-black text-slate-500 hover:text-white">{t('cancel')}</button><button onClick={handleSaveStaff} className="px-8 py-3 text-xs bg-blue-600 text-white rounded-xl font-black shadow-lg shadow-blue-500/20">{t('save')}</button></div>
        </div>
      </Modal>

      {/* مودال السلفة */}
      <Modal isOpen={isAdvanceModalOpen} onClose={() => setIsAdvanceModalOpen(false)} title={t('requestAdvance')} isRTL={isRTL} contentClassName="bg-slate-900 text-white border border-white/10">
           <div className="space-y-4">
               <div><label className={labelClass}>{t('amount')}</label><input type="number" className={inputClass} value={advanceAmount} onChange={(e) => setAdvanceAmount(Number(e.target.value))} /></div>
              <div className="pt-4 flex justify-end gap-2"><button onClick={() => setIsAdvanceModalOpen(false)} className="px-6 py-3 text-xs font-black text-slate-500 hover:text-white">{t('cancel')}</button><button onClick={handleRequestAdvance} className="px-8 py-3 text-xs bg-blue-600 text-white rounded-xl font-black shadow-lg shadow-blue-500/20">{t('save')}</button></div>
           </div>
      </Modal>
    </div>
  );
};

export default StaffView;

import React, { useState } from 'react';
import { Search, Plus, Filter, Edit2, Trash2, User } from 'lucide-react';
import { Language, Customer } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface CustomersProps {
  lang: Language;
  customers: Customer[];
  setCustomers: (customers: Customer[]) => void;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Customers: React.FC<CustomersProps> = ({ lang, customers, setCustomers, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;
  const isRTL = lang === Language.AR;

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editItem, setEditItem] = useState<Customer | null>(null);
  const [formData, setFormData] = useState({ name: '', phone: '', email: '', address: '' });

  const handleOpenModal = (item?: Customer) => {
    if (item) {
      setEditItem(item);
      setFormData({
        name: item.name,
        phone: item.phone,
        email: item.email,
        address: item.address
      });
    } else {
      setEditItem(null);
      setFormData({ name: '', phone: '', email: '', address: '' });
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    try {
        if (editItem) {
        setCustomers(customers.map(c => c.id === editItem.id ? { ...c, ...formData } : c));
        } else {
        const newItem: Customer = {
            id: Math.random().toString(36).substr(2, 9),
            ...formData
        };
        setCustomers([...customers, newItem]);
        }
        setIsModalOpen(false);
        showNotification(t('success'), 'success');
    } catch (e) {
        showNotification(t('error'), 'error');
    }
  };

  const handleDelete = (id: string) => {
    if (confirm(lang === Language.AR ? 'هل أنت متأكد من حذف هذا الزبون؟' : 'Êtes-vous sûr de vouloir supprimer ce client ?')) {
      setCustomers(customers.filter(c => c.id !== id));
      showNotification(t('success'), 'success');
    }
