              {customers.map((customer) => (
                <tr key={customer.id} className="hover:bg-white/5 transition-colors">
                  <td className={`px-6 py-4 text-sm font-medium text-white flex items-center gap-3 ${isRTL ? 'text-right' : 'text-left'}`}>
                    <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-slate-400">
                        <User size={16} />
                    </div>
                    {customer.name}
                  </td>
                  <td className={`px-6 py-4 text-sm text-slate-400 ${isRTL ? 'text-right' : 'text-left'}`}>{customer.phone}</td>
                  <td className={`px-6 py-4 text-sm text-slate-400 ${isRTL ? 'text-right' : 'text-left'}`}>{customer.email}</td>
                  <td className={`px-6 py-4 text-sm text-slate-400 ${isRTL ? 'text-right' : 'text-left'}`}>{customer.address}</td>
                  <td className={`px-6 py-4 text-sm flex items-center gap-3 ${isRTL ? 'justify-start' : 'justify-start'}`}>
                     <button onClick={() => handleOpenModal(customer)} className="text-blue-500 hover:text-blue-400 transition-colors"><Edit2 size={18} /></button>
                     <button onClick={() => handleDelete(customer.id)} className="text-red-500 hover:text-red-400 transition-colors"><Trash2 size={18} /></button>
