            <label className="block text-sm font-medium text-slate-400 mb-1">{t('phone')}</label>
            <input 
              type="text" 
              className="w-full border border-white/5 bg-slate-800 text-white rounded-md p-2"
              value={formData.phone}
              onChange={(e) => setFormData({...formData, phone: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">{t('email')}</label>
            <input 
              type="email" 
              className="w-full border border-white/5 bg-slate-800 text-white rounded-md p-2"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">{t('address')}</label>
            <textarea
              className="w-full border border-white/5 bg-slate-800 text-white rounded-md p-2"
              value={formData.address}
              onChange={(e) => setFormData({...formData, address: e.target.value})}
            />
          </div>

          <div className="pt-4 flex justify-end gap-2">
            <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-sm text-slate-500 hover:text-white rounded-md">
              {t('cancel')}
            </button>
            <button onClick={handleSave} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700">
              {t('save')}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

