import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { TrendingUp, Package, AlertTriangle, Wallet, Calendar as CalendarIcon, ArrowUpCircle, ArrowDownCircle } from 'lucide-react';
import { Language, Order, Staff, Expense, RawMaterial, Product } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface DashboardProps {
  lang: Language;
  setCurrentView: (view: string) => void;
  orders?: Order[];
  staff?: Staff[];
  expenses?: Expense[];
  materials?: RawMaterial[];
  products?: Product[];
}

const Dashboard: React.FC<DashboardProps> = ({ lang, setCurrentView, orders = [], expenses = [], materials = [], products = [] }) => {
  const t = (key: string) => TRANSLATIONS[key][lang];
  const isRTL = lang === Language.AR;
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);

  // --- Calculations for Real Data ---

  // 1. Finance Card Data
  const totalIncome = expenses.filter(e => e.type === 'income').reduce((sum, e) => sum + e.amount, 0);
  const totalExpenses = expenses.filter(e => e.type === 'expense').reduce((sum, e) => sum + e.amount, 0);
  const netProfit = totalIncome - totalExpenses;

  // 2. Chart Data: Daily Performance (Last 7 Days)
  const dailyData = useMemo(() => {
    const data = [];
    const today = new Date();
    for (let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(today.getDate() - i);
        const dateStr = d.toISOString().split('T')[0];

        // Sum income/expenses for this day
        const dayIncome = expenses
            .filter(e => e.type === 'income' && e.date === dateStr)
            .reduce((sum, e) => sum + e.amount, 0);

        const dayExpense = expenses
            .filter(e => e.type === 'expense' && e.date === dateStr)
            .reduce((sum, e) => sum + e.amount, 0);

        const dayName = d.toLocaleDateString(lang === Language.AR ? 'ar-SA' : 'fr-FR', { weekday: 'short' });

        data.push({
            name: dayName,
            income: dayIncome,
            expense: dayExpense
        });
    }
    return data;
  }, [expenses, lang]);

  // 3. Chart Data: Monthly Overview
  const monthlyData = useMemo(() => {
      const data: {[key: string]: {name: string, income: number, expense: number}} = {};

      expenses.forEach(e => {
          const d = new Date(e.date);
          const monthKey = `${d.getFullYear()}-${d.getMonth()}`;
          const monthName = d.toLocaleDateString(lang === Language.AR ? 'ar-SA' : 'fr-FR', { month: 'short' });

          if (!data[monthKey]) {
              data[monthKey] = { name: monthName, income: 0, expense: 0 };
          }

          if (e.type === 'income') data[monthKey].income += e.amount;
          else data[monthKey].expense += e.amount;
      });

      return Object.values(data);
  }, [expenses, lang]);


  const StatCard = ({ title, value, icon, color, subtext, onClick, customContent }: any) => (
    <div 
        onClick={onClick}
        className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-start justify-between cursor-pointer hover:shadow-md hover:-translate-y-1 transition-all duration-200"
    >
      <div>
        <p className={`text-sm text-slate-500 mb-1 ${isRTL ? 'font-cairo' : 'font-sans'}`}>{title}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
        {customContent ? customContent : (
             <p className={`text-xs mt-2 ${color.text} flex items-center gap-1`}>
                {subtext}
             </p>
        )}
      </div>
      <div className={`p-3 rounded-lg ${color.bg} ${color.iconText}`}>
        {icon}
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className={`text-2xl font-bold text-slate-800 ${isRTL ? 'font-cairo' : 'font-sans'}`}>
          {t('dashboard')}
        </h2>
        <button 
          onClick={() => setIsCalendarOpen(true)}
          className="text-sm text-slate-600 bg-white hover:bg-blue-50 hover:text-blue-600 px-3 py-1 rounded-full border shadow-sm flex items-center gap-2 transition-colors"
        >
          <CalendarIcon size={16} />
          {new Date().toLocaleDateString(lang === Language.AR ? 'ar-SA' : 'fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
        </button>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title={t('totalProduction')} 
          value="24,500" 
          icon={<Package />} 
          color={{ bg: 'bg-blue-50', iconText: 'text-blue-600', text: 'text-green-600' }}
          subtext="+12% vs last week"
          onClick={() => setCurrentView('production')}
        />
        <StatCard 
          title={t('totalSales')} 
          value={`${totalIncome} SAR`} 
          icon={<TrendingUp />} 
          color={{ bg: 'bg-green-50', iconText: 'text-green-600', text: 'text-green-600' }}
          subtext="Total Revenue"
          onClick={() => setCurrentView('orders')}
        />
        <StatCard 
          title={t('lowStock')} 
          value="2 Items" 
          icon={<AlertTriangle />} 
          color={{ bg: 'bg-amber-50', iconText: 'text-amber-600', text: 'text-red-600' }}
          subtext="Urgent action required"
          onClick={() => setCurrentView('inventory')}
        />

        {/* OPTIMISTIC FINANCE CARD */}
        <StatCard 
          title={t('netProfit')} 
          value={`${netProfit} SAR`} 
          icon={<Wallet />} 
          color={{ bg: 'bg-purple-50', iconText: 'text-purple-600', text: 'text-slate-500' }}
          onClick={() => setCurrentView('finance')}
          customContent={
              <div className="flex gap-4 mt-2">
                  <div className="flex items-center gap-1 text-xs text-green-600 font-bold bg-green-50 px-2 py-1 rounded-full">
                      <ArrowUpCircle size={14} />
                      <span>+{totalIncome}</span>
                  </div>
                  <div className="flex items-center gap-1 text-xs text-red-600 font-bold bg-red-50 px-2 py-1 rounded-full">
                      <ArrowDownCircle size={14} />
                      <span>-{totalExpenses}</span>
                  </div>
              </div>
          }
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* CHART 1: Daily Performance (Income vs Expense) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className={`text-lg font-bold mb-4 ${isRTL ? 'font-cairo' : 'font-sans'}`}>
            {t('dailyPerformance')}
          </h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={dailyData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <defs>
                    <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                    </linearGradient>
                    <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#ef4444" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
                    </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" stroke="#64748b" fontSize={12} />
                <YAxis stroke="#64748b" fontSize={12} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#fff', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Area type="monotone" dataKey="income" stroke="#10b981" strokeWidth={2} fillOpacity={1} fill="url(#colorIncome)" name={t('income')} />
                <Area type="monotone" dataKey="expense" stroke="#ef4444" strokeWidth={2} fillOpacity={1} fill="url(#colorExpense)" name={t('expenses')} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* CHART 2: Monthly Overview (Bar Chart) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className={`text-lg font-bold mb-4 ${isRTL ? 'font-cairo' : 'font-sans'}`}>
            {t('monthlyOverview')}
          </h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={monthlyData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" stroke="#64748b" fontSize={12} />
                <YAxis stroke="#64748b" fontSize={12} />
                <Tooltip 
                  cursor={{ fill: '#f1f5f9' }}
                  contentStyle={{ backgroundColor: '#fff', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="income" fill="#3b82f6" radius={[4, 4, 0, 0]} name={t('income')} />
                <Bar dataKey="expense" fill="#f59e0b" radius={[4, 4, 0, 0]} name={t('expenses')} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Calendar Modal */}
      <Modal
        isOpen={isCalendarOpen}
        onClose={() => setIsCalendarOpen(false)}
        title={t('calendarEvents')}
        isRTL={isRTL}
      >
        <div className="space-y-4">
            <div className="bg-slate-50 p-4 rounded-lg">
                <h4 className="font-bold text-slate-800 mb-2 border-b pb-2 border-slate-200">{t('salaryDate')}</h4>
                <ul className="space-y-2">
                    <li className="flex justify-between text-sm">
                        <span>Upcoming Salary Cycle</span>
                        <span className="font-bold text-blue-600">30th of Month</span>
                    </li>
                </ul>
            </div>
             <div className="bg-slate-50 p-4 rounded-lg">
                <h4 className="font-bold text-slate-800 mb-2 border-b pb-2 border-slate-200">{t('orders')}</h4>
                <ul className="space-y-2 max-h-40 overflow-y-auto">
                    {orders.slice(0, 5).map(o => (
                        <li key={o.id} className="flex justify-between text-sm items-center">
                            <span>#{o.id} - {o.customerName}</span>
                            <span className="text-xs bg-gray-200 px-2 py-1 rounded text-slate-700">{o.date}</span>
                        </li>
                    ))}
                    {orders.length === 0 && <li className="text-sm text-slate-400">No upcoming orders</li>}
                </ul>
            </div>
            <div className="text-center pt-2">
                <button 
                    onClick={() => setIsCalendarOpen(false)}
                    className="text-blue-600 hover:underline text-sm"
                >
                    {t('cancel')}
                </button>
            </div>
        </div>
      </Modal>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  isRTL?: boolean;
  contentClassName?: string;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, isRTL, contentClassName }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center overflow-y-auto overflow-x-hidden bg-black/50 backdrop-blur-sm p-4">
      <div className={`relative w-full max-w-md max-h-full rounded-lg shadow-2xl ${isRTL ? 'text-right' : 'text-left'} ${contentClassName || 'bg-white'}`}>

        {/* Header */}
        <div className={`flex items-center justify-between p-4 border-b rounded-t ${contentClassName?.includes('border') ? 'border-inherit' : ''}`}>
          <h3 className={`text-xl font-semibold ${contentClassName ? '' : 'text-gray-900'}`}>{title}</h3>
          <button
            onClick={onClose}
            type="button"
            className={`ml-auto inline-flex items-center justify-center rounded-lg bg-transparent p-1.5 text-sm ${contentClassName ? 'text-slate-400 hover:bg-white/10 hover:text-white' : 'text-gray-400 hover:bg-gray-200 hover:text-gray-900'}`}
          >
            <X size={20} />
            <span className="sr-only">Close modal</span>
          </button>
        </div>

        {/* Body */}
        <div className="p-6">
          {children}
        </div>

      </div>
    </div>
  );
};

export default Modal;

import React, { useState, useEffect, useCallback } from 'react';
import { Globe, Menu, ArrowLeft } from 'lucide-react';
// استيراد المكونات الفرعية
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Orders from './components/Orders';
import Customers from './components/Customers';
import StaffView from './components/Staff';
import Production from './components/Production';
import Finance from './components/Finance';
import Login from './components/Login';
import Hub from './components/Hub';
import MakhGold from './components/MakhGold';
import GeneralAdmin from './components/GeneralAdmin';
import MosqueManagement from './components/MosqueManagement';
import FarmManagement, { FarmRecord } from './components/FarmManagement';
import AlTaqaddum from './components/AlTaqaddum'; 
import BankPartners from './components/BankPartners';
import Toast from './components/Toast';
// استيراد الأنواع والثوابت
import { Language, Customer, Product, RawMaterial, Order, Staff, Expense, Notification, EntityType, GoldTransaction, Appointment, BankPartner } from './types';
import { TRANSLATIONS, MOCK_CUSTOMERS, MOCK_PRODUCTS, MOCK_RAW_MATERIALS, MOCK_ORDERS, MOCK_STAFF, MOCK_EXPENSES, MOCK_GOLD_TRANSACTIONS, MOCK_APPOINTMENTS } from './constants';

const App: React.FC = () => {
  // =========================================
  // إدارة حالة التطبيق (State Management)
  // =========================================
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [currentEntity, setCurrentEntity] = useState<EntityType>('MASTER');
  const [currentView, setCurrentView] = useState('dashboard');
  const [lang, setLang] = useState<Language>(Language.AR);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);

  // =========================================
  // بيانات النظام (مع التخزين المحلي LocalStorage)
  // =========================================
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('np_customers') || JSON.stringify(MOCK_CUSTOMERS)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('np_products') || JSON.stringify(MOCK_PRODUCTS)));
  const [materials, setMaterials] = useState<RawMaterial[]>(() => JSON.parse(localStorage.getItem('np_materials') || JSON.stringify(MOCK_RAW_MATERIALS)));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('np_orders') || JSON.stringify(MOCK_ORDERS)));
  const [staff, setStaff] = useState<Staff[]>(() => JSON.parse(localStorage.getItem('np_staff') || JSON.stringify(MOCK_STAFF)));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('np_expenses') || JSON.stringify(MOCK_EXPENSES)));
  const [goldTransactions, setGoldTransactions] = useState<GoldTransaction[]>(() => JSON.parse(localStorage.getItem('np_gold_tx') || JSON.stringify(MOCK_GOLD_TRANSACTIONS)));
  const [appointments, setAppointments] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('np_appointments') || JSON.stringify(MOCK_APPOINTMENTS)));

  // Farm Data State
  const [farmData, setFarmData] = useState<FarmRecord[]>(() => {
    const saved = localStorage.getItem('np_farm_data');
    if (saved) return JSON.parse(saved);
    return [{
        id: 'f-init-1',
        type: 'production',
        date: new Date().toISOString().split('T')[0],
        item: 'برسيم (Alfalfa)',
        quantity: 3277, 
        unit: 'Ton',
        unitPrice: 595,
        totalPrice: 1950000,
        notes: 'الإنتاج الجديد 2025 - في إدارة المزرعة',
        season: '2025'
    }];
  });

  // Bank Partners Data
  const [bankPartners, setBankPartners] = useState<BankPartner[]>(() => {
      const saved = localStorage.getItem('np_bank_partners');
      return saved ? JSON.parse(saved) : [];
  });
  const [totalBankProfit, setTotalBankProfit] = useState<number>(() => {
      const saved = localStorage.getItem('np_bank_profit');
      return saved ? Number(saved) : 0;
  });

  const isRTL = lang === Language.AR;
  const t = (key: string) => TRANSLATIONS[key]?.[lang] || key;

  // =========================================
  // حفظ البيانات تلقائياً عند التغيير
  // =========================================
  useEffect(() => {
    localStorage.setItem('np_customers', JSON.stringify(customers));
    localStorage.setItem('np_products', JSON.stringify(products));
    localStorage.setItem('np_materials', JSON.stringify(materials));
    localStorage.setItem('np_orders', JSON.stringify(orders));
    localStorage.setItem('np_staff', JSON.stringify(staff));
    localStorage.setItem('np_expenses', JSON.stringify(expenses));
    localStorage.setItem('np_gold_tx', JSON.stringify(goldTransactions));
    localStorage.setItem('np_appointments', JSON.stringify(appointments));
    localStorage.setItem('np_farm_data', JSON.stringify(farmData));
    localStorage.setItem('np_bank_partners', JSON.stringify(bankPartners));
    localStorage.setItem('np_bank_profit', String(totalBankProfit));
  }, [customers, products, materials, orders, staff, expenses, goldTransactions, appointments, farmData, bankPartners, totalBankProfit]);

  // دالة لعرض الإشعارات
  const showNotification = useCallback((message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
  }, []);

  // دالة تغيير اللغة
  const toggleLanguage = () => setLang(prev => prev === Language.AR ? Language.FR : Language.AR);

  // دالة تسجيل الدخول
  const handleLogin = (user: Staff) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    if (user.allowedEntity && user.allowedEntity !== 'MASTER' && user.allowedEntity !== 'GENERAL_ADMIN') {
        setCurrentEntity(user.allowedEntity);
    } else {
        setCurrentEntity('MASTER');
    }
  };

  // دالة تسجيل الخروج
  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentEntity('MASTER');
  };

  // =========================================
  // التوجيه (Routing) وعرض الصفحات
  // =========================================

  // 1. شاشة تسجيل الدخول
  if (!isLoggedIn) return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Login lang={lang} onLogin={handleLogin} toggleLanguage={toggleLanguage} staff={staff} showNotification={showNotification} />
    </>
  );

  // 2. المركز الرئيسي (HUB)
  if (currentEntity === 'MASTER') return (
    <>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}
      <Hub lang={lang} onSelectEntity={(e) => { setCurrentEntity(e); setCurrentView('dashboard'); }} onLogout={handleLogout} />
    </>
  );

  // 3. إدارة الذهب (عرض خاص)
  if (currentEntity === 'MAKH_GOLD') return (
    <MakhGold 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      goldTransactions={goldTransactions} 
      setGoldTransactions={setGoldTransactions} 
      shareholders={[]} 
      setShareholders={() => {}} 
      showNotification={showNotification} 
    />
  );

  // 4. إدارة المساجد (عرض خاص)
  if (currentEntity === 'MOSQUE') return (
    <MosqueManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification} 
    />
  );

  // 5. إدارة المزرعة (عرض خاص)
  if (currentEntity === 'FARM') return (
    <FarmManagement 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification}
      farmData={farmData}
      setFarmData={setFarmData}
    />
  );

  // 6. شركة التقدم (عرض خاص - جديد)
  if (currentEntity === 'ALTAQADDUM') return (
    <AlTaqaddum 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }} 
      showNotification={showNotification}
    />
  );

  // 7. شركاء المصرف (عرض خاص - جديد)
  if (currentEntity === 'BANK') return (
    <BankPartners 
      lang={lang}
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') setCurrentEntity('MASTER'); else handleLogout(); }}
      showNotification={showNotification}
      partners={bankPartners}
      setPartners={setBankPartners}
      totalPortfolioProfit={totalBankProfit}
      setTotalPortfolioProfit={setTotalBankProfit}
    />
  );

  // 8. الإدارة العامة (عرض خاص)
  if (currentEntity === 'GENERAL_ADMIN') return (
    <GeneralAdmin 
      lang={lang} 
      onLogout={() => { if(currentUser?.allowedEntity === 'MASTER') setCurrentEntity('MASTER'); else handleLogout(); }} 
      expenses={expenses} 
      goldTransactions={goldTransactions} 
      orders={orders} 
      staff={staff} 
      setStaff={setStaff} 
      appointments={appointments} 
      setAppointments={setAppointments} 
      showNotification={showNotification} 
      currentUser={currentUser} 
    />
  );

  // 9. لوحة التحكم الافتراضية للمصنع (FACTORY)
  const renderContent = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard lang={lang} setCurrentView={setCurrentView} orders={orders} staff={staff} expenses={expenses} materials={materials} products={products} />;
      case 'inventory': return <Inventory lang={lang} materials={materials} setMaterials={setMaterials} products={products} setProducts={setProducts} expenses={expenses} setExpenses={setExpenses} showNotification={showNotification} onRestockMaterial={() => {}} />;
      case 'orders': return <Orders lang={lang} customers={customers} orders={orders} setOrders={setOrders} products={products} setProducts={setProducts} setExpenses={setExpenses} showNotification={showNotification} />;
      case 'customers': return <Customers lang={lang} customers={customers} setCustomers={setCustomers} showNotification={showNotification} />;
      case 'staff': return <StaffView lang={lang} staff={staff} setStaff={setStaff} onPaySalary={() => {}} onRequestAdvance={() => {}} showNotification={showNotification} refreshData={() => {}} />;
      case 'production': return <Production lang={lang} products={products} setProducts={setProducts} materials={materials} setMaterials={setMaterials} showNotification={showNotification} />;
      case 'finance': return <Finance lang={lang} expenses={expenses} setExpenses={setExpenses} orders={orders} showNotification={showNotification} />;
      default: return <Dashboard lang={lang} setCurrentView={setCurrentView} />;
    }
  };

  return (
    // Updated Main Layout to Dark Theme
    <div dir={isRTL ? 'rtl' : 'ltr'} className={`flex h-screen bg-[#02040a] text-slate-100 overflow-hidden ${isRTL ? 'font-cairo' : 'font-sans'}`}>
      {notification && <Toast message={notification.message} type={notification.type} onClose={() => setNotification(null)} isRTL={isRTL} />}

      {/* القائمة الجانبية */}
      <Sidebar currentView={currentView} setCurrentView={setCurrentView} lang={lang} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        {/* الشريط العلوي - Dark Mode */}
        <header className="h-20 bg-slate-900/50 backdrop-blur-md border-b border-white/5 flex items-center justify-between px-8 z-10 print:hidden">
          <div className="flex items-center gap-6">
             <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-slate-400 hover:text-white"><Menu size={24} /></button>

             {/* إظهار زر العودة للمركز الرئيسي فقط للإدارة العليا */}
             {(currentUser?.allowedEntity === 'MASTER' || currentUser?.allowedEntity === 'GENERAL_ADMIN') && (
                <button onClick={() => setCurrentEntity('MASTER')} className="flex items-center gap-2 text-slate-400 hover:text-blue-400 font-bold text-sm transition-all">
                  <ArrowLeft size={16} className={isRTL ? 'rotate-180' : ''} />
                  {t('backToHub')}
                </button>
             )}
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden sm:block text-sm text-slate-400 font-bold">
                {lang === Language.AR ? `أهلاً، ${currentUser?.name || 'مستخدم'}` : `Welcome, ${currentUser?.name || 'User'}`}
             </div>
             <button onClick={toggleLanguage} className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white transition-all text-xs font-bold border border-white/5">
               <Globe size={14} />
               {lang === Language.AR ? 'Français' : 'العربية'}
             </button>
             <h2 className="hidden md:flex items-center gap-2 text-sm font-black text-white">
               {t(currentView)}
             </h2>
          </div>
        </header>

        {/* المحتوى الرئيسي - Dark Background */}
        <main className="flex-1 overflow-y-auto p-6 lg:p-10 bg-[#02040a]">
          <div className="max-w-7xl mx-auto h-full">{renderContent()}</div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Plus, Edit2, Trash2, ShoppingCart, AlertCircle } from 'lucide-react';
import { Language, RawMaterial, Product, Expense } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface InventoryProps {
  lang: Language;
  materials: RawMaterial[];
  setMaterials: (m: RawMaterial[]) => void;
  products: Product[];
  setProducts: (p: Product[]) => void;
  expenses: Expense[];
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  showNotification: (msg: string, type: 'success'|'error') => void;
  onRestockMaterial: () => void;
}

const Inventory: React.FC<InventoryProps> = ({ lang, materials, setMaterials, products, setProducts, expenses, setExpenses, showNotification, onRestockMaterial }) => {
  const t = (key: string) => TRANSLATIONS[key][lang];
  const isRTL = lang === Language.AR;
  const [activeTab, setActiveTab] = useState<'raw' | 'finished'>('raw');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isRestockModalOpen, setIsRestockModalOpen] = useState(false);
  const [editItem, setEditItem] = useState<any | null>(null);
  const [restockItem, setRestockItem] = useState<RawMaterial | null>(null);

  const [formData, setFormData] = useState({ 
    nameAr: '', 
    nameFr: '', 
    quantity: 0, 
    maxQuantity: 0,
    unit: 'kg',
    unitPrice: 0,
    supplier: '' 
  });

  const [restockData, setRestockData] = useState({ quantity: 0, totalCost: 0 });

  const handleOpenModal = (item?: any) => {
    if (item) {
      setEditItem(item);
      setFormData({
        nameAr: item.nameAr,
        nameFr: item.nameFr,
        quantity: item.quantity,
        maxQuantity: item.maxQuantity || 0,
        unit: item.unit || 'kg',
        unitPrice: item.price || 0,
        supplier: item.supplier || ''
      });
    } else {
      setEditItem(null);
      setFormData({ 
          nameAr: '', nameFr: '', quantity: 0, maxQuantity: 100, unit: activeTab === 'raw' ? 'kg' : 'plate', unitPrice: 0, supplier: '' 
      });
    }
    setIsModalOpen(true);
  };

  const handleOpenRestock = (item: RawMaterial) => {
      setRestockItem(item);
      setRestockData({ quantity: 0, totalCost: 0 });
      setIsRestockModalOpen(true);
  }

  // تحديث التكلفة الإجمالية تلقائياً بناءً على سعر الوحدة المخزن
  const handleRestockQtyChange = (val: number) => {
      const price = restockItem?.price || 0;
      setRestockData({ quantity: val, totalCost: val * price });
  }

  const handleRestockSubmit = () => {
    if (!restockItem || restockData.quantity <= 0) return;

    try {
      const newQuantity = restockItem.quantity + Number(restockData.quantity);

      // 1. تحديث المخزون محلياً
      setMaterials(materials.map(m => m.id === restockItem.id ? { ...m, quantity: newQuantity } : m));

      // 2. تسجيل المصروف في المالية محلياً
      const newExpense: Expense = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'expense',
        category: 'RawMaterial',
        description: `${lang === Language.AR ? 'شراء/تجديد مخزون' : 'Achat/Réappro'}: ${restockItem.nameAr}`,
        amount: restockData.totalCost,
        date: new Date().toISOString().split('T')[0]
      };

      setExpenses(prev => [newExpense, ...prev]);
      onRestockMaterial(); 

      setIsRestockModalOpen(false);
      showNotification(t('success'), 'success');
    } catch (e) {
      showNotification(t('error'), 'error');
    }
  };

  const handleSave = () => {
    try {
        if (activeTab === 'raw') {
            const newItemData = {
                nameAr: formData.nameAr,
                nameFr: formData.nameFr,
                quantity: Number(formData.quantity),
                maxQuantity: Number(formData.maxQuantity),
                unit: formData.unit,
                price: Number(formData.unitPrice),
                supplier: formData.supplier,
                minLevel: 10,
                lastUpdated: new Date().toISOString().split('T')[0]
            };

            if (editItem) {
                setMaterials(materials.map(m => m.id === editItem.id ? { ...m, ...newItemData } : m));
            } else {
                const newMaterial: RawMaterial = {
                    id: Math.random().toString(36).substr(2, 9),
                    ...newItemData
                };
                setMaterials([...materials, newMaterial]);

                // إذا أضاف كمية أولية، نسجلها كمصروف فوراً
                if (Number(formData.quantity) > 0) {
                    setExpenses(prev => [{
                        id: Math.random().toString(36).substr(2, 9),
                        type: 'expense',
                        category: 'RawMaterial',
                        description: `${lang === Language.AR ? 'رصيد أول المدة' : 'Stock Initial'}: ${formData.nameAr}`,
                        amount: Number(formData.quantity) * Number(formData.unitPrice),
                        date: new Date().toISOString().split('T')[0]
                    }, ...prev]);
                }
            }
        } else {
            const newItemData = {
                nameAr: formData.nameAr,
                nameFr: formData.nameFr,
                quantity: Number(formData.quantity),
                maxQuantity: Number(formData.maxQuantity),
                unit: formData.unit,
                price: Number(formData.unitPrice),
                minLevel: 10,
                lastUpdated: new Date().toISOString().split('T')[0]
            };
            if (editItem) {
                setProducts(products.map(p => p.id === editItem.id ? { ...p, ...newItemData } : p));
            } else {
                const newProduct: Product = {
                    id: Math.random().toString(36).substr(2, 9),
                    ...newItemData
                };
                setProducts([...products, newProduct]);
            }
        }
        onRestockMaterial(); 
        setIsModalOpen(false);
        showNotification(t('success'), 'success');
    } catch (e) {
        showNotification(t('error'), 'error');
    }
  };

  const handleDelete = (id: string) => {
      if(confirm(lang === Language.AR ? 'هل أنت متأكد؟' : 'Êtes-vous sûr ?')){
          try {
            if(activeTab === 'raw') setMaterials(materials.filter(m => m.id !== id));
            else setProducts(products.filter(p => p.id !== id));
            onRestockMaterial();
            showNotification(t('success'), 'success');
          } catch(e) {
             showNotification(t('error'), 'error'); 
          }
      }
  }

  const getStatus = (current: number, max: number) => {
      if(!max || max === 0) return { color: 'bg-gray-100 text-gray-800', label: t('unknown'), level: 'unknown' };
      const pct = (current / max) * 100;
      if(pct >= 85) return { color: 'bg-green-100 text-green-800', label: t('available'), level: 'high' };
      if(pct >= 55) return { color: 'bg-blue-100 text-blue-800', label: t('good'), level: 'med' };
      if(pct >= 25) return { color: 'bg-orange-100 text-orange-800', label: t('low'), level: 'low' };
      return { color: 'bg-red-100 text-red-800', label: t('critical'), level: 'critical' };
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className={`text-2xl font-bold text-slate-800 ${isRTL ? 'font-cairo' : 'font-sans'}`}>{t('inventory')}</h2>
        <button onClick={() => handleOpenModal()} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors text-sm font-medium shadow-sm">
          <Plus size={18} /><span>{t('add')}</span>
        </button>
      </div>

      <div className="flex border-b border-slate-200">
        <button onClick={() => setActiveTab('raw')} className={`px-6 py-3 text-sm font-medium transition-colors relative ${activeTab === 'raw' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>
          {t('rawMaterials')}{activeTab === 'raw' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-600"></div>}
        </button>
        <button onClick={() => setActiveTab('finished')} className={`px-6 py-3 text-sm font-medium transition-colors relative ${activeTab === 'finished' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>
          {t('finishedGoods')}{activeTab === 'finished' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-600"></div>}
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className={`px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider ${isRTL ? 'text-right' : 'text-left'}`}>{t('name')}</th>
                <th className={`px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider ${isRTL ? 'text-right' : 'text-left'}`}>{t('quantity')}</th>
                <th className={`px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider ${isRTL ? 'text-right' : 'text-left'}`}>{t('status')}</th>
                <th className={`px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider ${isRTL ? 'text-right' : 'text-left'}`}>{t('actions')}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {(activeTab === 'raw' ? materials : products).map((item: any) => {
                const status = getStatus(item.quantity, item.maxQuantity);
                return (
                  <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${status.level === 'critical' ? 'bg-red-50' : ''}`}>
                    <td className={`px-6 py-4 text-sm font-medium text-slate-900 ${isRTL ? 'text-right' : 'text-left'}`}>
                        {lang === Language.AR ? item.nameAr : item.nameFr}
                        {status.level === 'critical' && <div className="text-[10px] text-red-600 font-bold flex items-center gap-1 mt-1"><AlertCircle size={10}/> {t('critical')}</div>}
                    </td>
                    <td className={`px-6 py-4 text-sm text-slate-600 ${isRTL ? 'text-right' : 'text-left'}`}>{item.quantity} <span className="text-xs opacity-60">{item.unit}</span></td>
                    <td className={`px-6 py-4 ${isRTL ? 'text-right' : 'text-left'}`}>
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${status.color}`}>{status.label}</span>
                    </td>
                    <td className={`px-6 py-4 text-sm flex items-center gap-2 ${isRTL ? 'justify-start' : 'justify-start'}`}>
                       {activeTab === 'raw' && (
                           <button onClick={() => handleOpenRestock(item)} className="flex items-center gap-1 bg-green-50 text-green-700 border border-green-200 px-2 py-1.5 rounded-md hover:bg-green-100 transition-colors" title={t('purchaseMaterial')}>
                               <ShoppingCart size={14} /><span className="text-xs font-bold">{lang === Language.AR ? 'شراء' : 'Acheter'}</span>
                           </button>
                       )}
                       <button onClick={() => handleOpenModal(item)} className="text-blue-600 hover:text-blue-800 p-1.5"><Edit2 size={16} /></button>
                       <button onClick={() => handleDelete(item.id)} className="text-red-400 hover:text-red-600 p-1.5"><Trash2 size={16} /></button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* نافذة التجديد (شراء مواد خام) */}
      <Modal isOpen={isRestockModalOpen} onClose={() => setIsRestockModalOpen(false)} title={t('purchaseMaterial')} isRTL={isRTL}>
          <div className="space-y-4">
              <div className="bg-blue-50 p-3 rounded-md text-blue-800 text-sm">
                  <p className="font-bold">{lang === Language.AR ? `تجديد: ${restockItem?.nameAr}` : `Restock: ${restockItem?.nameFr}`}</p>
                  <p className="opacity-80 text-xs">{lang === Language.AR ? 'سيتم إضافة الكمية للمخزون وتسجيل التكلفة في المصروفات.' : 'La quantité sera ajoutée et le coût sera enregistré.'}</p>
              </div>
              <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">{t('addedQuantity')} ({restockItem?.unit})</label>
                  <input type="number" className="w-full border border-slate-300 rounded-md p-2" value={restockData.quantity} onChange={(e) => handleRestockQtyChange(Number(e.target.value))} />
              </div>
              <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">{t('totalCost')} (SAR)</label>
                  <input type="number" className="w-full border border-slate-300 rounded-md p-2" value={restockData.totalCost} onChange={(e) => setRestockData({...restockData, totalCost: Number(e.target.value)})} />
                  <p className="text-[10px] text-slate-500 mt-1">{lang === Language.AR ? '* محسوب بناءً على سعر الوحدة المسجل' : '* Calculé sur le prix unitaire enregistré'}</p>
              </div>
              <div className="pt-4 flex justify-end gap-2">
                  <button onClick={() => setIsRestockModalOpen(false)} className="px-4 py-2 text-sm text-slate-600">{t('cancel')}</button>
                  <button onClick={handleRestockSubmit} className="px-4 py-2 text-sm bg-green-600 text-white rounded-md hover:bg-green-700 font-bold shadow-lg">{t('save')}</button>
              </div>
          </div>
      </Modal>

      {/* نافذة الإضافة/التعديل العامة */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editItem ? t('edit') : t('add')} isRTL={isRTL}>
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Name (Arabic)</label>
            <input type="text" className="w-full border border-slate-300 rounded-md p-2" value={formData.nameAr} onChange={(e) => setFormData({...formData, nameAr: e.target.value})} />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Name (French)</label>
            <input type="text" className="w-full border border-slate-300 rounded-md p-2" value={formData.nameFr} onChange={(e) => setFormData({...formData, nameFr: e.target.value})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">{t('quantity')}</label>
              <input type="number" className="w-full border border-slate-300 rounded-md p-2" value={formData.quantity} onChange={(e) => setFormData({...formData, quantity: Number(e.target.value)})} />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">{t('maxQuantity')}</label>
              <input type="number" className="w-full border border-slate-300 rounded-md p-2" value={formData.maxQuantity} onChange={(e) => setFormData({...formData, maxQuantity: Number(e.target.value)})} />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">{t('unit')}</label>
                <select className="w-full border border-slate-300 rounded-md p-2 bg-white" value={formData.unit} onChange={(e) => setFormData({...formData, unit: e.target.value as any})}>
                    <option value="kg">KG</option><option value="l">Liters</option><option value="pcs">Pieces</option><option value="roll">Rolls</option><option value="plate">Plate</option><option value="carton">Carton</option>
                </select>
              </div>
            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">{lang === Language.AR ? 'سعر الوحدة' : 'Prix Unitaire'}</label>
                <input type="number" step="0.01" className="w-full border border-slate-300 rounded-md p-2" value={formData.unitPrice} onChange={(e) => setFormData({...formData, unitPrice: Number(e.target.value)})} />
            </div>
          </div>
          <div className="pt-4 flex justify-end gap-2">
            <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-sm text-slate-600">{t('cancel')}</button>
            <button onClick={handleSave} className="px-4 py-2 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 shadow-md">{t('save')}</button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default Inventory;

import React, { useState } from 'react';
import { Plus, Printer, Trash2, ChevronDown, MoreHorizontal, X } from 'lucide-react';
import { Language, Order, OrderStatus, Customer, Product, Expense } from '../types';
import { TRANSLATIONS } from '../constants';
import Modal from './Modal';

interface OrdersProps {
  lang: Language;
  customers: Customer[];
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  showNotification: (msg: string, type: 'success'|'error') => void;
}

const Orders: React.FC<OrdersProps> = ({ lang, customers, orders, setOrders, products, setProducts, setExpenses, showNotification }) => {
  const t = (key: string) => TRANSLATIONS[key][lang];
  const isRTL = lang === Language.AR;

  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showInvoice, setShowInvoice] = useState<Order | null>(null);

  const [formData, setFormData] = useState({ 
    customerId: '', 
    productId: '',
    quantity: 0,
    status: OrderStatus.PENDING 
  });

  // دالة تسجيل الدخل - فحص محلي
  const recordIncome = (order: Order) => {
      const orderId = order.id;
      const amount = order.totalAmount;
      const description = `OrderIncome_Ref_${orderId}`; 
      const displayDesc = lang === Language.AR ? `دخل فاتورة مبيعات رقم #${orderId}` : `Revenu commande #${orderId}`;

      const exists = expenses.some(e => e.description === description);
      if (exists) return;

      const newExpense: Expense = {
          id: Math.random().toString(36).substr(2, 9),
          type: 'income',
          category: 'Sales',
          description: description, // Tag for finding later
          amount: amount,
          date: order.date
      };

      // We modify description for display after the check
      const displayExpense = { ...newExpense, description: displayDesc };

      // Store the tag actually, or handle finding it differently. 
      // For simplicity in mock mode, we'll store the tag but maybe display it nicer if needed?
      // Let's store the tag as description to make removeIncome work easily.
      setExpenses(prev => [newExpense, ...prev]);
  };

  const removeIncome = (orderId: string) => {
      const searchTag = `OrderIncome_Ref_${orderId}`;
      setExpenses(prev => prev.filter(e => e.description !== searchTag));
  };

  const handleSaveOrder = () => {
    const customer = customers.find(c => c.id === formData.customerId);
    const product = products.find(p => p.id === formData.productId);

    if (!customer || !product || formData.quantity <= 0) return;

    if (formData.status === OrderStatus.COMPLETED && product.quantity < formData.quantity) {
        showNotification(t('insufficientStock'), 'error');
        return;
    }

    const total = product.price * formData.quantity;

    const newOrder: Order = {
        id: Math.random().toString(36).substr(2, 6).toUpperCase(),
        customerId: customer.id,
        customerName: customer.name,
        totalAmount: total,
        date: new Date().toISOString().split('T')[0],
        status: formData.status,
        items: [{
            productId: product.id,
            productName: lang === Language.AR ? product.nameAr : product.nameFr,
            quantity: formData.quantity,
            unitPrice: product.price,
            total: total
        }]
    };

    setOrders(prev => [newOrder, ...prev]);

    if (formData.status === OrderStatus.COMPLETED) {
        const newStock = product.quantity - formData.quantity;
        setProducts(prev => prev.map(p => p.id === product.id ? { ...p, quantity: newStock } : p));
        recordIncome(newOrder);
    }

    setIsModalOpen(false);
    showNotification(t('success'), 'success');
    setFormData({ customerId: '', productId: '', quantity: 0, status: OrderStatus.PENDING });
  };

  const handleStatusChange = (id: string, newStatus: OrderStatus) => {
    const order = orders.find(o => o.id === id);
    if (!order || order.status === newStatus) return;

    const oldStatus = order.status;

    // الحالة أ: الانتقال إلى "مكتمل" (خصم مخزون + إضافة دخل)
    if (newStatus === OrderStatus.COMPLETED) {
        for (const item of order.items) {
            const prod = products.find(p => p.id === item.productId);
            if (prod) {
                if (prod.quantity < item.quantity) {
                    showNotification(t('insufficientStock'), 'error');
                    return; // Stop if stock low
                }
                const updatedQty = prod.quantity - item.quantity;
                setProducts(prev => prev.map(p => p.id === prod.id ? { ...p, quantity: updatedQty } : p));
            }
        }
        recordIncome(order);
    }

    // الحالة ب: التراجع من "مكتمل" إلى حالة أخرى (إرجاع مخزون + حذف دخل)
    else if (oldStatus === OrderStatus.COMPLETED) {
        for (const item of order.items) {
            const prod = products.find(p => p.id === item.productId);
            if (prod) {
                const restoredQty = prod.quantity + item.quantity;
                setProducts(prev => prev.map(p => p.id === prod.id ? { ...p, quantity: restoredQty } : p));
            }
        }
        removeIncome(id);
    }

    setOrders(prev => prev.map(o => o.id === id ? { ...o, status: newStatus } : o));
    showNotification(t('success'), 'success');
  };

  const handleDelete = (id: string) => {
    if(confirm(lang === Language.AR ? 'هل أنت متأكد؟ سيتم حذف السجل المالي وإرجاع المخزون إذا كان الطلب مكتملاً.' : 'Confirmer ? Le stock sera restauré et le revenu supprimé.')) {
        const order = orders.find(o => o.id === id);
        if (order && order.status === OrderStatus.COMPLETED) {
            for (const item of order.items) {
                const prod = products.find(p => p.id === item.productId);
                if (prod) {
                    const restoredQty = prod.quantity + item.quantity;
                    setProducts(prev => prev.map(p => p.id === prod.id ? { ...p, quantity: restoredQty } : p));
                }
            }
            removeIncome(id);
        }
        setOrders(prev => prev.filter(o => o.id !== id));
        showNotification(t('success'), 'success');
    }
  };

  const handlePrint = () => window.print();

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.COMPLETED: return 'bg-green-100 text-green-700';
      case OrderStatus.PROCESSING: return 'bg-blue-100 text-blue-700';
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-700';
      case OrderStatus.CANCELLED: return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-6" onClick={() => setActiveMenuId(null)}>
       {showInvoice && (
           <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 print:bg-white print:fixed print:inset-0">
               <div className="absolute top-4 right-4 flex gap-2 print:hidden">
                    <button onClick={handlePrint} className="bg-green-600 text-white rounded-full p-3 shadow-lg hover:bg-green-700 flex items-center gap-2 font-bold">
                        <Printer size={20} /> {t('printInvoice')}
                    </button>
                    <button onClick={() => setShowInvoice(null)} className="bg-white text-slate-900 rounded-full p-3 shadow-lg hover:bg-slate-200">
                        <X size={20} />
                    </button>
               </div>
               <div className="bg-white w-[350px] md:w-[500px] p-10 shadow-2xl rounded-sm text-slate-900 print:shadow-none print:w-full">
                   <div className="text-center border-b-2 border-slate-900 pb-4 mb-6">
                       <h2 className="text-2xl font-bold uppercase tracking-widest">{lang === Language.AR ? 'مصنع كرتون اطباق البيض' : 'USINE DE CARTON D\'OEUFS'}</h2>
                       <p className="text-xs text-slate-500 mt-1">Industrial City, Saudi Arabia</p>
                   </div>
                   <div className="flex justify-between text-sm mb-8">
                       <div><p className="text-slate-500 text-[10px] uppercase font-bold">{t('invoice')} #</p><p className="font-mono font-bold text-lg">{showInvoice.id.slice(0, 8).toUpperCase()}</p></div>
